export const SEVEN_DAYS_IN_MS = 7 * 24 * 60 * 60 * 1000;
// Also defined in constants.ts, but good to have here for utility independence
export const BETTING_CUTOFF_MS = 120000; // 2 Minutes Hard Stop

export const getEffectiveTicketStatus = (ticket: Ticket, now: Date): Ticket['status'] | 'Expired' => {
  const ticketAge = now.getTime() - ticket.timestamp.getTime();
  if (['Winning', 'Active'].includes(ticket.status) && ticketAge > SEVEN_DAYS_IN_MS) {
    return 'Expired';
  }
  return ticket.status;
};

/**
 * STEP 1: Generate the Ticket Image (Base64)
 * ANTI-FREEZE UPDATE: Low Resolution Mode
 */
export const generateTicketImage = async (elementId: string): Promise<string> => {
    const element = document.getElementById(elementId);
    if (!element) {
      throw new Error("Element not found");
    }

    if (typeof html2canvas === 'undefined') {
      throw new Error("Library missing");
    }

    // CRITICAL ANTI-FREEZE: Yield to the main thread before heavy processing.
    // This allows the UI (button spinners, etc.) to update before the freeze starts.
    await new Promise(resolve => setTimeout(resolve, 100));

    try {
        // SCALE 1.0: Native resolution. 
        // Scale 2.0/3.0 uses exponential memory (4x/9x) causing Android freeze.
        // 1.0 is sufficient for thermal printers (which are usually 203dpi).
        const canvas = await html2canvas(element, {
            scale: 1.0, 
            useCORS: true,
            logging: false, 
            backgroundColor: '#ffffff',
            allowTaint: true,
            // Remove heavy elements
            ignoreElements: (node: Element) => node.classList?.contains('no-print')
        });

        return canvas.toDataURL('image/png');
    } catch (err: any) {
        console.error("Generation failed:", err);
        throw err;
    }
};

/**
 * ==================================================================================
 * CORE PRINTING FUNCTION - DO NOT MODIFY WITHOUT AUTHORIZATION
 * ==================================================================================
 * STEP 2: Print the Generated Image (HTML Method)
 * This method avoids generating a heavy image and just prints the DOM content directly.
 * It is much faster and prevents freezing on low-end devices.
 * ==================================================================================
 */
export const triggerPrint = (elementId: string): void => {
    const element = document.getElementById(elementId);
    if (!element) {
        alert("Error: Ticket content not found.");
        return;
    }

    const printWindow = window.open('', '_blank', 'width=350,height=600');
    if (!printWindow) {
        alert("Popup blocked! Please allow popups to print.");
        return;
    }

    const htmlContent = `
        <!DOCTYPE html>
        <html>
        <head>
            <title>Print Ticket</title>
            <script src="https://cdn.tailwindcss.com"></script>
            <style>
                @page { margin: 0; size: auto; }
                body { margin: 0; padding: 5px; background-color: white; }
                .printable-content { width: 100%; max-width: 300px; margin: 0 auto; }
                /* Ensure styles match the app */
                .text-betese-dark { color: #008000; }
                .text-betese-green { color: #008000; }
                .bg-betese-green { background-color: #008000; }

                /* Force black text for thermal printers */
                @media print {
                    body * { color: #000 !important; }
                    .no-print { display: none !important; }
                }
            </style>
        </head>
        <body>
            <div class="printable-content">
                ${element.innerHTML}
            </div>
            <script>
                // Wait for styles to apply then print
                setTimeout(() => {
                    window.print();
                    // Optional: window.close() after print if desired, but keeping open allows reprint
                }, 1000);
            </script>
        </body>
        </html>
    `;

    printWindow.document.open();
    printWindow.document.write(htmlContent);
    printWindow.document.close();
};

export function calculateTicketWinnings(ticket: Ticket, allRaces: Race[]): { totalWinnings: number; breakdown: WinningsBreakdown[] } {
    let grandTotalWinnings = 0;
    const finalBreakdown: WinningsBreakdown[] = [];

    ticket.selections.forEach((selection, selectionIndex) => {
        const race = allRaces.find(r => r.id === selection.raceId);
        if (!race?.result?.winningNumbers || !race.result.payouts) {
            return;
        }

        const checkResult = (winningNumbers: number[], payouts: Payouts, source: 'Primary' | 'Bracket') => {
            const { betType, numbers: baseSelectionNumbers, xCount, pattern } = selection;
            const pricing = BET_PRICING[betType];
            if (!pricing) return;

            const winsForThisSelection = new Map<string, { combinations: number[][]; payout: number }>();

            const updateWinsMap = (winType: string, payout: number | undefined, winningCombo: number[]) => {
                if (typeof payout !== 'number' || payout <= 0) return;
                const entry = winsForThisSelection.get(winType) || { combinations: [], payout: payout };
                const exists = entry.combinations.some(c => JSON.stringify(c) === JSON.stringify(winningCombo));
                if (!exists) {
                    entry.combinations.push(winningCombo);
                }
                winsForThisSelection.set(winType, entry);
            };

            if (betType.startsWith('Multi')) {
                const numToMatch = 4; 
                let payoutKey: keyof Payouts | null = null;

                if (betType === BetTypeOption.Multi4) payoutKey = 'multi4';
                else if (betType === BetTypeOption.Multi5) payoutKey = 'multi5';
                else if (betType === BetTypeOption.Multi6) payoutKey = 'multi6';
                else if (betType === BetTypeOption.Multi7) payoutKey = 'multi7';

                if (payoutKey && payouts[payoutKey]) {
                    const topWinners = winningNumbers.slice(0, numToMatch);
                    const allRunners = Array.from({ length: race.horseCount }, (_, i) => i + 1);
                    const validRunners = allRunners.filter(h => !race.nonRunners.includes(h));
                    const fieldHorses = validRunners.filter(h => !baseSelectionNumbers.includes(h));

                    const neededFromField = topWinners.filter(w => !baseSelectionNumbers.includes(w));

                    if (neededFromField.length <= xCount && neededFromField.every(n => fieldHorses.includes(n))) {
                         updateWinsMap(betType, payouts[payoutKey], topWinners);
                    } else if (xCount === 0 && topWinners.every(n => baseSelectionNumbers.includes(n))) {
                         updateWinsMap(betType, payouts[payoutKey], topWinners);
                    }
                }
            }
            else {
                const minHorsesForBet = pricing.minHorses;
                let effectiveCombinations: number[][];

                if (xCount > 0) {
                    const allRunners = Array.from({ length: race.horseCount }, (_, i) => i + 1);
                    const validRunners = allRunners.filter(h => !race.nonRunners.includes(h));
                    const poolForX = validRunners.filter(h => !baseSelectionNumbers.includes(h));

                    if (pattern && pattern.length > 0) {
                        effectiveCombinations = generateCombinationsFromPattern(pattern, poolForX, xCount);
                    } else {
                        const xCombinations = getCombinations(poolForX, xCount);
                        effectiveCombinations = xCombinations.map(combo => [...baseSelectionNumbers, ...combo]);
                    }
                } else if ([BetTypeOption.SimpleGagnant, BetTypeOption.SimplePlace].includes(betType)){
                    effectiveCombinations = baseSelectionNumbers.map(n => [n]);
                } else {
                    effectiveCombinations = getCombinations(baseSelectionNumbers, minHorsesForBet);
                }

                for (const combo of effectiveCombinations) {
                    const comboSet = new Set(combo);

                    if (betType === BetTypeOption.SimpleGagnant) {
                        if (combo.length === 1 && winningNumbers[0] === combo[0]) {
                            updateWinsMap('Simple Gagnant', payouts.simpleGagnant, combo);
                        }
                    }
                    else if (betType === BetTypeOption.SimplePlace) {
                         if (combo.length === 1) {
                            const top3Pos = winningNumbers.slice(0, 3);
                            const index = top3Pos.indexOf(combo[0]);
                            if (index >= 0) {
                                let payoutKey: keyof Payouts = 'simplePlaceA';
                                if (index === 1) payoutKey = 'simplePlaceB';
                                if (index === 2) payoutKey = 'simplePlaceC';
                                updateWinsMap(`Simple Placé (${index+1}st)`, payouts[payoutKey] || payouts.simplePlaceA, combo);
                            }
                        }
                    }
                    else if (betType === BetTypeOption.Quinte) {
                        const top5 = winningNumbers.slice(0, 5);
                        const top4 = winningNumbers.slice(0, 4);
                        const top3 = winningNumbers.slice(0, 3);

                        // Strict check for Order: Exact match of first 5
                        const isOrder = combo.length >= 5 && combo.slice(0, 5).every((num, i) => num === top5[i]);
                        // Strict check for Disorder: Set match of first 5
                        const isDisorder = top5.length === 5 && top5.every(n => comboSet.has(n));

                        const hasBonus4 = top4.length === 4 && top4.every(n => comboSet.has(n));
                        const hasBonus3 = top3.length === 3 && top3.every(n => comboSet.has(n));

                        // FIX: ELSE IF HIERARCHY for individual combinations
                        // However, for Field bets, different combinations yield different results.
                        // So we record them all here, and filter at the END of the selection processing.
                        if (isOrder) {
                            updateWinsMap('Quinté+ Ordre', payouts.quinteOrdre, combo);
                        } else if (isDisorder) {
                            updateWinsMap('Quinté+ Désordre', payouts.quinteDesordre, combo);
                        } else if (hasBonus4) {
                            updateWinsMap('Quinté+ Bonus 4', payouts.quinteBonus4, combo);
                        } else if (hasBonus3) {
                             updateWinsMap('Quinté+ Bonus 3', payouts.quinteBonus3, combo);
                        }
                    }
                    else if (betType === BetTypeOption.Quarte) {
                        const top4 = winningNumbers.slice(0, 4);
                        const top3 = winningNumbers.slice(0, 3);

                        const isOrder = combo.length >= 4 && combo.slice(0, 4).every((num, i) => num === top4[i]);
                        const isDisorder = top4.length === 4 && top4.every(n => comboSet.has(n));
                        const hasBonus3 = top3.length === 3 && top3.every(n => comboSet.has(n));

                        if (isOrder) {
                            updateWinsMap('Quarté+ Ordre', payouts.quarteOrdre, combo);
                        } else if (isDisorder) {
                            updateWinsMap('Quarté+ Désordre', payouts.quarteDesordre, combo);
                        } else if (hasBonus3) {
                            updateWinsMap('Quarté+ Bonus 3', payouts.quarteBonus3, combo);
                        }
                    }
                    else if (betType === BetTypeOption.Tierce) {
                        const top3 = winningNumbers.slice(0, 3);
                        const isSetMatch = combo.length === 3 && top3.every(n => comboSet.has(n));

                        if (isSetMatch) {
                            const isOrder = combo.every((num, i) => num === top3[i]);
                            if (isOrder) {
                                updateWinsMap('Tiercé Ordre', payouts.tierceOrdre, combo);
                            } else {
                                updateWinsMap('Tiercé Désordre', payouts.tierceDesordre, combo);
                            }
                        }
                    }
                    else if (betType === BetTypeOption.CoupleGagnant) {
                        const top2 = winningNumbers.slice(0, 2);
                        if (combo.length === 2 && top2.every(n => comboSet.has(n))) {
                            const isOrder = combo[0] === top2[0] && combo[1] === top2[1];
                            if (isOrder && payouts.ordreGagnant) {
                                 updateWinsMap('Couplé Ordre', payouts.ordreGagnant, combo);
                            } else {
                                 updateWinsMap('Couplé Gagnant', payouts.desordreGagnant, combo);
                            }
                        }
                    }
                    else if (betType === BetTypeOption.CouplePlace) {
                         if (combo.length === 2) {
                            const top3 = winningNumbers.slice(0, 3);
                            if (comboSet.has(top3[0]) && comboSet.has(top3[1])) updateWinsMap('Couplé Placé (1-2)', payouts.coupleA, combo);
                            else if (comboSet.has(top3[0]) && comboSet.has(top3[2])) updateWinsMap('Couplé Placé (1-3)', payouts.coupleB, combo);
                            else if (comboSet.has(top3[1]) && comboSet.has(top3[2])) updateWinsMap('Couplé Placé (2-3)', payouts.coupleC, combo);
                        }
                    }
                }
            }

            // --- PRIZE HIERARCHY FILTERING (The Fix for Field Bets) ---
            // For complex bets involving 'X', multiple combinations can trigger multiple prize tiers.
            // We must ensure only the HIGHEST PRIZE is awarded per selection to prevent overpayment.
            const wonTypes = Array.from(winsForThisSelection.keys());

            if (betType === BetTypeOption.Quinte) {
                const hasMainWin = wonTypes.some(t => t.includes('Ordre') || t.includes('Désordre'));
                const hasBonus4 = wonTypes.some(t => t.includes('Bonus 4'));

                if (hasMainWin) {
                    // If you have Order or Disorder, remove ALL Bonus prizes for this selection
                    for (const type of wonTypes) {
                        if (type.includes('Bonus')) winsForThisSelection.delete(type);
                    }
                } else if (hasBonus4) {
                    // If you have Bonus 4, remove Bonus 3
                    for (const type of wonTypes) {
                        if (type.includes('Bonus 3')) winsForThisSelection.delete(type);
                    }
                }
            } else if (betType === BetTypeOption.Quarte) {
                const hasMainWin = wonTypes.some(t => t.includes('Ordre') || t.includes('Désordre'));
                if (hasMainWin) {
                    // If you have Order or Disorder, remove Bonus 3
                    for (const type of wonTypes) {
                        if (type.includes('Bonus')) winsForThisSelection.delete(type);
                    }
                }
            }
            // --------------------------------

            if (winsForThisSelection.size > 0) {
                winsForThisSelection.forEach((value, winType) => {
                    const totalForType = value.combinations.length * value.payout * selection.multiplier;
                    grandTotalWinnings += totalForType;
                    finalBreakdown.push({
                        selectionIndex: selectionIndex,
                        status: 'Win',
                        winType: `${winType} ${source === 'Bracket' ? '(Bracket)' : ''}`,
                        winningCombinations: value.combinations.length,
                        winningCombinationList: value.combinations,
                        payoutPerCombination: value.payout,
                        totalPayout: totalForType,
                        source: source
                    });
                });
            }
        };

        checkResult(race.result.winningNumbers, race.result.payouts, 'Primary');

        if (race.result.bracketWinningNumbers && race.result.bracketPayouts && race.result.bracketWinningNumbers.length > 0) {
            checkResult(race.result.bracketWinningNumbers, race.result.bracketPayouts, 'Bracket');
        }

        if (!finalBreakdown.some(b => b.selectionIndex === selectionIndex)) {
             finalBreakdown.push({
                selectionIndex: selectionIndex,
                status: 'Loss',
            });
        }
    });

    return { totalWinnings: grandTotalWinnings, breakdown: finalBreakdown };
}

export function calculateWinSummary(race: Race, winningNumbers: number[], allTickets: Ticket[]): WinSummary {
  const summary: WinSummary = {};
  if (winningNumbers.length < 1) return {};
  const activeTickets = allTickets.filter(t => t.status === 'Active');

  for (const ticket of activeTickets) {
      const { breakdown } = calculateTicketWinnings(ticket, [race]);
      breakdown.filter(b => b.status === 'Win').forEach(win => {
          if(win.winType && win.totalPayout) {
              const type = win.winType.replace(' (Bracket)', '').replace(' (Primary)', '');
              if (!summary[type]) {
                  summary[type] = { count: 0, stake: 0 };
              }
              summary[type].count += win.winningCombinations || 1;
          }
      });
  }
  return summary;
}

