interface TicketModalProps {
  ticket: Ticket;
  onClose: () => void;
  showPrintButton: boolean;
  races?: Race[];
}

export const TicketModal: React.FC<TicketModalProps> = ({ ticket, onClose, showPrintButton, races }) => {

  const handlePrint = () => {
    // Directly trigger print on the content div ID. No async/await needed as it is instant HTML copy.
    triggerPrint(`ticket-content-${ticket.id}`);
  };

  const isPaidReceipt = ticket.status === 'Paid';
  const qrCodeUrl = `https://api.qrserver.com/v1/create-qr-code/?size=100x100&data=${ticket.id}`;

  // ULTRA-COMPACT PAID RECEIPT LAYOUT
  const renderPaidReceipt = () => (
    <>
      {/* Header: "PAID" + Top ID */}
      <div className="text-center border-b-2 border-black pb-1 mb-1">
        <p className="text-3xl font-black uppercase leading-none tracking-tighter">PAID</p>
        <p className="text-xs font-mono font-black mt-0.5">{ticket.id}</p>
      </div>

      {/* Meta Data: Grid Layout to save vertical space */}
      <div className="grid grid-cols-2 text-[10px] font-black leading-tight mb-1 gap-x-1">
        <div>{ticket.timestamp.toLocaleDateString()}</div>
        <div className="text-right">{ticket.paidAt ? ticket.paidAt.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : ''}</div>
        <div className="col-span-2 border-t border-black mt-0.5 pt-0.5 truncate">
            By: {ticket.paidByName}
        </div>
      </div>

      {/* Amount: Minimal vertical padding, large text */}
      {ticket.winnings !== undefined && ticket.winnings > 0 && (
        <div className="text-center border-y-4 border-black my-1 py-0.5">
          <p className="text-[10px] font-black uppercase leading-none">AMOUNT PAID</p>
          <p className="text-4xl font-black leading-none">{ticket.winnings.toFixed(2)}</p>
        </div>
      )}

      {/* Footer: QR Code LEFT, Ref ID RIGHT (Side-by-Side) */}
      <div className="flex justify-between items-end mt-1">
        {/* QR Code */}
        <img src={qrCodeUrl} alt="QR" className="w-[50px] h-[50px] block" />

        {/* Safety ID & Timestamp */}
        <div className="text-right flex-1 ml-2">
             <div className="border-b border-black mb-0.5">
                <span className="block text-[8px] font-black leading-none">REF ID</span>
                <span className="block text-sm font-mono font-black leading-none">{ticket.id}</span>
             </div>
             <p className="text-[7px] leading-none">Printed At: {new Date().toLocaleString([], { dateStyle: 'short', timeStyle: 'short' })}</p>
        </div>
      </div>
    </>
  );

  const renderStandardTicket = () => (
    <>
      <div className="text-center mb-1 border-b-2 border-black pb-1">
        <Logo className="text-xl" />
        <p className="text-lg font-black uppercase leading-none">{ticket.status === 'Winning' ? 'WINNING TICKET' : 'OFFICIAL TICKET'}</p>
      </div>

      <div className="text-xs mb-1 font-black text-black leading-tight">
        <div className="flex justify-between"><span>ID:</span> <span className="font-mono">{ticket.id}</span></div>
        <div className="flex justify-between"><span>Date:</span> <span>{ticket.timestamp.toLocaleDateString()}</span></div>
        <div className="flex justify-between"><span>Time Played:</span> <span>{ticket.timestamp.toLocaleTimeString()}</span></div>
      </div>

      <div className="border-t-2 border-b-2 border-black py-1 space-y-1">
        {ticket.selections.map((sel, index) => {
            const selectionResults = ticket.winningsBreakdown?.filter(b => b.selectionIndex === index);
            const winningItems = selectionResults?.filter(r => r.status === 'Win') || [];
            const isWin = winningItems.length > 0;

            const race = races?.find(r => r.id === sel.raceId);
            const officialWinningNumbers = race?.result?.winningNumbers;
            const bracketWinningNumbers = race?.result?.bracketWinningNumbers;
            const hasResult = !!officialWinningNumbers;

            return (
              <div key={index} className="p-0">
                <div className="flex flex-col mb-0.5 border-b border-black pb-0.5">
                    {/* JACKPOT DISPLAY - UPDATED TO WHITE BG WITH BORDER */}
                    {race?.jackpot && race.jackpot > 0 && (
                       <div className="text-center bg-white text-black font-black text-xs py-1 mb-1 border-y-2 border-black border-dashed uppercase tracking-widest">
                          *** JACKPOT: {race.jackpot.toLocaleString()} GMD ***
                       </div>
                    )}
                    <div className="flex justify-between items-baseline">
                        <span className="font-black text-sm uppercase leading-none">{sel.raceName}</span>
                        <span className="font-black text-sm uppercase leading-none">{sel.betType}</span>
                    </div>
                </div>

                <div className="flex justify-between items-end mt-0.5">
                    <div className="w-3/4">
                        <span className="font-mono font-black text-lg leading-none text-black block break-all">
                        {sel.pattern ? (
                            sel.pattern.join('-')
                        ) : (
                            <>
                                {sel.xCount > 0 && `${'X '.repeat(sel.xCount)}`}
                                {sel.numbers.join(', ')}
                            </>
                        )}
                        </span>
                    </div>
                    <div className="text-right w-1/4">
                        <p className="font-black text-lg leading-none">
                            {(sel.cost * sel.multiplier).toFixed(2)}
                        </p>
                    </div>
                </div>

                {officialWinningNumbers && (
                    <div className="mt-1 border-t border-dotted border-black pt-0.5 text-[10px]">
                        <div className="flex justify-between items-center">
                            <span className="font-black uppercase">Res:</span>
                            <span className="font-mono font-black text-sm tracking-widest text-black">
                                {formatWinningNumbersForDisplay(officialWinningNumbers)}
                            </span>
                        </div>
                        {/* BRACKET RESULT DISPLAY ADDED HERE */}
                        {bracketWinningNumbers && bracketWinningNumbers.length > 0 && (
                             <div className="flex justify-between items-center mt-0.5">
                                <span className="font-black uppercase text-[9px]">Bracket:</span>
                                <span className="font-mono font-black text-xs tracking-widest text-black">
                                    {formatWinningNumbersForDisplay(bracketWinningNumbers)}
                                </span>
                            </div>
                        )}
                    </div>
                )}

                {isWin ? (
                  <div className="mt-0.5 bg-gray-200 px-1 border border-black">
                    {winningItems.map((result, rIdx) => (
                        <div key={rIdx} className="flex justify-between text-xs font-black">
                            <span>{result.winType}</span>
                            <span>{result.totalPayout?.toFixed(2)}</span>
                        </div>
                    ))}
                  </div>
                ) : (
                    /* EXPLICIT LOSS INDICATOR FOR COMBINATION TICKETS */
                    hasResult && (
                        <div className="mt-0.5 text-right">
                            <span className="text-[10px] font-black border border-black px-1">LOST</span>
                        </div>
                    )
                )}
              </div>
            );
        })}
      </div>

      <div className="mt-1 text-right border-b-2 border-black pb-1">
        <p className="text-sm font-black">TOTAL: <span className="text-xl">{ticket.totalCost.toFixed(2)}</span></p>
      </div>

      {ticket.winnings !== undefined && ticket.winnings > 0 && (
        <div className="mt-1 text-center border-y-2 border-black py-0.5">
          <p className="text-xs font-black uppercase leading-none">WINNINGS</p>
          <p className="text-3xl font-black leading-none">{ticket.winnings.toFixed(2)}</p>
        </div>
      )}

      <div className="mt-1 pt-1 text-center text-[10px] font-black uppercase leading-tight">
        <div className="flex justify-between items-end">
            <img src={qrCodeUrl} alt="QR" className="w-[50px] h-[50px] block" />
            <div className="text-right flex-1 ml-2">
                <div className="border-b border-black mb-0.5">
                    <span className="block text-[8px] font-black leading-none">REF ID</span>
                    <span className="block text-sm font-mono font-black leading-none">{ticket.id}</span>
                </div>
                <p className="text-[7px] leading-none">Printed At: {new Date().toLocaleString()}</p>
            </div>
        </div>
      </div>
    </>
  );

  return (
    <>
      <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
        <div className="bg-white rounded-lg shadow-2xl w-[320px] flex flex-col max-h-[90vh]">

          {/* Header */}
          <div className="p-2 border-b flex justify-between items-center bg-gray-100">
              <h3 className="font-bold text-sm">Ticket Details</h3>
