// Make TypeScript aware of the global html2canvas variable from the CDN
declare var html2canvas: any;

export const formatWinningNumbersForDisplay = (numbers: number[] | undefined): string => {
    if (!numbers || numbers.length === 0) return 'N/A';
    return numbers.join(' - ');
};

export const formatWinningNumbersForInput = (numbers: number[] | undefined): string => {
    if (!numbers) return '';
    return numbers.join(', ');
};

export const parseWinningNumbersFromString = (str: string): number[] => {
    return str.split(/[\s,\/-]+/)
        .map(s => parseInt(s.trim(), 10))
        .filter(n => !isNaN(n));
};


/**
 * Generates all unique combinations of a specific size from an array.
 */
function getCombinations<T>(array: T[], k: number): T[][] {
  if (k < 0 || k > array.length || k === 0) {
    return [];
  }
  if (k === array.length) {
    return [array];
  }
  const result: T[][] = [];
  function backtrack(combination: T[], start: number) {
    if (combination.length === k) {
      result.push([...combination]);
      return;
    }
    for (let i = start; i < array.length; i++) {
      combination.push(array[i]);
      backtrack(combination, i + 1);
      combination.pop();
    }
  }
  backtrack([], 0);
  return result;
}

/**
 * Generates permutations for the field horses filling the 'X' slots in a specific pattern.
 */
function generateCombinationsFromPattern(pattern: string[], fieldHorses: number[], xCount: number): number[][] {
    const xIndices = pattern.map((val, idx) => val === 'X' ? idx : -1).filter(idx => idx !== -1);

    if (xIndices.length !== xCount) {
        return [];
    }

    const permutations = getPermutations(fieldHorses, xCount);
    const results: number[][] = [];

    for (const perm of permutations) {
        const combo = [...pattern];
        for (let i = 0; i < xCount; i++) {
            combo[xIndices[i]] = perm[i].toString();
        }
        results.push(combo.map(s => parseInt(s, 10)));
    }

    return results;
}

function getPermutations<T>(array: T[], k: number): T[][] {
    if (k === 0) return [[]];
    const result: T[][] = [];

    for (let i = 0; i < array.length; i++) {
        const elem = array[i];
        const remaining = array.filter((_, idx) => idx !== i);
        const remainingPerms = getPermutations(remaining, k - 1);

        for (const perm of remainingPerms) {
            result.push([elem, ...perm]);
        }
    }
    return result;
}


