        <div className="mt-1 text-center border-y-2 border-black py-0.5">
          <p className="text-xs font-black uppercase leading-none">WINNINGS</p>
          <p className="text-3xl font-black leading-none">{ticket.winnings.toFixed(2)}</p>
        </div>
      )}

      <div className="mt-1 pt-1 text-center text-[10px] font-black uppercase leading-tight">
        <div className="flex justify-between items-end">
            <img src={qrCodeUrl} alt="QR" className="w-[50px] h-[50px] block" />
            <div className="text-right flex-1 ml-2">
                <div className="border-b border-black mb-0.5">
                    <span className="block text-[8px] font-black leading-none">REF ID</span>
                    <span className="block text-sm font-mono font-black leading-none">{ticket.id}</span>
                </div>
                <p className="text-[7px] leading-none">Printed At: {new Date().toLocaleString()}</p>
            </div>
        </div>
      </div>
