          <div className="p-2 border-b flex justify-between items-center bg-gray-100">
              <h3 className="font-bold text-sm">Ticket Details</h3>
              <button onClick={onClose} className="text-gray-500 hover:text-red-500 font-bold text-xl px-2">&times;</button>
          </div>

          <div className="flex-grow overflow-y-auto p-1 bg-gray-300 flex justify-center">
            <div className="relative w-full">
                {/* This is the actual printable content container */}
                <div id={`ticket-content-${ticket.id}`} className="printable-content bg-white text-black p-1 font-sans shadow-lg min-h-[150px]">
                    {isPaidReceipt ? renderPaidReceipt() : renderStandardTicket()}
                </div>
            </div>
          </div>

          <div className="flex-shrink-0 p-3 bg-gray-100 border-t rounded-b-lg flex flex-col gap-2">
            {showPrintButton && (
                <button
                    onClick={handlePrint}
                    className="w-full py-3 bg-betese-green text-white font-bold text-lg rounded shadow hover:bg-green-700 flex justify-center items-center gap-2 transition-colors"
                >
                    <span className="text-2xl">🖨️</span> PRINT TICKET
