import React, { useState, useEffect, useMemo } from 'react';
import { Race } from '../types';
import { BETTING_CUTOFF_MS } from '../utils';

interface RaceTimerButtonProps {
  race: Race;
  isSelected: boolean;
  onClick: (raceId: string) => void;
  initialEffectiveTime: Date; // Note: This prop is updated every second by parent App
  variant?: 'vendor' | 'customer';
}

const Icon: React.FC<{ name: string }> = ({ name }) => (
    <span className="text-xl">{name === 'race' ? '🏇' : ''}</span>
);

const RaceTimerButton: React.FC<RaceTimerButtonProps> = ({ race, isSelected, onClick, initialEffectiveTime, variant = 'vendor' }) => {
  // Calculate time left directly from the prop which updates every second.
  // We do not use internal state for time to avoid drift.
  const timeLeft = race.endDate.getTime() - initialEffectiveTime.getTime();

  const isEnded = timeLeft <= 0;

  // FIXED: Strictly use <= to match App.tsx logic.
  // If timeLeft is exactly 120000ms (2 mins), it IS closed.
  const isVisuallyClosed = timeLeft <= BETTING_CUTOFF_MS;

  const isClosingSoon = !isEnded && timeLeft < (BETTING_CUTOFF_MS + 60000); // Warning 1 min before cutoff

  const minutes = Math.max(0, Math.floor(timeLeft / 60000));
  const seconds = Math.max(0, Math.floor((timeLeft % 60000) / 1000));

  const buttonClasses = useMemo(() => {
    if (isEnded || isVisuallyClosed) {
      return 'bg-gray-200 text-gray-500 cursor-not-allowed';
    }
    if (isSelected) {
      return 'bg-betese-green text-white shadow-lg ring-2 ring-betese-yellow';
    }
    if (isClosingSoon) {
      return 'bg-yellow-300 text-yellow-900 shadow-lg ring-2 ring-yellow-500 animate-pulse';
    }
    return 'bg-green-100 text-betese-dark hover:bg-green-200 shadow';
  }, [isEnded, isVisuallyClosed, isSelected, isClosingSoon]);

  const handleClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!isEnded && !isVisuallyClosed) {
      onClick(race.id);
    }
  };

  if (variant === 'vendor') {
    return (
      <button
        onClick={handleClick}
        disabled={isEnded || isVisuallyClosed}
        className={`px-3 py-2 rounded-lg font-medium transition-all flex flex-col justify-center text-center h-24 w-28 ${buttonClasses}`}
      >
        <span className="text-sm font-bold">{race.name}</span>
        <span className="text-xs">({race.endDate.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' })})</span>
        {isEnded || isVisuallyClosed ? (
          <span className="block text-base font-bold font-mono mt-1 text-red-700">CLOSED</span>
        ) : (
          <>
            {isClosingSoon && <span className="text-xs font-bold text-red-700">CLOSING</span>}
            <span className="block text-sm font-bold font-mono mt-1 text-red-600">
              {String(minutes).padStart(2, '0')}:{String(seconds).padStart(2, '0')}
            </span>
          </>
        )}
      </button>
    );
  }

  return (
    <button
      onClick={handleClick}
      disabled={isEnded || isVisuallyClosed}
      className={`p-3 rounded-lg text-base font-medium transition-all flex flex-col items-center justify-center gap-1 w-32 h-28 text-center ${buttonClasses}`}
    >
      <Icon name="race" />
      <span>{race.name}</span>
      <span className="text-xs">{race.endDate.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit', hour12: true })}</span>
      {isEnded || isVisuallyClosed ? (
        <span className="text-sm font-bold font-mono text-red-700">CLOSED</span>
      ) : (
        <>
          {isClosingSoon && <span className="text-xs font-bold text-red-700">CLOSING</span>}
          <span className="text-sm font-bold font-mono text-red-600">
            {String(minutes).padStart(2, '0')}:{String(seconds).padStart(2, '0')}
          </span>
        </>
      )}
    </button>
  );
};

export default RaceTimerButton;

