const InformationBox: React.FC<{ messages: ChatMessage[], threads: ChatThread[], onOpenChat: () => void }> = ({ messages, threads, onOpenChat }) => {
    const latestBroadcast = useMemo(() => {
        const broadcastThread = threads.find(t => t.isBroadcast);
        if (!broadcastThread) return null;

        const broadcastMessages = messages
            .filter(m => m.threadId === broadcastThread.id)
            .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

        return broadcastMessages[0] || null;
    }, [messages, threads]);

    return (
        <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 mb-6">
            <div className="flex justify-between items-start">
                <div>
                    <h3 className="text-xl font-bold text-blue-800 flex items-center gap-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                        Messages & Information
                    </h3>
                    {latestBroadcast ? (
                        <div className="mt-2 text-sm">
                            <p className="text-gray-600">
                                From: <span className="font-semibold">{latestBroadcast.senderName}</span>
                                <span className="ml-2 text-xs text-gray-500">
                                    {new Date(latestBroadcast.timestamp).toLocaleString([], { dateStyle: 'short', timeStyle: 'short' })}
                                </span>
                            </p>
                            <p className="mt-1 text-gray-800">{latestBroadcast.content}</p>
                        </div>
                    ) : (
                        <p className="mt-2 text-gray-600">No new information at this time.</p>
                    )}
                </div>
                <button
                    onClick={onOpenChat}
                    className="flex-shrink-0 ml-4 px-4 py-2 bg-blue-600 text-white font-semibold text-sm rounded-lg hover:bg-blue-700 transition-colors"
                >
                    View All
                </button>
            </div>
        </div>
    );
};

