// Sales Report Screen - Vendor Version (Summary Only)
const SalesReportView: React.FC<{ vendorTickets: Ticket[], effectiveTime: Date, vendorName: string }> = ({ vendorTickets, effectiveTime, vendorName }) => {
    const [reportDate, setReportDate] = useState(effectiveTime.toISOString().split('T')[0]);

    const dailyData = useMemo(() => {
        const [year, month, day] = reportDate.split('-').map(Number);
        const targetDateStart = new Date(year, month - 1, day);
        targetDateStart.setHours(0, 0, 0, 0);
        const targetDateEnd = new Date(targetDateStart);
        targetDateEnd.setDate(targetDateStart.getDate() + 1);

        const ticketsForDay = vendorTickets
            .filter(t => {
                const ticketDate = new Date(t.timestamp);
                return ticketDate >= targetDateStart && ticketDate < targetDateEnd;
            })
            .sort((a, b) => a.timestamp.getTime() - b.timestamp.getTime());

        const sales = ticketsForDay
            .filter(t => ['Active', 'Winning', 'Lost', 'Paid'].includes(t.status))
            .reduce((sum, t) => sum + t.totalCost, 0);

        const payouts = ticketsForDay
            .filter(t => t.status === 'Paid')
            .reduce((sum, t) => sum + (t.winnings ?? 0), 0);

        const profit = sales - payouts;
        return { sales, payouts, profit };
    }, [vendorTickets, reportDate]);

    return (
        <div className="bg-white p-6 rounded-lg shadow-lg max-w-4xl mx-auto">
            <div className="flex flex-col sm:flex-row justify-between sm:items-center mb-4 gap-4">
                <div>
                    <h2 className="text-2xl font-bold text-betese-dark">Vendor Daily Report</h2>
                    <p className="font-semibold text-gray-600">Vendor: {vendorName}</p>
                </div>
                <div>
                    <label htmlFor="sales-date" className="block text-sm font-medium text-gray-700">Select Date</label>
                    <input type="date" id="sales-date" value={reportDate} onChange={e => setReportDate(e.target.value)} className="mt-1 block w-full p-2 border border-gray-300 rounded-md shadow-sm" />
                </div>
            </div>

            <div id="sales-report-printable">
                <div className="printable-content">
                    <div className="text-center mb-4 print-only">
                         <h2 className="text-2xl font-bold text-betese-dark mb-2 text-center">Vendor Daily Report</h2>
                        <p className="font-semibold text-center mb-2">Vendor: {vendorName}</p>
                        <p className="font-bold text-lg">{new Date(reportDate + 'T00:00:00').toDateString()}</p>
                    </div>

                    {/* Summary Cards */}
                    <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 text-center bg-gray-50 p-6 rounded-lg mb-6 border-2 border-gray-200">
                        <div>
                            <p className="text-gray-600 text-sm font-semibold uppercase tracking-wide">Total Sales</p>
                            <p className="text-3xl font-black text-blue-600">{dailyData.sales.toFixed(2)} GMD</p>
                        </div>
                        <div>
                            <p className="text-gray-600 text-sm font-semibold uppercase tracking-wide">Total Payouts</p>
                            <p className="text-3xl font-black text-red-600">{dailyData.payouts.toFixed(2)} GMD</p>
                        </div>
                         <div>
                            <p className="text-gray-600 text-sm font-semibold uppercase tracking-wide">Net Profit</p>
                            <p className={`text-3xl font-black ${dailyData.profit >= 0 ? 'text-betese-green' : 'text-red-600'}`}>{dailyData.profit.toFixed(2)} GMD</p>
                        </div>
                    </div>
                    {/* Detailed ticket table removed for Vendors as requested */}
                </div>
            </div>

            <button onClick={() => triggerPrint('sales-report-printable')} className="mt-6 w-full px-4 py-3 bg-betese-green text-white font-bold text-lg rounded-lg hover:bg-green-700 shadow-md">Print Summary Report</button>
        </div>
    );
};

const TicketToolsView: React.FC<{ allTickets: Ticket[], onCancelTicket: (ticketId: string) => void, races: Race[], onPayoutTicket: (ticketId: string) => void, effectiveTime: Date, onReprintTicket: (ticket: Ticket) => void, currentUser: User }> = ({ allTickets, onCancelTicket, races, onPayoutTicket, effectiveTime, onReprintTicket, currentUser }) => {
    const [ticketId, setTicketId] = useState('');
    const [foundTicket, setFoundTicket] = useState<Ticket | null>(null);
    const [effectiveStatus, setEffectiveStatus] = useState<string>('');
    const [message, setMessage] = useState('');

    // Fetch last 3 tickets for this vendor to allow quick reprint
    const recentVendorTickets = useMemo(() => {
        return allTickets
            .filter(t => t.vendorId === currentUser.id && t.status !== 'Booked')
            .sort((a, b) => b.timestamp.getTime() - a.timestamp.getTime())
            .slice(0, 3);
    }, [allTickets, currentUser.id]);

    const handleFindTicket = () => {
        setMessage(''); setFoundTicket(null); setEffectiveStatus('');
        if (!ticketId) { setMessage('Please enter a Ticket ID.'); return; }
        const ticket = allTickets.find(t => t.id === ticketId);
        if (ticket) {
            setFoundTicket(ticket);
            setEffectiveStatus(getEffectiveTicketStatus(ticket, effectiveTime));
        } else {
            setMessage('Ticket not found.');
        }
    };

    const isTicketCancellable = (ticket: Ticket): boolean => {
        if (ticket.status === 'Booked') return true;
        if (ticket.status !== 'Active') return false;

        const hasRaceStarted = ticket.selections.some(selection => {
            const race = races.find(r => r.id === selection.raceId);
            return race && effectiveTime >= race.startDate;
        });
        return !hasRaceStarted;
    };

    const handleCancel = () => {
        if (!foundTicket) return;
        onCancelTicket(foundTicket.id);
        setMessage(`Ticket ${foundTicket.id} has been canceled.`);
        setFoundTicket(null);
        setTicketId('');
    };

    const handlePayout = () => {
        if (foundTicket) {
          onPayoutTicket(foundTicket.id);
          setMessage(`Ticket ${foundTicket.id} has been paid out.`);
          setFoundTicket(null);
          setTicketId('');
        }
    };

    const handleReprint = (ticket: Ticket) => {
        onReprintTicket(ticket);
    };

    return (
        <div className="space-y-6">
            <div className="bg-white p-6 rounded-lg shadow-lg max-w-2xl mx-auto">
                <h2 className="text-2xl font-bold text-betese-dark mb-4">Ticket Payout & Check</h2>
                <div className="flex gap-2">
                    <input type="text" value={ticketId} onChange={e => setTicketId(e.target.value)} placeholder="Enter Ticket ID to check, pay, or cancel" className="flex-grow p-2 border border-gray-300 rounded-md" />
                    <button onClick={handleFindTicket} className="px-4 py-2 bg-blue-600 text-white font-semibold rounded-lg hover:bg-blue-700">Find Ticket</button>
                </div>
                {message && <p className={`text-center text-sm p-2 mt-4 rounded-md ${message.includes('paid') || message.includes('canceled') ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800'}`}>{message}</p>}

                {foundTicket && (
                    <div className="mt-4 p-4 bg-gray-50 border rounded-lg space-y-3">
                        <p><strong>ID:</strong> {foundTicket.id}</p>
                        <p><strong>Status:</strong> <span className="font-bold">{effectiveStatus}</span></p>
                        <p><strong>Cost:</strong> {foundTicket.totalCost.toFixed(2)} GMD</p>
                        {foundTicket.winnings !== undefined && (effectiveStatus === 'Winning' || effectiveStatus === 'Paid') && (
                            <p className="text-lg font-bold text-green-600">
                                Winnings: {foundTicket.winnings.toFixed(2)} GMD
                            </p>
                        )}
                        <div className="flex flex-col gap-2 pt-3 border-t">
                            {effectiveStatus === 'Winning' && (
                                <button onClick={handlePayout} className="w-full px-4 py-3 bg-betese-green text-white font-bold rounded-lg hover:bg-green-700">
                                    Pay Winnings & Print Receipt
                                </button>
                            )}
                            {isTicketCancellable(foundTicket) && (
                                <button onClick={handleCancel} className="w-full px-4 py-2 bg-red-600 text-white font-semibold rounded-lg hover:bg-red-700">
                                    Cancel Ticket
                                </button>
                            )}
                            {(effectiveStatus === 'Winning' || effectiveStatus === 'Paid') && (
                                <button onClick={() => handleReprint(foundTicket)} className="w-full px-4 py-2 bg-gray-500 text-white font-semibold rounded-lg hover:bg-gray-600">
                                    Re-Print Receipt
                                </button>
                            )}
                        </div>
                    </div>
                )}
            </div>

            {/* LAST 3 TICKETS SECTION - For Quick Reprinting */}
            <div className="bg-white p-6 rounded-lg shadow-lg max-w-2xl mx-auto">
                <h3 className="text-lg font-bold text-gray-700 mb-3 border-b pb-2">Your Recent Tickets (Last 3)</h3>
                {recentVendorTickets.length > 0 ? (
                    <div className="space-y-3">
                        {recentVendorTickets.map(ticket => (
                            <div key={ticket.id} className="flex justify-between items-center p-3 bg-gray-50 rounded-md border">
                                <div>
                                    <p className="text-sm font-bold font-mono">{ticket.id}</p>
                                    <p className="text-xs text-gray-500">{ticket.timestamp.toLocaleTimeString()}</p>
                                </div>
                                <div className="text-right">
                                    <p className="font-bold text-sm">{ticket.totalCost.toFixed(2)} GMD</p>
                                    <button 
                                        onClick={() => handleReprint(ticket)} 
                                        className="mt-1 px-3 py-1 bg-gray-600 text-white text-xs font-bold rounded hover:bg-gray-700"
                                    >
                                        Reprint
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <p className="text-gray-500 text-sm italic">No recent tickets found.</p>
                )}
            </div>
        </div>
    );
};

export const BettingTerminal: React.FC<BettingTerminalProps> = (props) => {
    const { 
        races, betSlip, onUpdateBetSlip, onClearBetSlip, onInitiatePlaceBet, onRemoveSelection, onUpdateSelectionMultiplier,
        allTickets, onPayForBooking, customers, onDeposit, depositLogs, placedTickets, messages, threads, onOpenChat, effectiveTime, currentUser,
        lastTicket, onCloseTicket
    } = props;
    const [view, setView] = useState<View>('DASHBOARD');
    const [rapportModalRace, setRapportModalRace] = useState<Race | null>(null);
    const [bookingSlipToPrint, setBookingSlipToPrint] = useState<Ticket | null>(null);

    const sortedRaces = useMemo(() => [...races].sort((a,b) => a.endDate.getTime() - b.endDate.getTime()), [races]);
    const [selectedRace, setSelectedRace] = useState<Race | null>(races.find(r => r.endDate > effectiveTime) || null);
    const [selectedBetType, setSelectedBetType] = useState<BetTypeOption | null>(null);
    const [selectedNumbers, setSelectedNumbers] = useState<number[]>([]);
    const [xCount, setXCount] = useState<number>(0);
    const [pattern, setPattern] = useState<string[]>([]);
    const availableBetTypes = useMemo(() => Object.values(BetTypeOption), []);

    useEffect(() => {
        if (selectedRace && effectiveTime >= selectedRace.endDate) {
            setSelectedRace(sortedRaces.find(r => r.endDate > effectiveTime) || null);
        } else if (!selectedRace) {
             setSelectedRace(sortedRaces.find(r => r.endDate > effectiveTime) || null);
        }
    }, [effectiveTime, selectedRace, sortedRaces]);


    const handleAddBet = () => {
        if (!selectedRace || !selectedBetType) {
            alert('Please select a race and a bet type.');
            return;
        }

        const timeRemaining = selectedRace.endDate.getTime() - effectiveTime.getTime();
        // Strict check matches App.tsx
        if (timeRemaining <= BETTING_CUTOFF_MS) {
            alert("Betting for this race is CLOSED (Cutoff: 2 mins before race).");
            return;
        }

        const pricing = BET_PRICING[selectedBetType];
        const totalSelections = selectedNumbers.length + xCount;

        if (totalSelections < pricing.minHorses) {
            alert(`Please select at least ${pricing.minHorses} horses for ${selectedBetType}.`);
            return;
        }

        onUpdateBetSlip({
            raceId: selectedRace.id,
            raceName: selectedRace.name,
            betType: selectedBetType,
            numbers: selectedNumbers,
            xCount: xCount,
            pattern: pattern,
        });

        setSelectedNumbers([]);
        setXCount(0);
        setPattern([]);
        setSelectedBetType(null);
    };

    const handleSelectRace = (raceId: string) => {
        const race = races.find(r => r.id === raceId);
        if (race) {
            setSelectedRace(race);
            setSelectedBetType(null);
            setSelectedNumbers([]);
            setXCount(0);
            setPattern([]);
        }
    };

    const handleSelectBetType = (betType: BetTypeOption) => {
        setSelectedBetType(betType);
        setSelectedNumbers([]);
        setXCount(0);
        setPattern([]);
    };

    const renderView = () => {
        switch (view) {
            case 'PLACE_BET':
                const timeRemaining = selectedRace ? selectedRace.endDate.getTime() - effectiveTime.getTime() : 0;
                const isRaceClosed = timeRemaining <= BETTING_CUTOFF_MS;
                const bettingTimeRemaining = Math.max(0, timeRemaining - BETTING_CUTOFF_MS);

                if(isRaceClosed && (selectedNumbers.length > 0 || xCount > 0)) {
                    setSelectedNumbers([]);
                    setXCount(0);
                    setPattern([]);
                }

                return (
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                        <div className="lg:col-span-2 space-y-6">
                            <div className="bg-white p-6 rounded-lg shadow-lg">
                                <div className="flex justify-between items-center mb-4">
                                    <h2 className="text-2xl font-bold text-betese-dark">Place a Bet</h2>

                                    {selectedRace && !isRaceClosed && (
                                        <div className={`text-center px-3 py-1 rounded border-2 ${bettingTimeRemaining < 60000 ? 'bg-red-100 border-red-500 text-red-700 animate-pulse' : 'bg-green-100 border-green-500 text-green-800'}`}>
                                            <p className="text-[10px] font-bold uppercase">Time Left To Bet</p>
                                            <p className="text-xl font-mono font-black">
                                                {Math.floor(bettingTimeRemaining / 60000).toString().padStart(2, '0')}:
                                                {Math.floor((bettingTimeRemaining % 60000) / 1000).toString().padStart(2, '0')}
                                            </p>
                                        </div>
                                    )}
                                </div>

                                <div className="mb-6">
                                    <h3 className="text-lg font-semibold mb-2">1. Select a Race</h3>
                                    {sortedRaces.length > 0 ? (
                                        <div className="flex flex-wrap gap-2">
                                            {sortedRaces.map((race) => (
                                                <RaceTimerButton
                                                    key={race.id}
                                                    race={race}
                                                    isSelected={selectedRace?.id === race.id}
                                                    onClick={handleSelectRace}
                                                    initialEffectiveTime={effectiveTime}
                                                    variant="vendor"
                                                />
                                            ))}
                                        </div>
                                    ) : (
                                        <p className="text-gray-500">There are no races available for betting.</p>
                                    )}
                                </div>

                                {selectedRace && (
                                    <>
                                    <div className="mb-6">
                                        <h3 className="text-lg font-semibold mb-2">2. Select Bet Type</h3>
                                        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-3">
                                            {availableBetTypes.map((betType) => {
                                                const isDisabled = selectedRace.disabledBetTypes?.includes(betType);
                                                return (
                                                    <button
                                                        key={betType}
                                                        onClick={() => handleSelectBetType(betType)}
                                                        disabled={isDisabled}
                                                        className={`relative p-3 text-center rounded-lg text-sm font-semibold transition-all flex flex-col items-center justify-center h-24 gap-1 ${
                                                            isDisabled 
                                                                ? 'bg-gray-300 text-gray-400 cursor-not-allowed line-through' 
                                                                : (selectedBetType === betType ? 'bg-yellow-400 text-betese-dark ring-2 ring-betese-green shadow-lg' : 'bg-gray-100 text-gray-800 hover:bg-yellow-200 shadow')
                                                        }`}
                                                    >
                                                        <span className="text-3xl"><Icon name={betType} /></span>
                                                        <span className="text-sm font-bold leading-tight">{betType}</span>
                                                        {isDisabled && <span className="absolute top-1 right-1 text-red-600 font-black text-lg">X</span>}
                                                    </button>
                                                );
                                            })}
                                        </div>
                                    </div>

                                    {selectedBetType && (
                                        <HorseSelector
                                            race={selectedRace}
                                            betType={selectedBetType}
                                            selectedNumbers={selectedNumbers}
                                            xCount={xCount}
                                            onNumberSelect={setSelectedNumbers}
                                            onXSelect={setXCount}
                                            onPatternChange={setPattern}
                                            disabled={isRaceClosed}
                                        />
                                    )}
                                    </>
                                )}

                                <div className="mt-6 flex justify-end">
                                    <button
                                        onClick={handleAddBet}
                                        disabled={!selectedRace || !selectedBetType || selectedNumbers.length + xCount === 0 || isRaceClosed}
                                        className="px-6 py-3 bg-betese-green text-white font-bold rounded-lg hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed"
                                    >
                                        Add to Bet Slip
                                    </button>
                                </div>
                            </div>
                        </div>

                        <div className="lg:col-span-1">
                            <BetSlipPanel
                                betSlip={betSlip}
                                onClear={onClearBetSlip}
                                onInitiatePlaceBet={onInitiatePlaceBet}
                                onRemove={onRemoveSelection}
                                onUpdateSelectionMultiplier={onUpdateSelectionMultiplier}
                            />
                        </div>
                    </div>
                );
            case 'ONLINE':
                return (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        <AppQRCodePanel />
                        <BookingRetrievalPanel allTickets={allTickets} onPayForBooking={onPayForBooking} onPrintBookingSlip={setBookingSlipToPrint} />
                        <ProcessWithdrawalPanel withdrawalRequests={props.withdrawalRequests} onProcessWithdrawal={props.onProcessWithdrawal} customers={customers} />
                        <CustomerDepositPanel 
                            customers={customers} 
                            onDeposit={onDeposit} 
                            depositLogs={depositLogs} 
                            depositRequests={props.depositRequests}
                            onApproveDepositRequest={props.onApproveDepositRequest}
                            onRejectDepositRequest={props.onRejectDepositRequest}
                            currentUserRole={currentUser.role}
                        />
                    </div>
                );
            case 'SALES_REPORT':
                return <SalesReportView vendorTickets={placedTickets} effectiveTime={effectiveTime} vendorName={currentUser.name} />;
            case 'PAYOUT_REPORTS':
                return <PayoutReportView races={races} onPrintRequest={setRapportModalRace} effectiveTime={effectiveTime} />;
            case 'TICKET_TOOLS':
                return (
                    <div className="space-y-6">
                        <TicketToolsView allTickets={allTickets} onCancelTicket={props.onCancelTicket} races={races} onPayoutTicket={props.onPayoutTicket} effectiveTime={effectiveTime} onReprintTicket={props.onReprintTicket} currentUser={currentUser} />
                    </div>
                );
            case 'SCAN':
                return (
                    <div className="bg-white p-6 rounded-lg shadow-lg text-center">
                        <h2 className="text-2xl font-bold text-betese-dark mb-4">Scan Ticket QR Code</h2>
                        <div className="bg-gray-100 p-10 rounded-lg border-2 border-dashed border-gray-400">
                            <p className="text-gray-500 mb-4">Camera scanning feature is currently in development.</p>
                            <button className="px-6 py-3 bg-blue-600 text-white font-bold rounded-lg hover:bg-blue-700">Activate Camera</button>
                        </div>
                    </div>
                );
            case 'RESULT_UPDATE':
                return <ResultUpdatePanel races={races} onPrintRequest={setRapportModalRace} effectiveTime={effectiveTime} />;
            case 'DASHBOARD':
            default:
                return <VendorDashboardView setView={setView} messages={messages} threads={threads} onOpenChat={onOpenChat} />;
        }
    };

    return (
        <div className="space-y-6">
            {view !== 'DASHBOARD' && <BackButton onClick={() => setView('DASHBOARD')} />}

            {lastTicket && (
                <TicketModal 
                    ticket={lastTicket} 
                    onClose={onCloseTicket} 
                    showPrintButton={true} 
                    races={races} 
                />
            )}

            {rapportModalRace && <RapportModal race={rapportModalRace} onClose={() => setRapportModalRace(null)} showPrintButton={true} />}
            {bookingSlipToPrint && <BookingCodeModal ticket={bookingSlipToPrint} onClose={() => setBookingSlipToPrint(null)} />}
            {renderView()}
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { BetSlip, BetTypeOption, Race, Ticket, BetSelection, User, WithdrawalRequest, Promotion, DepositRequest, ProgramImage } from '../types';
import { BetSlipPanel } from './BetSlipPanel';
import { HorseSelector } from './HorseSelector';
import { TicketModal } from './TicketModal';
import { BET_PRICING } from '../constants';
import { TicketHistoryPanel } from './TicketHistoryPanel';
import { WinningTicketModal } from './WinningTicketModal';
import { WalletPanel } from './WalletPanel';
import { RaceResultsPanel } from './RaceResultsPanel';
import { RapportModal } from './RapportModal';
import { ProgramModal } from './ProgramModal';
import { PromotionCarousel } from './PromotionCarousel';
import { PromotionTicker } from './PromotionTicker';
import { PasswordChangePanel } from './PasswordChangePanel';
import { OfficialPayoutsPanel } from './AllBetsPricesPanel';
import RaceTimerButton from './RaceTimerButton';
import { RulesModal } from './RulesModal';
import { useLanguage } from '../LanguageContext';
import { BETTING_CUTOFF_MS } from '../utils';
import { WhatsAppButton } from './WhatsAppButton';


interface CustomerDashboardProps {
  user: User;
  races: Race[];
  betSlip: BetSlip;
  onUpdateBetSlip: (selection: Omit<BetSelection, 'cost' | 'multiplier'>) => void;
  onClearBetSlip: () => void;
  onInitiatePlaceBet: () => void;
  onInitiateBookBet: () => void;
  lastTicket: Ticket | null;
  onCloseTicket: () => void;
  onRemoveSelection: (index: number) => void;
  onUpdateSelectionMultiplier: (index: number, multiplier: number) => void;
  placedTickets: Ticket[];
  onCancelTicket: (ticketId: string) => void;
  seenWinningTickets: Set<string>;
  onMarkWinningTicketAsSeen: (ticketId: string) => void;
  onWithdrawalRequest: (amount: number) => void;
  withdrawalRequests: WithdrawalRequest[];
  onWalletFlash: () => void;
  programImages: ProgramImage[];
  promotions: Promotion[];
  onChangePassword: (userId: string, oldPass: string, newPass: string) => { success: boolean, message: string };
  effectiveTime: Date;
  onDepositRequest: (amount: number, method: 'Wave' | 'AfriMoney', transactionId: string) => void;
  depositRequests: DepositRequest[];
  onCancelWithdrawal?: (requestId: string) => void; // New Prop
}

const Icon: React.FC<{ name: string }> = ({ name }) => {
    const icons: { [key: string]: React.ReactNode } = {
        'Simple Gagnant': <span title="Simple Gagnant">🏆</span>,
        'Simple Placé': <span title="Simple Placé">🏅</span>,
        'Couplé Gagnant': <span title="Couplé Gagnant">🥇🥈</span>,
        'Couplé Placé': <span title="Couplé Placé">🎖️</span>,
        'Tiercé': <span title="Tiercé">🥉</span>,
        'Quarté+': <span title="Quarté+">4️⃣</span>,
        'Quinté+': <span title="Quinté+">5️⃣</span>,
        'Multi 4': <span title="Multi 4">M4</span>,
        'Multi 5': <span title="Multi 5">M5</span>,
        'Multi 6': <span title="Multi 6">M6</span>,
        'Multi 7': <span title="Multi 7">M7</span>,
    };
    return icons[name] || null;
}

const TabButton: React.FC<{ label: string; isActive: boolean; onClick: () => void }> = ({ label, isActive, onClick }) => (
    <button
        onClick={onClick}
        className={`w-full text-center px-4 py-3 text-base sm:text-lg font-bold rounded-lg transition-all ${
            isActive
                ? 'bg-betese-green text-white shadow-md'
                : 'bg-gray-200 text-gray-600 hover:bg-gray-300'
        }`}
    >
        {label}
    </button>
);

export const CustomerDashboard: React.FC<CustomerDashboardProps> = ({
  user,
  races,
  betSlip,
  onUpdateBetSlip,
  onClearBetSlip,
  onInitiatePlaceBet,
  onInitiateBookBet,
  lastTicket,
  onCloseTicket,
  onRemoveSelection,
  onUpdateSelectionMultiplier,
  placedTickets,
  onCancelTicket,
  seenWinningTickets,
  onMarkWinningTicketAsSeen,
  onWithdrawalRequest,
  withdrawalRequests,
  onWalletFlash,
  programImages,
  promotions,
  onChangePassword,
  effectiveTime,
  onDepositRequest,
  depositRequests,
  onCancelWithdrawal
}) => {
  const [activeTab, setActiveTab] = useState<'bet' | 'history' | 'wallet' | 'info'>('bet');
  const [rapportModalRace, setRapportModalRace] = useState<Race | null>(null);
  const [isProgramModalOpen, setIsProgramModalOpen] = useState(false);
  const [isRulesModalOpen, setIsRulesModalOpen] = useState(false);
  const [showPromoTV, setShowPromoTV] = useState(true); // State for TV visibility
  const { t } = useLanguage();

  const sortedRaces = useMemo(() => [...races].sort((a,b) => a.endDate.getTime() - b.endDate.getTime()), [races]);

  const [selectedRace, setSelectedRace] = useState<Race | null>(sortedRaces.find(r => r.endDate > effectiveTime) || null);
  const [selectedBetType, setSelectedBetType] = useState<BetTypeOption | null>(null);
  const [selectedNumbers, setSelectedNumbers] = useState<number[]>([]);
  const [xCount, setXCount] = useState<number>(0);
  const [pattern, setPattern] = useState<string[]>([]);

  const availableBetTypes = useMemo(() => Object.values(BetTypeOption), []);

  const winningTicketToShow = useMemo(() => {
      return placedTickets.find(t => t.status === 'Winning' && !seenWinningTickets.has(t.id));
  }, [placedTickets, seenWinningTickets]);

  const latestResultedRace = useMemo(() => {
    return races
      .filter(r => r.result)
      .sort((a, b) => b.endDate.getTime() - a.endDate.getTime())[0] || null;
  }, [races]);

  useEffect(() => {
    if (selectedRace && effectiveTime >= selectedRace.endDate) {
        setSelectedRace(sortedRaces.find(r => r.endDate > effectiveTime) || null);
    } else if (!selectedRace) {
        setSelectedRace(sortedRaces.find(r => r.endDate > effectiveTime) || null);
    }
  }, [effectiveTime, selectedRace, sortedRaces]);


  const handleAddBet = () => {
    if (!selectedRace || !selectedBetType) {
      alert('Please select a race and a bet type.');
      return;
    }

    // UI-SIDE PREVENTION - MATCHES APP.TSX
    const timeRemaining = selectedRace.endDate.getTime() - effectiveTime.getTime();
    if (timeRemaining <= BETTING_CUTOFF_MS) {
        alert("Betting for this race is CLOSED (Cutoff: 2 mins before race).");
        return;
    }

    const pricing = BET_PRICING[selectedBetType];
    const totalSelections = selectedNumbers.length + xCount;

    if (totalSelections < pricing.minHorses) {
      alert(`Please select at least ${pricing.minHorses} horses for ${selectedBetType}.`);
      return;
    }

    onUpdateBetSlip({
        raceId: selectedRace.id,
        raceName: selectedRace.name,
        betType: selectedBetType,
        numbers: selectedNumbers,
        xCount: xCount,
        pattern: pattern,
    });

    // Reset for next selection
    setSelectedNumbers([]);
    setXCount(0);
    setPattern([]);
    setSelectedBetType(null);
  };

  const handleSelectRace = (raceId: string) => {
    const race = sortedRaces.find(r => r.id === raceId);
    if (race) {
        setSelectedRace(race);
        setSelectedBetType(null);
        setSelectedNumbers([]);
        setXCount(0);
        setPattern([]);
    }
  };

  const handleSelectBetType = (betType: BetTypeOption) => {
    setSelectedBetType(betType);
    setSelectedNumbers([]);
    setXCount(0);
    setPattern([]);
  };

  const programs = useMemo(() => programImages.filter(img => img.type === 'program'), [programImages]);
  const advertisements = useMemo(() => programImages.filter(img => img.type === 'advertisement'), [programImages]);

  // Real-time check for closure
  const timeRemaining = selectedRace ? selectedRace.endDate.getTime() - effectiveTime.getTime() : 0;
  const isRaceClosed = timeRemaining <= BETTING_CUTOFF_MS;
  const bettingTimeRemaining = Math.max(0, timeRemaining - BETTING_CUTOFF_MS);

  // Aggressively clear inputs if race closes while open
  if(isRaceClosed && (selectedNumbers.length > 0 || xCount > 0)) {
        setSelectedNumbers([]);
        setXCount(0);
        setPattern([]);
  }

  return (
    <div className="space-y-6">
      <WhatsAppButton />
      {lastTicket && <TicketModal ticket={lastTicket} onClose={onCloseTicket} showPrintButton={false} races={races} />}
      {winningTicketToShow && <WinningTicketModal ticket={winningTicketToShow} onClose={() => onMarkWinningTicketAsSeen(winningTicketToShow.id)} />}
      {rapportModalRace && (
        <RapportModal 
          race={rapportModalRace} 
          onClose={() => setRapportModalRace(null)}
          showPrintButton={false}
        />
      )}
      <ProgramModal isOpen={isProgramModalOpen} onClose={() => setIsProgramModalOpen(false)} programImages={programs} />
      <RulesModal isOpen={isRulesModalOpen} onClose={() => setIsRulesModalOpen(false)} />

      {showPromoTV && (
        <PromotionCarousel ads={advertisements} onClose={() => setShowPromoTV(false)} />
      )}

      <PromotionTicker promotions={promotions} />

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-2 space-y-6">
            <div className="bg-white p-2 rounded-lg shadow-lg grid grid-cols-2 md:grid-cols-4 gap-2">
                <TabButton label={t('tab_place_bet')} isActive={activeTab === 'bet'} onClick={() => setActiveTab('bet')} />
                <TabButton label={t('tab_history')} isActive={activeTab === 'history'} onClick={() => setActiveTab('history')} />
                <TabButton label={t('tab_wallet')} isActive={activeTab === 'wallet'} onClick={() => setActiveTab('wallet')} />
                <TabButton label={t('tab_info')} isActive={activeTab === 'info'} onClick={() => setActiveTab('info')} />
            </div>

            {activeTab === 'bet' && (
              <div className="bg-white p-6 rounded-lg shadow-lg">
                  <div className="flex justify-between items-center mb-4">
                    <h2 className="text-2xl font-bold text-betese-dark">{t('welcome')}, {user.name}!</h2>
                    {/* Betting Countdown Timer */}
                    {selectedRace && !isRaceClosed && (
                        <div className={`text-center px-3 py-1 rounded border-2 ${bettingTimeRemaining < 60000 ? 'bg-red-100 border-red-500 text-red-700 animate-pulse' : 'bg-green-100 border-green-500 text-green-800'}`}>
                            <p className="text-[10px] font-bold uppercase">Time Left To Bet</p>
                            <p className="text-xl font-mono font-black">
                                {Math.floor(bettingTimeRemaining / 60000).toString().padStart(2, '0')}:
                                {Math.floor((bettingTimeRemaining % 60000) / 1000).toString().padStart(2, '0')}
                            </p>
                        </div>
                    )}
                  </div>

                  <div className="mb-6">
                  <h3 className="text-lg font-semibold mb-2">{t('select_race')}</h3>
                  {sortedRaces.length > 0 ? (
                      <div className="flex flex-wrap gap-3">
                          {sortedRaces.map((race) => (
                              <RaceTimerButton
                                  key={race.id}
                                  race={race}
                                  isSelected={selectedRace?.id === race.id}
                                  onClick={handleSelectRace}
                                  initialEffectiveTime={effectiveTime}
                                  variant="customer"
                              />
                          ))}
                      </div>
                  ) : (
                      <p className="text-gray-500">{t('no_races')}</p>
                  )}
                  </div>

                  {selectedRace && (
                      <>
                      <div className="mb-6">
                          <h3 className="text-lg font-semibold mb-2">{t('select_bet_type')}</h3>
                          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-3">
                          {availableBetTypes.map((betType) => {
                              const isDisabled = selectedRace.disabledBetTypes?.includes(betType);
                              return (
                                  <button
                                      key={betType}
                                      onClick={() => handleSelectBetType(betType)}
                                      disabled={isDisabled}
                                      className={`relative p-3 text-center rounded-lg text-sm font-semibold transition-all flex flex-col items-center justify-center h-24 gap-1 ${
                                          isDisabled 
                                              ? 'bg-gray-300 text-gray-500 cursor-not-allowed'
                                              : (selectedBetType === betType ? 'bg-yellow-400 text-betese-dark ring-2 ring-betese-green shadow-lg' : 'bg-gray-100 text-gray-800 hover:bg-yellow-200 shadow')
                                      }`}
                                  >
                                      <span className="text-2xl"><Icon name={betType} /></span>
                                      <span className="text-sm font-bold">{betType}</span>
                                      {isDisabled && <span className="absolute top-1 right-1 text-red-600 font-black text-lg">X</span>}
                                  </button>
                              );
                          })}
                          </div>
                      </div>

                      {selectedBetType && (
                          <HorseSelector
                              race={selectedRace}
                              betType={selectedBetType}
                              selectedNumbers={selectedNumbers}
                              xCount={xCount}
                              onNumberSelect={setSelectedNumbers}
                              onXSelect={setXCount}
                              onPatternChange={setPattern}
                              disabled={isRaceClosed}
                          />
                      )}
                      </>
                  )}

                  <div className="mt-6 flex justify-end">
                      <button
                          onClick={handleAddBet}
                          disabled={!selectedRace || !selectedBetType || selectedNumbers.length + xCount === 0 || isRaceClosed}
                          className="px-8 py-3 bg-betese-green text-white font-bold rounded-lg shadow-md hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-transform transform hover:scale-105"
                      >
                          {t('add_to_slip')}
                      </button>
                  </div>
              </div>
            )}
            {activeTab === 'history' && (
                <TicketHistoryPanel
                    tickets={placedTickets}
                    onCancelTicket={onCancelTicket}
                    races={races}
                    effectiveTime={effectiveTime}
                />
            )}
            {activeTab === 'wallet' && (
                <div className="space-y-6">
                    <WalletPanel 
                      user={user} 
                      onWithdrawalRequest={onWithdrawalRequest} 
                      withdrawalRequests={withdrawalRequests} 
                      onWalletFlash={onWalletFlash} 
                      onDepositRequest={onDepositRequest}
                      depositRequests={depositRequests}
                      onCancelWithdrawal={onCancelWithdrawal} // Pass new Prop
                    />
                    <PasswordChangePanel user={user} onChangePassword={onChangePassword} />
                </div>
            )}
             {activeTab === 'info' && (
                <div className="space-y-6">
                    <div className="bg-white p-6 rounded-lg shadow-lg">
                         <h3 className="text-xl font-bold text-betese-dark mb-4">{t('legal_compliance')}</h3>
                         <button 
                            onClick={() => setIsRulesModalOpen(true)}
                            className="w-full flex items-center justify-center gap-2 px-4 py-3 bg-betese-green text-white font-semibold rounded-lg hover:bg-green-700 transition-colors shadow-md"
                        >
                            <span className="text-xl">⚖️</span>
                            {t('official_rules_link')}
                        </button>
                    </div>
                    <OfficialPayoutsPanel latestResultedRace={latestResultedRace} />
                </div>
            )}
          </div>

          <div className="lg:col-span-1 space-y-6">
             <div className="bg-white p-6 rounded-lg shadow-lg">
                <h3 className="text-xl font-bold text-betese-dark mb-4">{t('daily_program')}</h3>
                <button
                    onClick={() => setIsProgramModalOpen(true)}
                    className="w-full flex items-center justify-center gap-2 px-4 py-3 bg-betese-dark text-white font-semibold rounded-lg hover:bg-gray-800 transition-colors"
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 7v10a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-6l-2-2H5a2 2 0 00-2 2z" /></svg>
                    {t('view_programs')}
                </button>
            </div>
            <BetSlipPanel
              betSlip={betSlip}
              onClear={onClearBetSlip}
              onInitiatePlaceBet={onInitiatePlaceBet}
              onInitiateBookBet={onInitiateBookBet}
              onRemove={onRemoveSelection}
              onUpdateSelectionMultiplier={onUpdateSelectionMultiplier}
            />
            <RaceResultsPanel races={races} onSelectRace={setRapportModalRace} effectiveTime={effectiveTime} />
          </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Ticket, Race } from '../types';
import { BETTING_CUTOFF_MS } from '../utils';

interface BookingRetrievalPanelProps {
  allTickets: Ticket[];
  onPayForBooking: (bookingCode: string) => { success: boolean; message: string };
  onPrintBookingSlip: (ticket: Ticket) => void;
  races: Race[];
  effectiveTime: Date;
}

export const BookingRetrievalPanel: React.FC<BookingRetrievalPanelProps> = ({ allTickets, onPayForBooking, onPrintBookingSlip, races, effectiveTime }) => {
  const [bookingCode, setBookingCode] = useState('');
  const [foundTicket, setFoundTicket] = useState<Ticket | null>(null);
  const [message, setMessage] = useState('');
  const [isSuccess, setIsSuccess] = useState(false);

  const handleFindBooking = () => {
    setMessage('');
    setFoundTicket(null);
    setIsSuccess(false);
    if (!bookingCode) {
        setMessage('Please enter a Booking Code.');
        return;
    }
    const ticket = allTickets.find(t => t.bookingCode?.toUpperCase() === bookingCode.toUpperCase() && t.status === 'Booked');
    if (ticket) {
        setFoundTicket(ticket);
    } else {
        setMessage('Booking code not found or has already been processed.');
    }
  };

  const handlePay = () => {
      if (!foundTicket?.bookingCode) return;

      const result = onPayForBooking(foundTicket.bookingCode);
      setMessage(result.message);
      setIsSuccess(result.success);

      if(result.success) {
          setFoundTicket(null);
          setBookingCode('');
      }
  }

  // Check if ticket is expired based on race time
  const isTicketExpired = () => {
      if (!foundTicket) return false;
      const now = effectiveTime.getTime();
      return foundTicket.selections.some(selection => {
          const race = races.find(r => r.id === selection.raceId);
          if (!race) return true; // Safety: if race not found, assume unpayable
          const timeRemaining = race.endDate.getTime() - now;
          return timeRemaining <= BETTING_CUTOFF_MS;
      });
  };

  const expired = isTicketExpired();

  return (
    <div className="bg-white p-6 rounded-lg shadow-lg border-2 border-transparent hover:border-blue-100 transition-colors">
      <h3 className="text-xl font-bold text-betese-dark mb-4">Retrieve & Pay Booking</h3>
      <div className="space-y-4">
        <div className="flex gap-2">
            <input
            type="text"
            value={bookingCode}
            onChange={(e) => setBookingCode(e.target.value)}
            placeholder="Enter Booking Code"
            className="flex-grow p-3 border-2 border-gray-300 rounded-lg uppercase font-bold text-lg tracking-widest focus:border-betese-green focus:ring-0"
            />
            <button
                onClick={handleFindBooking}
                className="px-6 py-2 bg-blue-600 text-white font-bold rounded-lg hover:bg-blue-700 shadow-md"
            >
                Find
            </button>
        </div>

        {message && <p className={`text-center text-sm p-3 font-bold rounded-md ${isSuccess ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>{message}</p>}

        {foundTicket && (
            <div className={`mt-4 p-4 rounded-lg border-2 shadow-sm ${expired ? 'bg-red-50 border-red-200' : 'bg-yellow-50 border-yellow-200'}`}>
                {expired && (
                    <div className="mb-4 p-3 bg-red-600 text-white rounded text-center shadow">
                        <p className="font-black text-lg uppercase flex items-center justify-center gap-2">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                            BOOKING EXPIRED
                        </p>
                        <p className="text-xs font-medium mt-1">The race has already started (or is about to start). Payment cannot be accepted.</p>
                    </div>
                )}

                <div className="text-sm space-y-1 mb-3">
                    <p className="flex justify-between"><span>Customer:</span> <span className="font-bold">{foundTicket.vendorName}</span></p>
                    <p className="flex justify-between"><span>Booked At:</span> <span className="font-mono">{foundTicket.timestamp.toLocaleTimeString()}</span></p>
                    <div className="flex justify-between items-center pt-2 border-t border-black/10 mt-2">
                        <span className="text-gray-600">Amount Due:</span>
                        <span className="font-black text-2xl text-betese-dark">{foundTicket.totalCost.toFixed(2)} GMD</span>
                    </div>
                </div>

                <div className="text-xs space-y-1 mb-4 max-h-24 overflow-y-auto bg-white/60 p-2 rounded">
                     {foundTicket.selections.map((sel, i) => (
                        <div key={i} className="border-b last:border-0 pb-1 mb-1 border-gray-200">
                            <span className="font-bold">{sel.raceName}</span>
                            <span className="block text-gray-600">{sel.betType}: {sel.xCount > 0 && `${'X '.repeat(sel.xCount)}`}{sel.numbers.join(', ')}</span>
                        </div>
                     ))}
                </div>

                 <div className="flex flex-col gap-3">
                    <button
                        onClick={handlePay}
                        disabled={expired}
                        className={`w-full px-4 py-3 text-white font-bold rounded-lg shadow-md flex justify-center items-center gap-2 transition-all ${
                            expired 
                            ? 'bg-gray-400 cursor-not-allowed opacity-70' 
                            : 'bg-betese-green hover:bg-green-700 transform active:scale-95'
                        }`}
                    >
                        {expired ? (
                            <>⛔ CANNOT PAY (RACE STARTED)</>
                        ) : (
                            <>
                                <span className="text-xl">💵</span> CONFIRM PAYMENT & PRINT
                            </>
                        )}
                    </button>

                    <button
                        onClick={() => onPrintBookingSlip(foundTicket)}
                        className="w-full px-4 py-2 bg-blue-600 text-white font-semibold rounded-lg hover:bg-blue-700 text-xs"
                    >
                        Re-Print Booking Slip (Not Valid for Bet)
                    </button>
                 </div>
            </div>
        )}
      </div>
    </div>
  );
};

