                                {selectedRace && (
                                    <>
                                    <div className="mb-6">
                                        <h3 className="text-lg font-semibold mb-2">2. Select Bet Type</h3>
                                        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-3">
                                            {availableBetTypes.map((betType) => {
                                                const isDisabled = selectedRace.disabledBetTypes?.includes(betType);
                                                return (
                                                    <button
                                                        key={betType}
                                                        onClick={() => handleSelectBetType(betType)}
                                                        disabled={isDisabled}
                                                        className={`relative p-3 text-center rounded-lg text-sm font-semibold transition-all flex flex-col items-center justify-center h-24 gap-1 ${
                                                            isDisabled 
                                                                ? 'bg-gray-300 text-gray-400 cursor-not-allowed line-through' 
                                                                : (selectedBetType === betType ? 'bg-yellow-400 text-betese-dark ring-2 ring-betese-green shadow-lg' : 'bg-gray-100 text-gray-800 hover:bg-yellow-200 shadow')
                                                        }`}
                                                    >
                                                        <span className="text-3xl"><Icon name={betType} /></span>
                                                        <span className="text-sm font-bold leading-tight">{betType}</span>
                                                        {isDisabled && <span className="absolute top-1 right-1 text-red-600 font-black text-lg">X</span>}
                                                    </button>
                                                );
                                            })}
                                        </div>
                                    </div>

                                    {selectedBetType && (
                                        <HorseSelector
                                            race={selectedRace}
                                            betType={selectedBetType}
                                            selectedNumbers={selectedNumbers}
                                            xCount={xCount}
                                            onNumberSelect={setSelectedNumbers}
                                            onXSelect={setXCount}
                                            onPatternChange={setPattern}
                                            disabled={isRaceClosed}
                                        />
                                    )}
                                    </>
                                )}

                                <div className="mt-6 flex justify-end">
                                    <button
                                        onClick={handleAddBet}
                                        disabled={!selectedRace || !selectedBetType || selectedNumbers.length + xCount === 0 || isRaceClosed}
                                        className="px-6 py-3 bg-betese-green text-white font-bold rounded-lg hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed"
                                    >
                                        Add to Bet Slip
                                    </button>
                                </div>
                            </div>
                        </div>

                        <div className="lg:col-span-1">
                            <BetSlipPanel
                                betSlip={betSlip}
                                onClear={onClearBetSlip}
                                onInitiatePlaceBet={onInitiatePlaceBet}
                                onRemove={onRemoveSelection}
                                onUpdateSelectionMultiplier={onUpdateSelectionMultiplier}
                            />
                        </div>
                    </div>
                );
            case 'ONLINE':
                return (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        <AppQRCodePanel />
                        {/* UPDATE: Pass races and effectiveTime to enable expiration check */}
                        <BookingRetrievalPanel 
                            allTickets={allTickets} 
                            onPayForBooking={onPayForBooking} 
                            onPrintBookingSlip={setBookingSlipToPrint}
                            races={races}
                            effectiveTime={effectiveTime} 
                        />
                        <ProcessWithdrawalPanel withdrawalRequests={props.withdrawalRequests} onProcessWithdrawal={props.onProcessWithdrawal} customers={customers} />
                        <CustomerDepositPanel 
                            customers={customers} 
                            onDeposit={onDeposit} 
                            depositLogs={depositLogs} 
                            depositRequests={props.depositRequests}
                            onApproveDepositRequest={props.onApproveDepositRequest}
                            onRejectDepositRequest={props.onRejectDepositRequest}
                            currentUserRole={currentUser.role}
                        />
                    </div>
                );
            case 'SALES_REPORT':
                return <SalesReportView vendorTickets={placedTickets} effectiveTime={effectiveTime} vendorName={currentUser.name} />;
            case 'PAYOUT_REPORTS':
                return <PayoutReportView races={races} onPrintRequest={setRapportModalRace} effectiveTime={effectiveTime} />;
            case 'TICKET_TOOLS':
                return (
                    <div className="space-y-6">
                        <TicketToolsView allTickets={allTickets} onCancelTicket={props.onCancelTicket} races={races} onPayoutTicket={props.onPayoutTicket} effectiveTime={effectiveTime} onReprintTicket={props.onReprintTicket} currentUser={currentUser} />
                    </div>
                );
            case 'SCAN':
                return (
                    <div className="bg-white p-6 rounded-lg shadow-lg text-center">
                        <h2 className="text-2xl font-bold text-betese-dark mb-4">Scan Ticket QR Code</h2>
                        <div className="bg-gray-100 p-10 rounded-lg border-2 border-dashed border-gray-400">
                            <p className="text-gray-500 mb-4">Camera scanning feature is currently in development.</p>
                            <button className="px-6 py-3 bg-blue-600 text-white font-bold rounded-lg hover:bg-blue-700">Activate Camera</button>
                        </div>
                    </div>
                );
            case 'RESULT_UPDATE':
                return <ResultUpdatePanel races={races} onPrintRequest={setRapportModalRace} effectiveTime={effectiveTime} />;
            case 'DASHBOARD':
            default:
                return <VendorDashboardView setView={setView} messages={messages} threads={threads} onOpenChat={onOpenChat} />;
        }
    };

    return (
        <div className="space-y-6">
            {view !== 'DASHBOARD' && <BackButton onClick={() => setView('DASHBOARD')} />}

            {lastTicket && (
                <TicketModal 
                    ticket={lastTicket} 
                    onClose={onCloseTicket} 
                    showPrintButton={true} 
                    races={races} 
                />
            )}

            {rapportModalRace && <RapportModal race={rapportModalRace} onClose={() => setRapportModalRace(null)} showPrintButton={true} />}
            {bookingSlipToPrint && <BookingCodeModal ticket={bookingSlipToPrint} onClose={() => setBookingSlipToPrint(null)} />}
            {renderView()}
        </div>
    );
};

import React, { useState, useCallback, useEffect } from 'react';
import { BetSlip, BetTypeOption, Ticket, BetSelection, User, Role, WithdrawalRequest, Race, RaceResult, DepositLog, ChatMessage, ChatThread, Promotion, PromotionRule, DepositRequest, PaymentIntegrationConfig, ProgramImage } from './types';
import { BET_PRICING, MOCK_RACES, MOCK_USERS, MOCK_PROMOTIONS, MOCK_CHAT_THREADS, MOCK_CHAT_MESSAGES } from './constants';
import { LoginScreen } from './components/LoginScreen';
import { BettingTerminal } from './components/BettingTerminal';
import { Header } from './components/Header';
import { AdminDashboard } from './components/AdminDashboard';
import { SupervisorDashboard } from './components/SupervisorDashboard';
import { CustomerDashboard } from './components/CustomerDashboard';
import { ConfirmationModal } from './components/ConfirmationModal';
import { BookingCodeModal } from './components/BookingCodeModal';
import { WithdrawalCodeModal } from './components/WithdrawalCodeModal';
import { TicketModal } from './components/TicketModal';
import { ChatPanel, BroadcastNotificationModal } from './components/ChatSystem';
import { calculateTicketWinnings, BETTING_CUTOFF_MS } from './utils';
import { TestingPanel } from './components/TestingPanel';
import { LanguageProvider } from './LanguageContext';
import { supabase } from './supabaseClient';

// --- Data Persistence Hooks ---

function useRehydratedState<T>(key: string, defaultValue: T, rehydrator: (data: any) => T): [T, React.Dispatch<React.SetStateAction<T>>] {
  const [state, setState] = useState<T>(() => {
    try {
      const storedValue = localStorage.getItem(key);
      if (storedValue) {
        const parsedData = JSON.parse(storedValue);
        const rehydratedData = rehydrator(parsedData);

        // Special handling for stale race data
        if (key === 'betese-races' && Array.isArray(rehydratedData)) {
            const allRacesPast = rehydratedData.length > 0 && rehydratedData.every((race: Race) => new Date(race.endDate) < new Date());
            if (allRacesPast) {
                localStorage.setItem(key, JSON.stringify(defaultValue));
                return rehydrator(defaultValue);
            }
        }

        return rehydratedData;
      }
      localStorage.setItem(key, JSON.stringify(defaultValue));
      return defaultValue;
    } catch (e) {
      console.error(`Failed to parse or rehydrate ${key}`, e);
      return defaultValue;
    }
  });

  useEffect(() => {
    try {
      localStorage.setItem(key, JSON.stringify(state));
    } catch (e) {
      console.error(`Failed to save state for ${key}`, e);
    }
  }, [key, state]);

  return [state, setState];
}

function useRehydratedSetState(key: string, defaultValue: Set<string>): [Set<string>, React.Dispatch<React.SetStateAction<Set<string>>>] {
    const [state, setState] = useState<Set<string>>(() => {
        try {
            const storedValue = localStorage.getItem(key);
            if (storedValue) {
                return new Set(JSON.parse(storedValue));
            }
            localStorage.setItem(key, JSON.stringify(Array.from(defaultValue)));
            return defaultValue;
        } catch (e) { 
            return defaultValue; 
        }
    });

    useEffect(() => {
        localStorage.setItem(key, JSON.stringify(Array.from(state)));
    }, [key, state]);

    return [state, setState];
}

const rehydrateRaces = (data: any[]): Race[] => data.map(r => ({ ...r, startDate: new Date(r.startDate), endDate: new Date(r.endDate), result: r.result ? { ...r.result, payouts: r.result.payouts || {} } : undefined }));
const rehydrateTickets = (data: any[]): Ticket[] => data.map(t => ({ ...t, timestamp: new Date(t.timestamp), paidAt: t.paidAt ? new Date(t.paidAt) : undefined, canceledAt: t.canceledAt ? new Date(t.canceledAt) : undefined }));
const rehydrateWithdrawals = (data: any[]): WithdrawalRequest[] => data.map(w => ({ ...w, requestedAt: new Date(w.requestedAt), completedAt: w.completedAt ? new Date(w.completedAt) : undefined }));
const rehydrateDeposits = (data: any[]): DepositLog[] => data.map(d => ({ ...d, timestamp: new Date(d.timestamp) }));
const rehydrateDepositRequests = (data: any[]): DepositRequest[] => data.map(d => ({ ...d, timestamp: new Date(d.timestamp), processedAt: d.processedAt ? new Date(d.processedAt) : undefined }));
const rehydrateMessages = (data: any[]): ChatMessage[] => data.map(m => ({ ...m, timestamp: new Date(m.timestamp) }));
const rehydrateThreads = (data: any[]): ChatThread[] => data.map(t => ({ ...t, lastMessageTimestamp: t.lastMessageTimestamp ? new Date(t.lastMessageTimestamp) : undefined }));
const identity = (data: any) => data; 

const AppContent: React.FC = () => {
  // --- Persistent State ---
  const [currentUser, setCurrentUser] = useRehydratedState<User | null>('betese-currentUser', null, identity);
  const [users, setUsers] = useRehydratedState<User[]>('betese-users', MOCK_USERS, identity);
  const [races, setRaces] = useRehydratedState<Race[]>('betese-races', MOCK_RACES, rehydrateRaces);
  const [placedTickets, setPlacedTickets] = useRehydratedState<Ticket[]>('betese-tickets', [], rehydrateTickets);
  const [withdrawalRequests, setWithdrawalRequests] = useRehydratedState<WithdrawalRequest[]>('betese-withdrawals', [], rehydrateWithdrawals);
  const [depositLogs, setDepositLogs] = useRehydratedState<DepositLog[]>('betese-deposits', [], rehydrateDeposits);
  const [depositRequests, setDepositRequests] = useRehydratedState<DepositRequest[]>('betese-deposit-requests', [], rehydrateDepositRequests);
  const [programImages, setProgramImages] = useRehydratedState<ProgramImage[]>('betese-programImages', [], identity);
  const [promotions, setPromotions] = useRehydratedState<Promotion[]>('betese-promotions', MOCK_PROMOTIONS, identity);
  const [threads, setThreads] = useRehydratedState<ChatThread[]>('betese-threads', MOCK_CHAT_THREADS, rehydrateThreads);
  const [messages, setMessages] = useRehydratedState<ChatMessage[]>('betese-messages', MOCK_CHAT_MESSAGES, rehydrateMessages);
  const [seenWinningTickets, setSeenWinningTickets] = useRehydratedSetState('betese-seenTickets', new Set());
  const [isTestingMode, setIsTestingMode] = useRehydratedState<boolean>('betese-testingMode', false, identity);
  const [paymentConfigs, setPaymentConfigs] = useRehydratedState<PaymentIntegrationConfig[]>('betese-payment-configs', [], identity);

  // --- Transient (UI) State ---
  const [betSlip, setBetSlip] = useState<BetSlip>({ selections: [], totalCost: 0 });
  const [lastTicket, setLastTicket] = useState<Ticket | null>(null);
  const [paidTicketModal, setPaidTicketModal] = useState<Ticket | null>(null);
  const [ticketToReprint, setTicketToReprint] = useState<Ticket | null>(null);
  const [lastBooking, setLastBooking] = useState<Ticket | null>(null);
  const [lastWithdrawal, setLastWithdrawal] = useState<WithdrawalRequest | null>(null);
  const [walletFlash, setWalletFlash] = useState(false);
  const [confirmationModal, setConfirmationModal] = useState<{
    isOpen: boolean;
    title: string;
    content: React.ReactNode;
    onConfirm: () => void;
  } | null>(null);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [broadcastNotification, setBroadcastNotification] = useState<ChatMessage | null>(null);
  const [effectiveTime, setEffectiveTime] = useState(new Date());

  useEffect(() => {
    if (isTestingMode) return;
    const interval = setInterval(() => {
      setEffectiveTime(new Date());
    }, 1000);
    return () => clearInterval(interval);
  }, [isTestingMode]);

  const handleTimeJump = (minutes: number) => {
    if (!isTestingMode) return;
    setEffectiveTime(prevTime => new Date(prevTime.getTime() + minutes * 60 * 1000));
  };

  const handleResetData = () => {
    const keysToRemove = [
      'betese-currentUser', 'betese-users', 'betese-races', 'betese-tickets',
      'betese-withdrawals', 'betese-deposits', 'betese-programImages', 'betese-promotions',
      'betese-threads', 'betese-messages', 'betese-seenTickets', 'betese-testingMode', 'betese-deposit-requests',
      'betese-payment-configs'
    ];
    keysToRemove.forEach(key => localStorage.removeItem(key));
    window.location.reload();
  };

  // --- OPTIMIZED TICKET PROCESSING (ANTI-FREEZE) ---
  useEffect(() => {
    // 1. Identify only tickets that NEED processing (Active)
    // This ignores thousands of historical Paid/Lost tickets, preventing the freeze.
    const activeTickets = placedTickets.filter(t => t.status === 'Active');

    if (activeTickets.length === 0) return;

    const updates = new Map<string, Ticket>();
    const userBalanceUpdates = new Map<string, number>();
    let hasChanges = false;

    activeTickets.forEach(ticket => {
        // Check if all races in the ticket have results
        const allRacesResulted = ticket.selections.every(selection => {
            const race = races.find(r => r.id === selection.raceId);
            return !!race?.result;
        });

        if (allRacesResulted) {
            const { totalWinnings, breakdown } = calculateTicketWinnings(ticket, races);
            const newStatus = totalWinnings > 0 ? 'Winning' : 'Lost';

            const updatedTicket: Ticket = {
                ...ticket,
                status: newStatus,
                winnings: totalWinnings,
                winningsBreakdown: breakdown
            };

            updates.set(ticket.id, updatedTicket);
            hasChanges = true;

            // Prepare customer balance update if applicable
            if (updatedTicket.customerId && updatedTicket.status === 'Winning') {
                const currentBalance = userBalanceUpdates.get(updatedTicket.customerId) || 0;
                userBalanceUpdates.set(updatedTicket.customerId, currentBalance + totalWinnings);
            }
        }
    });

    if (hasChanges) {
        // Batch update tickets
        setPlacedTickets(prev => prev.map(t => updates.get(t.id) || t));

        // Batch update users
        if (userBalanceUpdates.size > 0) {
            setUsers(prevUsers => prevUsers.map(user => {
                const bonus = userBalanceUpdates.get(user.id);
                if (bonus) {
                    return { ...user, walletBalance: (user.walletBalance ?? 0) + bonus };
                }
                return user;
            }));

            // Sync current user if affected
            if (currentUser && userBalanceUpdates.has(currentUser.id)) {
                setCurrentUser(prev => prev ? { ...prev, walletBalance: (prev.walletBalance ?? 0) + (userBalanceUpdates.get(prev.id) || 0) } : null);
            }
        }
    }
  }, [races, placedTickets, currentUser, setCurrentUser, setUsers]);


  const calculateCost = useCallback((betType: BetTypeOption, numbers: number[], xCount: number): number => {
    const pricing = BET_PRICING[betType];
    if (!pricing) return 0;
    if (pricing.perHorsePrice) return (numbers.length + xCount) * pricing.perHorsePrice;
    if (xCount > 0) {
      const xPrices = pricing.xPriceMap?.[xCount];
      return xPrices?.[numbers.length] ?? 0;
    }
    return pricing.priceMap[numbers.length] ?? 0;
  }, []);

  const updateBetSlip = (newSelection: Omit<BetSelection, 'cost' | 'multiplier'>) => {
    const costOfNewSelection = calculateCost(newSelection.betType, newSelection.numbers, newSelection.xCount);
    setBetSlip(prevSlip => {
      const updatedSelection: BetSelection = { ...newSelection, cost: costOfNewSelection, multiplier: 1 };
      const newSelections = [...prevSlip.selections, updatedSelection];
      const totalCost = newSelections.reduce((sum, s) => sum + (s.cost * s.multiplier), 0);
      return { selections: newSelections, totalCost };
    });
  };

  const removeSelection = (index: number) => {
    setBetSlip(prevSlip => {
        const newSelections = prevSlip.selections.filter((_, i) => i !== index);
        const totalCost = newSelections.reduce((sum, s) => sum + (s.cost * s.multiplier), 0);
        return { selections: newSelections, totalCost };
    });
  };

  const updateSelectionMultiplier = (selectionIndex: number, newMultiplier: number) => {
    const safeMultiplier = Math.max(1, isNaN(newMultiplier) ? 1 : newMultiplier);
    const newSelections = [...betSlip.selections];
    if (!newSelections[selectionIndex]) return;
    newSelections[selectionIndex] = { ...newSelections[selectionIndex], multiplier: safeMultiplier };
    const newTotalCost = newSelections.reduce((sum, s) => sum + (s.cost * s.multiplier), 0);
    setBetSlip({ selections: newSelections, totalCost: newTotalCost });
  };

  const clearBetSlip = () => setBetSlip({ selections: [], totalCost: 0 });

  const placeBet = () => {
    if (!currentUser || betSlip.selections.length === 0) return;

    const now = effectiveTime.getTime();
    const lateSelections = betSlip.selections.filter(selection => {
        const race = races.find(r => r.id === selection.raceId);
        if (!race) return true;
        return (race.endDate.getTime() - now) <= BETTING_CUTOFF_MS;
    });

    if (lateSelections.length > 0) {
        setConfirmationModal(null);
        alert(`FAILED: Betting has closed for one or more selected races.`);
        return;
    }

    if(currentUser.role === 'Customer') {
      const totalBalance = (currentUser.walletBalance ?? 0) + (currentUser.bonusBalance ?? 0);
      if (totalBalance < betSlip.totalCost) {
        setWalletFlash(true);
        return;
      }

      let remainingCost = betSlip.totalCost;
      const walletAmount = currentUser.walletBalance ?? 0;
      const bonusAmount = currentUser.bonusBalance ?? 0;
      const walletToUse = Math.min(remainingCost, walletAmount);
      const newWalletBalance = walletAmount - walletToUse;
      remainingCost -= walletToUse;
      const bonusToUse = Math.min(remainingCost, bonusAmount);
      const newBonusBalance = bonusAmount - bonusToUse;

      const updatedUser = { ...currentUser, walletBalance: newWalletBalance, bonusBalance: newBonusBalance };
      setCurrentUser(updatedUser);
      setUsers(users.map(u => u.id === currentUser.id ? updatedUser : u));
    }

    const newTicket: Ticket = {
      id: Math.floor(10000000 + Math.random() * 90000000).toString(),
      timestamp: effectiveTime,
      vendorId: currentUser.role === 'Vendor' ? currentUser.id : '',
      vendorName: currentUser.name,
      status: 'Active',
      customerId: currentUser.role === 'Customer' ? currentUser.id : undefined,
      ...betSlip
    };

    setPlacedTickets(prevTickets => [...prevTickets, newTicket]);
    setLastTicket(newTicket);
    clearBetSlip();
  };

  const initiatePlaceBet = () => {
    const now = effectiveTime.getTime();
    const hasRaceEnded = betSlip.selections.some(selection => {
        const race = races.find(r => r.id === selection.raceId);
        return !race || (race.endDate.getTime() - now) <= BETTING_CUTOFF_MS;
    });

    if (hasRaceEnded) {
        alert('Betting has closed for one or more selected races.');
        return;
    }

    setConfirmationModal({
      isOpen: true,
      title: "Confirm Bet",
      content: (
        <div>
          <p>Are you sure you want to place this bet?</p>
          <p className="font-bold text-lg mt-2">Total Cost: {betSlip.totalCost.toFixed(2)} GMD</p>
        </div>
      ),
      onConfirm: placeBet
    });
  }

  const bookBet = () => {
    if (!currentUser || betSlip.selections.length === 0) return;
    const now = effectiveTime.getTime();
    const lateSelections = betSlip.selections.filter(selection => {
        const race = races.find(r => r.id === selection.raceId);
        return !race || (race.endDate.getTime() - now) <= BETTING_CUTOFF_MS;
    });

    if (lateSelections.length > 0) {
        setConfirmationModal(null); 
        alert(`FAILED: Booking closed for one or more selected races.`);
        return;
    }

    const newBooking: Ticket = {
      id: `BOOK-${Math.random().toString(36).substring(2, 8).toUpperCase()}`,
      bookingCode: Math.random().toString(36).substring(2, 7).toUpperCase(),
      timestamp: effectiveTime,
      vendorId: '',
      vendorName: currentUser.name,
      customerId: currentUser.id,
      status: 'Booked',
      ...betSlip
    };

    setPlacedTickets(prev => [...prev, newBooking]);
    setLastBooking(newBooking);
    clearBetSlip();
  };

  const initiateBookBet = () => {
     const now = effectiveTime.getTime();
     const hasRaceEnded = betSlip.selections.some(selection => {
         const race = races.find(r => r.id === selection.raceId);
         return !race || (race.endDate.getTime() - now) <= BETTING_CUTOFF_MS;
     });

     if (hasRaceEnded) {
         alert('Betting has closed. You cannot book this bet.');
         return;
     }

     setConfirmationModal({
      isOpen: true,
      title: "Confirm Booking",
      content: (
        <div>
          <p>This will generate a booking code. You can pay for this bet at any vendor shop using Cash.</p>
           <p className="font-bold text-lg mt-2">Total Cost: {betSlip.totalCost.toFixed(2)} GMD</p>
        </div>
      ),
      onConfirm: bookBet
    });
  }

  const handleLogin = (user: User) => setCurrentUser(user);
  const handleLogout = () => setCurrentUser(null);

  const handleSignUp = (name: string, role: Role, phone?: string, password?: string): User => {
    return addUser(name, role, phone, password, { id: 'SYSTEM', name: 'SignUp', role: 'Admin', isLocked: false });
  };

  const addUser = (name: string, role: Role, phone?: string, password?: string, creator?: User): User => {
    const creatorUser = creator || currentUser;
    if (!creatorUser) throw new Error("A user must be logged in to create new users.");

    const userId = (role === 'Customer' && phone) 
        ? phone 
        : `${role.toUpperCase().slice(0, 4)}-${name.replace(/\s+/g, '-').toUpperCase()}-${Math.random().toString(36).substring(2, 6)}`;

    const newUser: User = {
      id: userId,
      name: name,
      role: role,
      isLocked: false,
      password: password,
      phone: phone,
      walletBalance: role === 'Customer' ? 0 : undefined,
      bonusBalance: role === 'Customer' ? 0 : undefined,
      createdById: creatorUser.id,
      createdByName: creatorUser.name,
    };

    setUsers(prevUsers => [...prevUsers, newUser]);
    if(supabase) supabase.from('users').insert(newUser).then(({ error }) => { if(error) console.error("Sync error", error); });
    return newUser;
  };

  const toggleLock = (userId: string) => setUsers(users.map(u => u.id === userId ? { ...u, isLocked: !u.isLocked } : u));

  const lockAllVendors = () => {
      setUsers(users.map(u => u.role === 'Vendor' ? { ...u, isLocked: true } : u));
      alert("All vendor accounts have been locked.");
  }

  const cancelTicket = (ticketId: string) => {
    if (!currentUser) return;
    setPlacedTickets(prev => prev.map(t => t.id === ticketId ? { ...t, status: 'Canceled', canceledById: currentUser.id, canceledByName: currentUser.name } : t));
  };

  const handleDeposit = (customerId: string, amount: number, method: 'Cash' | 'Wave' | 'AfriMoney' | 'Correction' = 'Cash', transactionId?: string): { success: boolean, bonusApplied: number | null } => {
    if (!currentUser) return { success: false, bonusApplied: null };
    const userToUpdate = users.find(u => u.id === customerId);
    if (!userToUpdate) return { success: false, bonusApplied: null };

    if (amount < 0 && (userToUpdate.walletBalance ?? 0) + amount < 0) {
        alert("Error: Insufficient balance for this debit.");
        return { success: false, bonusApplied: null };
    }

    let bonusApplied: number | null = null;
    if (amount > 0 && method !== 'Correction') {
        const customerDeposits = depositLogs.filter(d => d.customerId === customerId);
        const isFirstTimeDeposit = customerDeposits.length === 0;

        if (isFirstTimeDeposit) {
            const firstDepositPromo = promotions.find(p => p.type === 'first-deposit' && p.isActive);
            if (firstDepositPromo) {
                const applicableRule = firstDepositPromo.rules.filter(rule => amount >= rule.depositAmount).sort((a, b) => b.depositAmount - a.depositAmount)[0];
                if (applicableRule) bonusApplied = applicableRule.bonusAmount;
            }
        } else {
            const otherActivePromos = promotions.filter(p => p.isActive && p.type !== 'first-deposit');
            let maxPossibleBonus = 0;
            for (const promo of otherActivePromos) {
                const rule = promo.rules.filter(r => amount >= r.depositAmount).sort((a, b) => b.depositAmount - a.depositAmount)[0];
                if (rule && rule.bonusAmount > maxPossibleBonus) maxPossibleBonus = rule.bonusAmount;
            }
            if (maxPossibleBonus > 0) bonusApplied = maxPossibleBonus;
        }
    }

    const updatedCustomer: User = {
        ...userToUpdate,
        walletBalance: (userToUpdate.walletBalance ?? 0) + amount,
        bonusBalance: (userToUpdate.bonusBalance ?? 0) + (bonusApplied ?? 0)
    };

    setUsers(prevUsers => prevUsers.map(u => u.id === customerId ? updatedCustomer : u));
    if (currentUser.id === customerId) setCurrentUser(updatedCustomer);

    const newLog: DepositLog = {
      id: `dep-${Date.now()}`,
      customerId,
      customerName: updatedCustomer.name,
      customerPhone: updatedCustomer.phone,
      amount,
      bonusAwarded: bonusApplied ?? undefined,
      processedById: currentUser.id,
      processedByName: currentUser.name,
      timestamp: effectiveTime,
      method,
      transactionId,
    };
    setDepositLogs(prev => [...prev, newLog]);
    return { success: true, bonusApplied };
  };

  const handleCreateDepositRequest = (amount: number, method: 'Wave' | 'AfriMoney', transactionId: string) => {
      if (!currentUser || currentUser.role !== 'Customer') return;
      const newRequest: DepositRequest = {
          id: `dep-req-${Date.now()}`,
          customerId: currentUser.id,
          customerName: currentUser.name,
          amount,
          method,
          transactionId,
          status: 'Pending',
          timestamp: effectiveTime,
      };
      setDepositRequests(prev => [newRequest, ...prev]);
  };

  const handleApproveDepositRequest = (requestId: string) => {
      if (!currentUser) return;
      const request = depositRequests.find(r => r.id === requestId);
      if (!request || request.status !== 'Pending') return;
      handleDeposit(request.customerId, request.amount, request.method, request.transactionId);
      setDepositRequests(prev => prev.map(r => r.id === requestId ? { ...r, status: 'Approved', processedBy: currentUser.id, processedByName: currentUser.name, processedAt: effectiveTime } : r));
  };

  const handleRejectDepositRequest = (requestId: string) => {
      if (!currentUser) return;
      setDepositRequests(prev => prev.map(r => r.id === requestId ? { ...r, status: 'Rejected', processedBy: currentUser.id, processedByName: currentUser.name, processedAt: effectiveTime } : r));
  };

  const payForBooking = (bookingCode: string): { success: boolean; message: string } => {
    const ticketToActivate = placedTickets.find(t => t.bookingCode?.toUpperCase() === bookingCode.toUpperCase() && t.status === 'Booked');
    if (!ticketToActivate) return { success: false, message: 'Booking code not found or already processed.' };
    if (!currentUser) return { success: false, message: 'Current user not found.' };

    const now = effectiveTime.getTime();
    const hasRaceEnded = ticketToActivate.selections.some(selection => {
        const race = races.find(r => r.id === selection.raceId);
        return !race || (race.endDate.getTime() - now) <= BETTING_CUTOFF_MS;
    });

    if (hasRaceEnded) return { success: false, message: 'Event has already begun. Booked tickets must be paid before start time.' };

    const activatedTicket: Ticket = {
        ...ticketToActivate,
        status: 'Active',
        vendorId: currentUser.id,
        vendorName: currentUser.name,
        timestamp: effectiveTime,
    };

    setPlacedTickets(prevTickets => prevTickets.map(t => t.id === ticketToActivate.id ? activatedTicket : t));
    setPaidTicketModal(activatedTicket);
    return { success: true, message: 'Payment successful! Ticket is now active.' };
  };

  const processWithdrawal = (code: string): boolean => {
      if (!currentUser) return false;
      let success = false;
      let withdrawalAmount = 0;
      let customerId: string | undefined;

      setWithdrawalRequests(prev => prev.map(req => {
          if (req.code.toUpperCase() === code.toUpperCase() && req.status === 'Pending') {
              success = true;
              withdrawalAmount = req.amount;
              customerId = req.customerId;
              return { ...req, status: 'Completed', completedAt: effectiveTime, processedBy: currentUser.id, processedByName: currentUser.name };
          }
          return req;
      }));

      if (success && customerId) {
          setUsers(prev => prev.map(u => {
              if (u.id === customerId) {
                  const updatedUser = { ...u, walletBalance: (u.walletBalance ?? 0) - withdrawalAmount };
                   if(currentUser.id === customerId) setCurrentUser(updatedUser);
                  return updatedUser;
              }
              return u;
          }));
      }
      return success;
  };

  const handleWithdrawalRequest = (amount: number) => {
    if (!currentUser || currentUser.role !== 'Customer') return;
    const newRequest: WithdrawalRequest = {
      id: `wd-${Date.now()}`,
      code: Math.random().toString(36).substring(2, 8).toUpperCase(),
      customerId: currentUser.id,
      customerName: currentUser.name,
      amount: amount,
      status: 'Pending',
      requestedAt: effectiveTime,
    };
    setWithdrawalRequests(prev => [newRequest, ...prev]);
    setLastWithdrawal(newRequest);
  };

  const handleCancelWithdrawal = (requestId: string) => {
      if (!currentUser) return;
      const request = withdrawalRequests.find(r => r.id === requestId);
      if (request && request.status === 'Pending' && request.customerId === currentUser.id) {
          const updatedUser = { ...currentUser, walletBalance: (currentUser.walletBalance ?? 0) + request.amount };
          setCurrentUser(updatedUser);
          setUsers(users.map(u => u.id === currentUser.id ? updatedUser : u));
          setWithdrawalRequests(prev => prev.map(r => r.id === requestId ? { ...r, status: 'Canceled' } : r));
          alert("Withdrawal request canceled. Funds refunded.");
      }
  };

  const payoutTicket = (ticketId: string) => {
    if (!currentUser) return;
    setPlacedTickets(prev => prev.map(t => {
      if (t.id === ticketId && t.status === 'Winning') {
        const paidTicket = { ...t, status: 'Paid' as const, paidAt: effectiveTime, paidById: currentUser.id, paidByName: currentUser.name };
        setPaidTicketModal(paidTicket);
        return paidTicket;
      }
      return t;
    }));
  };

  const handleSaveRaceResult = (result: RaceResult) => {
    setRaces(prevRaces => prevRaces.map(r => r.id === result.raceId ? { ...r, result } : r));
  };

  const updateNonRunners = (raceId: string, nonRunners: number[]) => setRaces(races.map(r => r.id === raceId ? { ...r, nonRunners } : r));
  const addRace = (race: Race) => setRaces([...races, race]);
  const updateRace = (updatedRace: Race) => setRaces(races.map(r => r.id === updatedRace.id ? updatedRace : r));
  const deleteRace = (raceToDelete: Race) => setRaces(races.filter(r => r.id !== raceToDelete.id));

  const addProgramImage = (imageDataUrl: string, type: 'program' | 'advertisement', mediaType: 'image' | 'video' = 'image') => {
      const newImage: ProgramImage = { id: `img-${Date.now()}`, type, url: imageDataUrl, mediaType };
      setProgramImages(prev => [...prev, newImage]);
  };

  const deleteProgramImage = (id: string) => setProgramImages(prev => prev.filter(img => img.id !== id));

  const togglePromotionStatus = (promoId: string) => setPromotions(promos => promos.map(p => p.id === promoId ? { ...p, isActive: !p.isActive } : p));
  const updatePromotion = (promoId: string, newName: string, newRules: PromotionRule[]) => setPromotions(promos => promos.map(p => p.id === promoId ? { ...p, name: newName, rules: newRules } : p));

  const movePromotion = (id: string, direction: 'up' | 'down') => {
    setPromotions(prev => {
      const index = prev.findIndex(p => p.id === id);
      if (index === -1) return prev;
      const newPromos = [...prev];
      if (direction === 'up' && index > 0) [newPromos[index], newPromos[index - 1]] = [newPromos[index - 1], newPromos[index]];
      else if (direction === 'down' && index < newPromos.length - 1) [newPromos[index], newPromos[index + 1]] = [newPromos[index + 1], newPromos[index]];
      return newPromos;
    });
  };

  const createPromotion = (name: string, type: 'first-deposit' | 'weekly' | 'special') => {
      const newPromo: Promotion = { id: `promo-${Date.now()}`, name, type, isActive: false, rules: [] };
      setPromotions(prev => [...prev, newPromo]);
  };

  const deletePromotion = (id: string) => {
      if(confirm("Delete this promotion?")) setPromotions(prev => prev.filter(p => p.id !== id));
  };

  const adminResetPassword = (userId: string, newPass: string): { success: boolean, message: string } => {
      let userFound = false;
      setUsers(users.map(u => {
          if (u.id === userId) {
              userFound = true;
              return { ...u, password: newPass };
          }
          return u;
      }));
      return userFound ? { success: true, message: 'Password reset successfully!' } : { success: false, message: 'User not found.' };
  };

  const changePassword = (userId: string, oldPass: string, newPass: string): { success: boolean, message: string } => {
      const user = users.find(u => u.id === userId);
      if (!user) return { success: false, message: 'User not found.' };
      if (user.password !== oldPass) return { success: false, message: 'Incorrect current password.' };
      setUsers(users.map(u => u.id === userId ? { ...u, password: newPass } : u));
      if (currentUser?.id === userId) setCurrentUser(prev => prev ? { ...prev, password: newPass } : null);
      return { success: true, message: 'Password changed successfully!' };
  };

  const handleSendMessage = (threadId: string | 'new', content: string, recipients: string[], audioData?: { base64: string, duration: number }) => {
    if (!currentUser) return;
    let targetThreadId = threadId;

    if(threadId === 'new') {
        const existingThread = threads.find(t => t.participantIds.length === recipients.length + 1 && recipients.every(r => t.participantIds.includes(r)) && t.participantIds.includes(currentUser.id));
        if(existingThread) {
            targetThreadId = existingThread.id;
        } else {
            const newThread: ChatThread = { id: `thread-${Date.now()}`, participantIds: [...recipients, currentUser.id] };
            setThreads(prev => [...prev, newThread]);
            targetThreadId = newThread.id;
        }
    }

    const newMessage: ChatMessage = {
      id: `msg-${Date.now()}`,
      threadId: targetThreadId,
      senderId: currentUser.id,
      senderName: currentUser.name,
      content: content,
      timestamp: effectiveTime,
      readByIds: [currentUser.id],
      contentType: audioData ? 'audio' : 'text',
      audioBase64: audioData?.base64,
      audioDuration: audioData?.duration,
    };
    setMessages(prev => [...prev, newMessage]);
    setThreads(prev => prev.map(t => t.id === targetThreadId ? { ...t, lastMessageTimestamp: effectiveTime } : t));
  };

  const markThreadAsRead = (threadId: string) => {
      if(!currentUser) return;
      setMessages(prev => prev.map(msg => {
          if (msg.threadId === threadId && !msg.readByIds.includes(currentUser!.id)) return { ...msg, readByIds: [...msg.readByIds, currentUser!.id] };
          return msg;
      }));
  };

  const handleUpdatePaymentConfig = (newConfig: PaymentIntegrationConfig) => {
      setPaymentConfigs(prev => [...prev.filter(c => c.provider !== newConfig.provider), newConfig]);
  };

  useEffect(() => {
      if (!currentUser || currentUser.role === 'Customer') return;
      const broadcastThread = threads.find(t => t.isBroadcast);
      if (!broadcastThread) return;

      const latestBroadcast = messages.filter(m => m.threadId === broadcastThread.id).sort((a,b) => b.timestamp.getTime() - a.timestamp.getTime())[0];
      if (latestBroadcast && !latestBroadcast.readByIds.includes(currentUser.id) && latestBroadcast.senderId !== currentUser.id) {
          setBroadcastNotification(latestBroadcast);
      }
  }, [messages, threads, currentUser]);

  const pendingDepositCount = depositRequests.filter(r => r.status === 'Pending').length;

  if (!currentUser) {
    return <LoginScreen onLogin={handleLogin} users={users} onSignUp={handleSignUp} />;
  }

  const userTickets = placedTickets.filter(t => (currentUser.role === 'Vendor' && t.vendorId === currentUser.id) || (currentUser.role === 'Customer' && t.customerId === currentUser.id));

  return (
    <>
      <Header
        user={currentUser}
        onLogout={handleLogout}
        walletFlash={walletFlash}
        onWalletFlashComplete={() => setWalletFlash(false)}
        onOpenChat={() => setIsChatOpen(true)}
        messages={messages}
        threads={threads}
        isTestingMode={isTestingMode}
        onToggleTestingMode={(currentUser.role === 'Admin' || currentUser.role === 'Supervisor') ? () => setIsTestingMode(!isTestingMode) : undefined}
        pendingDepositCount={pendingDepositCount}
      />
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        {currentUser.role === 'Vendor' && (
          <BettingTerminal
            races={races}
            betSlip={betSlip}
            onUpdateBetSlip={updateBetSlip}
            onClearBetSlip={clearBetSlip}
            onInitiatePlaceBet={initiatePlaceBet}
            lastTicket={lastTicket}
            onCloseTicket={() => setLastTicket(null)}
            onRemoveSelection={removeSelection}
            onUpdateSelectionMultiplier={updateSelectionMultiplier}
            placedTickets={placedTickets.filter(t => t.vendorId === currentUser.id)}
            allTickets={placedTickets}
            onCancelTicket={cancelTicket}
            customers={users.filter(u => u.role === 'Customer')}
            onDeposit={handleDeposit}
            onPayForBooking={payForBooking}
            onProcessWithdrawal={processWithdrawal}
            depositLogs={depositLogs}
            onPayoutTicket={payoutTicket}
            messages={messages}
            threads={threads}
            onOpenChat={() => setIsChatOpen(true)}
            effectiveTime={effectiveTime}
            currentUser={currentUser}
            withdrawalRequests={withdrawalRequests}
            onReprintTicket={setTicketToReprint}
            depositRequests={depositRequests}
            onApproveDepositRequest={handleApproveDepositRequest}
            onRejectDepositRequest={handleRejectDepositRequest}
          />
        )}
        {currentUser.role === 'Admin' && (
            <AdminDashboard
                tickets={placedTickets.filter(t => t.vendorId === currentUser.id)}
                users={users}
                onToggleLock={toggleLock}
                onLockAllVendors={lockAllVendors}
                onAddUser={addUser}
                onDeposit={handleDeposit}
                races={races}
                onSaveRaceResult={handleSaveRaceResult}
                onAddRace={addRace}
                onUpdateNonRunners={updateNonRunners}
                depositLogs={depositLogs}
                onUpdateRace={updateRace}
                onDeleteRace={deleteRace}
                allTickets={placedTickets}
                onCancelTicket={cancelTicket}
                programImages={programImages}
                onAddProgramImage={addProgramImage}
                onDeleteProgramImage={deleteProgramImage}
                promotions={promotions}
                onTogglePromotionStatus={togglePromotionStatus}
                onUpdatePromotion={updatePromotion}
                onMovePromotion={movePromotion}
                onCreatePromotion={createPromotion}
                onDeletePromotion={deletePromotion}
                onAdminResetPassword={adminResetPassword}
                effectiveTime={effectiveTime}
                currentUser={currentUser}
                onPayoutTicket={payoutTicket}
                onReprintTicket={setTicketToReprint}
                depositRequests={depositRequests}
                onApproveDepositRequest={handleApproveDepositRequest}
                onRejectDepositRequest={handleRejectDepositRequest}
                paymentConfigs={paymentConfigs}
                onSavePaymentConfig={handleUpdatePaymentConfig}
            />
        )}
        {currentUser.role === 'Supervisor' && (
            <SupervisorDashboard
                tickets={placedTickets.filter(t => t.vendorId === currentUser.id)}
                users={users}
                onToggleLock={toggleLock}
                onAddUser={addUser}
                onDeposit={handleDeposit}
                races={races}
                onSaveRaceResult={handleSaveRaceResult}
                onUpdateNonRunners={updateNonRunners}
                depositLogs={depositLogs}
                onUpdateRace={updateRace}
                onDeleteRace={deleteRace}
                allTickets={placedTickets}
                onCancelTicket={cancelTicket}
                programImages={programImages}
                onAddProgramImage={addProgramImage}
                onDeleteProgramImage={deleteProgramImage}
                promotions={promotions}
                onTogglePromotionStatus={togglePromotionStatus}
                onUpdatePromotion={updatePromotion}
                onMovePromotion={movePromotion}
                onCreatePromotion={createPromotion}
                onDeletePromotion={deletePromotion}
                onAdminResetPassword={adminResetPassword}
                effectiveTime={effectiveTime}
                currentUser={currentUser}
                onPayoutTicket={payoutTicket}
                onReprintTicket={setTicketToReprint}
                depositRequests={depositRequests}
                onApproveDepositRequest={handleApproveDepositRequest}
                onRejectDepositRequest={handleRejectDepositRequest}
            />
        )}
        {currentUser.role === 'Customer' && (
          <CustomerDashboard
            user={currentUser}
            races={races}
            betSlip={betSlip}
            onUpdateBetSlip={updateBetSlip}
            onClearBetSlip={clearBetSlip}
            onInitiatePlaceBet={initiatePlaceBet}
            onInitiateBookBet={initiateBookBet}
            lastTicket={lastTicket}
            onCloseTicket={() => setLastTicket(null)}
            onRemoveSelection={removeSelection}
            onUpdateSelectionMultiplier={updateSelectionMultiplier}
            placedTickets={userTickets}
            onCancelTicket={cancelTicket}
            seenWinningTickets={seenWinningTickets}
            onMarkWinningTicketAsSeen={(ticketId) => setSeenWinningTickets(prev => new Set(prev).add(ticketId))}
            onWithdrawalRequest={handleWithdrawalRequest}
            withdrawalRequests={withdrawalRequests.filter(wr => wr.customerId === currentUser.id)}
            onWalletFlash={() => setWalletFlash(true)}
            programImages={programImages}
            promotions={promotions}
            onChangePassword={changePassword}
            effectiveTime={effectiveTime}
            onDepositRequest={handleCreateDepositRequest}
            depositRequests={depositRequests.filter(dr => dr.customerId === currentUser.id)}
            onCancelWithdrawal={handleCancelWithdrawal}
          />
        )}
      </main>
      {confirmationModal?.isOpen && <ConfirmationModal {...confirmationModal} onClose={() => setConfirmationModal(null)} />}
      {lastBooking && <BookingCodeModal ticket={lastBooking} onClose={() => setLastBooking(null)} />}
      {lastWithdrawal && <WithdrawalCodeModal request={lastWithdrawal} onClose={() => setLastWithdrawal(null)} />}
      {paidTicketModal && <TicketModal ticket={paidTicketModal} onClose={() => setPaidTicketModal(null)} showPrintButton={true} races={races} />}
      {ticketToReprint && <TicketModal ticket={ticketToReprint} onClose={() => setTicketToReprint(null)} showPrintButton={true} races={races} />}
      <ChatPanel 
        isOpen={isChatOpen}
        onClose={() => setIsChatOpen(false)}
        currentUser={currentUser}
        users={users}
        threads={threads}
        messages={messages}
        onSendMessage={handleSendMessage}
        onMarkAsRead={markThreadAsRead}
      />
       {broadcastNotification && (
          <BroadcastNotificationModal 
            message={broadcastNotification} 
            onClose={() => {
              markThreadAsRead(broadcastNotification.threadId);
              setBroadcastNotification(null);
            }}
          />
       )}
       {isTestingMode && (currentUser.role === 'Admin' || currentUser.role === 'Supervisor') && (
        <TestingPanel 
            currentTime={effectiveTime}
            onTimeJump={handleTimeJump}
            onResetData={handleResetData}
        />
       )}
    </>
  );
};

const App: React.FC = () => {
  return (
    <LanguageProvider>
      <AppContent />
    </LanguageProvider>
  );
};

export default App;

import React, { useState } from 'react';
import { Ticket, Race } from '../types';
import { BETTING_CUTOFF_MS } from '../utils';

interface BookingRetrievalPanelProps {
  allTickets: Ticket[];
  onPayForBooking: (bookingCode: string) => { success: boolean; message: string };
  onPrintBookingSlip: (ticket: Ticket) => void;
  races: Race[];
  effectiveTime: Date;
}

export const BookingRetrievalPanel: React.FC<BookingRetrievalPanelProps> = ({ allTickets, onPayForBooking, onPrintBookingSlip, races, effectiveTime }) => {
  const [bookingCode, setBookingCode] = useState('');
  const [foundTicket, setFoundTicket] = useState<Ticket | null>(null);
  const [message, setMessage] = useState('');
  const [isSuccess, setIsSuccess] = useState(false);

  const handleFindBooking = () => {
    setMessage('');
    setFoundTicket(null);
    setIsSuccess(false);
    if (!bookingCode) {
        setMessage('Please enter a Booking Code.');
        return;
    }
    const ticket = allTickets.find(t => t.bookingCode?.toUpperCase() === bookingCode.toUpperCase() && t.status === 'Booked');
    if (ticket) {
        setFoundTicket(ticket);
    } else {
        setMessage('Booking code not found or has already been processed.');
    }
  };

  const handlePay = () => {
      if (!foundTicket?.bookingCode) return;

      const result = onPayForBooking(foundTicket.bookingCode);
      setMessage(result.message);
      setIsSuccess(result.success);

      if(result.success) {
          setFoundTicket(null);
          setBookingCode('');
      }
  }

  // Check if ticket is expired based on race time
  const isTicketExpired = () => {
      if (!foundTicket) return false;
      const now = effectiveTime.getTime();
      return foundTicket.selections.some(selection => {
          const race = races.find(r => r.id === selection.raceId);
          if (!race) return true; // Safety: if race not found, assume unpayable
          const timeRemaining = race.endDate.getTime() - now;
          return timeRemaining <= BETTING_CUTOFF_MS;
      });
  };

  const expired = isTicketExpired();

  return (
    <div className="bg-white p-6 rounded-lg shadow-lg border-2 border-transparent hover:border-blue-100 transition-colors">
      <h3 className="text-xl font-bold text-betese-dark mb-4">Retrieve & Pay Booking</h3>
      <div className="space-y-4">
        <div className="flex gap-2">
            <input
            type="text"
            value={bookingCode}
            onChange={(e) => setBookingCode(e.target.value)}
            placeholder="Enter Booking Code"
            className="flex-grow p-3 border-2 border-gray-300 rounded-lg uppercase font-bold text-lg tracking-widest focus:border-betese-green focus:ring-0"
            />
            <button
                onClick={handleFindBooking}
                className="px-6 py-2 bg-blue-600 text-white font-bold rounded-lg hover:bg-blue-700 shadow-md"
            >
                Find
            </button>
        </div>

        {message && <p className={`text-center text-sm p-3 font-bold rounded-md ${isSuccess ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>{message}</p>}

        {foundTicket && (
            <div className={`mt-4 p-4 rounded-lg border-2 shadow-sm ${expired ? 'bg-red-50 border-red-200' : 'bg-yellow-50 border-yellow-200'}`}>
                {expired && (
                    <div className="mb-4 p-3 bg-red-600 text-white rounded text-center shadow">
                        <p className="font-black text-lg uppercase flex items-center justify-center gap-2">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                            BOOKING EXPIRED
                        </p>
                        <p className="text-xs font-medium mt-1">The race has already started (or is about to start). Payment cannot be accepted.</p>
                    </div>
                )}

                <div className="text-sm space-y-1 mb-3">
                    <p className="flex justify-between"><span>Customer:</span> <span className="font-bold">{foundTicket.vendorName}</span></p>
                    <p className="flex justify-between"><span>Booked At:</span> <span className="font-mono">{foundTicket.timestamp.toLocaleTimeString()}</span></p>
                    <div className="flex justify-between items-center pt-2 border-t border-black/10 mt-2">
                        <span className="text-gray-600">Amount Due:</span>
                        <span className="font-black text-2xl text-betese-dark">{foundTicket.totalCost.toFixed(2)} GMD</span>
                    </div>
                </div>

                <div className="text-xs space-y-1 mb-4 max-h-24 overflow-y-auto bg-white/60 p-2 rounded">
                     {foundTicket.selections.map((sel, i) => (
                        <div key={i} className="border-b last:border-0 pb-1 mb-1 border-gray-200">
                            <span className="font-bold">{sel.raceName}</span>
                            <span className="block text-gray-600">{sel.betType}: {sel.xCount > 0 && `${'X '.repeat(sel.xCount)}`}{sel.numbers.join(', ')}</span>
                        </div>
                     ))}
                </div>

                 <div className="flex flex-col gap-3">
                    <button
                        onClick={handlePay}
                        disabled={expired}
                        className={`w-full px-4 py-3 text-white font-bold rounded-lg shadow-md flex justify-center items-center gap-2 transition-all ${
                            expired 
                            ? 'bg-gray-400 cursor-not-allowed opacity-70' 
                            : 'bg-betese-green hover:bg-green-700 transform active:scale-95'
                        }`}
                    >
                        {expired ? (
                            <>⛔ CANNOT PAY (RACE STARTED)</>
                        ) : (
                            <>
                                <span className="text-xl">💵</span> CONFIRM PAYMENT & PRINT
                            </>
                        )}
                    </button>

                    <button
                        onClick={() => onPrintBookingSlip(foundTicket)}
                        className="w-full px-4 py-2 bg-blue-600 text-white font-semibold rounded-lg hover:bg-blue-700 text-xs"
                    >
                        Re-Print Booking Slip (Not Valid for Bet)
                    </button>
                 </div>
            </div>
        )}
      </div>
    </div>
  );
};

