import { createClient } from '@supabase/supabase-js';
import { Ticket, User, Race, DepositLog } from './types';

// Safely retrieve environment variables
const getEnvVar = (key: string): string | undefined => {
  try {
    // @ts-ignore
    if (typeof import.meta !== 'undefined' && import.meta.env) {
      // @ts-ignore
      return import.meta.env[key];
    }
  } catch (e) { }
  return undefined;
};

const supabaseUrl = getEnvVar('VITE_SUPABASE_URL');
const supabaseAnonKey = getEnvVar('VITE_SUPABASE_ANON_KEY');

// Initialize Client
export const supabase = (supabaseUrl && supabaseAnonKey) 
  ? createClient(supabaseUrl, supabaseAnonKey) 
  : null;

// --- Helper Types for DB Mapping ---
// Maps camelCase (Frontend) to snake_case (DB) automatically if needed, 
// but here we manually handle the transformation to ensure safety.

export const checkBackendConnection = async () => {
    if (!supabase) return false;
    try {
        const { error } = await supabase.from('users').select('count', { count: 'exact', head: true });
        return !error;
    } catch (e) {
        return false;
    }
};

/**
 * Executes a secure bet placement transaction on the database.
 * This handles balance deduction and ticket creation atomically.
 */
export const dbPlaceBet = async (ticket: Ticket, user: User) => {
    if (!supabase) throw new Error("Supabase not connected");

    const isOnlineCustomer = user.role === 'Customer';

    // Call the Postgres RPC function defined in the SQL setup
    const { data, error } = await supabase.rpc('place_bet_transaction', {
        p_ticket_id: ticket.id,
        p_vendor_id: isOnlineCustomer ? null : user.id,
        p_vendor_name: user.name,
        p_customer_id: isOnlineCustomer ? user.id : null,
        p_total_cost: ticket.totalCost,
        p_selections: ticket.selections,
        p_status: ticket.status,
        p_booking_code: ticket.bookingCode || null
    });

    if (error) {
        console.error("Bet Transaction Error:", error);
        throw new Error(error.message);
    }
    return data;
};

/**
 * Syncs Users from DB
 */
export const dbFetchUsers = async (): Promise<User[]> => {
    if(!supabase) return [];
    const { data, error } = await supabase.from('users').select('*');
    if(error) { console.error(error); return []; }

    // Map DB snake_case to TS camelCase
    return data.map((u: any) => ({
        id: u.id,
        name: u.name,
        role: u.role,
        isLocked: u.is_locked,
        phone: u.phone,
        password: u.password,
        walletBalance: u.wallet_balance,
        bonusBalance: u.bonus_balance,
        createdById: u.created_by_id,
        createdByName: u.created_by_name
    }));
};

/**
 * Syncs Races from DB
 */
export const dbFetchRaces = async (): Promise<Race[]> => {
    if(!supabase) return [];
    const { data, error } = await supabase.from('races').select('*');
    if(error) { console.error(error); return []; }

    return data.map((r: any) => ({
        id: r.id,
        name: r.name,
        startDate: new Date(r.start_date),
        endDate: new Date(r.end_date),
        horseCount: r.horse_count,
        nonRunners: r.non_runners || [],
        result: r.result, // JSONB maps directly
        disabledBetTypes: r.disabled_bet_types || [],
        jackpot: r.jackpot
    }));
};

/**
 * Syncs Active/Recent Tickets
 * Optimization: Only fetch tickets from the last 7 days to prevent loading 100k+ old tickets
 */
export const dbFetchRecentTickets = async (): Promise<Ticket[]> => {
    if(!supabase) return [];

    const sevenDaysAgo = new Date();
    sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

    const { data, error } = await supabase
        .from('tickets')
        .select('*')
        .gte('timestamp', sevenDaysAgo.toISOString())
        .order('timestamp', { ascending: false });

    if(error) { console.error(error); return []; }

    return data.map((t: any) => ({
        id: t.id,
        timestamp: new Date(t.timestamp),
        vendorId: t.vendor_id,
        vendorName: t.vendor_name,
        status: t.status,
        customerId: t.customer_id,
        bookingCode: t.booking_code,
        selections: t.selections,
        totalCost: t.total_cost,
        winnings: t.winnings,
        winningsBreakdown: t.winnings_breakdown,
        paidAt: t.paid_at ? new Date(t.paid_at) : undefined,
        paidById: t.paid_by_id,
        paidByName: t.paid_by_name,
        canceledAt: t.canceled_at ? new Date(t.canceled_at) : undefined,
        canceledById: t.canceled_by_id,
        canceledByName: t.canceled_by_name
    }));
};

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { BetSlip, BetTypeOption, Ticket, BetSelection, User, Role, WithdrawalRequest, Race, RaceResult, DepositLog, ChatMessage, ChatThread, Promotion, PromotionRule, DepositRequest, PaymentIntegrationConfig, ProgramImage } from './types';
import { BET_PRICING, MOCK_USERS, MOCK_PROMOTIONS, MOCK_CHAT_THREADS, MOCK_CHAT_MESSAGES } from './constants';
import { LoginScreen } from './components/LoginScreen';
import { BettingTerminal } from './components/BettingTerminal';
import { Header } from './components/Header';
import { AdminDashboard } from './components/AdminDashboard';
import { SupervisorDashboard } from './components/SupervisorDashboard';
import { CustomerDashboard } from './components/CustomerDashboard';
import { ConfirmationModal } from './components/ConfirmationModal';
import { BookingCodeModal } from './components/BookingCodeModal';
import { WithdrawalCodeModal } from './components/WithdrawalCodeModal';
import { TicketModal } from './components/TicketModal';
import { ChatPanel, BroadcastNotificationModal } from './components/ChatSystem';
import { SEVEN_DAYS_IN_MS, calculateTicketWinnings, BETTING_CUTOFF_MS } from './utils';
import { TestingPanel } from './components/TestingPanel';
import { LanguageProvider } from './LanguageContext';
import { supabase, dbPlaceBet, dbFetchUsers, dbFetchRaces, dbFetchRecentTickets } from './supabaseClient';

const AppContent: React.FC = () => {
  // --- STATE MANAGEMENT ---
  // We utilize local state for the UI, but this state is constantly synced with Supabase
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [races, setRaces] = useState<Race[]>([]);
  const [placedTickets, setPlacedTickets] = useState<Ticket[]>([]);

  // Auxiliary State (Mocked/Local mostly, but could be synced)
  const [withdrawalRequests, setWithdrawalRequests] = useState<WithdrawalRequest[]>([]);
  const [depositLogs, setDepositLogs] = useState<DepositLog[]>([]);
  const [depositRequests, setDepositRequests] = useState<DepositRequest[]>([]);
  const [programImages, setProgramImages] = useState<ProgramImage[]>([]);
  const [promotions, setPromotions] = useState<Promotion[]>(MOCK_PROMOTIONS);
  const [threads, setThreads] = useState<ChatThread[]>(MOCK_CHAT_THREADS);
  const [messages, setMessages] = useState<ChatMessage[]>(MOCK_CHAT_MESSAGES);
  const [seenWinningTickets, setSeenWinningTickets] = useState<Set<string>>(new Set());
  const [paymentConfigs, setPaymentConfigs] = useState<PaymentIntegrationConfig[]>([]);

  // UI State
  const [betSlip, setBetSlip] = useState<BetSlip>({ selections: [], totalCost: 0 });
  const [lastTicket, setLastTicket] = useState<Ticket | null>(null);
  const [paidTicketModal, setPaidTicketModal] = useState<Ticket | null>(null);
  const [ticketToReprint, setTicketToReprint] = useState<Ticket | null>(null);
  const [lastBooking, setLastBooking] = useState<Ticket | null>(null);
  const [lastWithdrawal, setLastWithdrawal] = useState<WithdrawalRequest | null>(null);
  const [walletFlash, setWalletFlash] = useState(false);
  const [confirmationModal, setConfirmationModal] = useState<{ isOpen: boolean; title: string; content: React.ReactNode; onConfirm: () => void; } | null>(null);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [broadcastNotification, setBroadcastNotification] = useState<ChatMessage | null>(null);
  const [isTestingMode, setIsTestingMode] = useState(false);
  const [effectiveTime, setEffectiveTime] = useState(new Date());

  // --- SUPABASE SYNCHRONIZATION ---
  // This is the heart of the "Perfect Sync" logic.

  const loadInitialData = async () => {
      if (!supabase) {
          // Fallback to MOCK data if no Supabase connection
          setUsers(MOCK_USERS);
          return;
      }

      try {
          const [fetchedUsers, fetchedRaces, fetchedTickets] = await Promise.all([
              dbFetchUsers(),
              dbFetchRaces(),
              dbFetchRecentTickets()
          ]);

          if(fetchedUsers.length > 0) setUsers(fetchedUsers);
          if(fetchedRaces.length > 0) setRaces(fetchedRaces);
          if(fetchedTickets.length > 0) setPlacedTickets(fetchedTickets);

      } catch (err) {
          console.error("Data Sync Error:", err);
      }
  };

  useEffect(() => {
      loadInitialData();

      if (!supabase) return;

      // 1. Subscribe to USERS (Balance updates, locks)
      const userSub = supabase.channel('public:users')
          .on('postgres_changes', { event: '*', schema: 'public', table: 'users' }, async (payload) => {
              // Refresh users on any change to ensure balance accuracy
              const updatedUsers = await dbFetchUsers();
              setUsers(updatedUsers);

              // Update current user session if it's them
              if (currentUser && payload.new && (payload.new as any).id === currentUser.id) {
                  const updatedMe = updatedUsers.find(u => u.id === currentUser.id);
                  if (updatedMe) setCurrentUser(updatedMe);
              }
          })
          .subscribe();

      // 2. Subscribe to TICKETS (New sales, payouts)
      const ticketSub = supabase.channel('public:tickets')
          .on('postgres_changes', { event: '*', schema: 'public', table: 'tickets' }, async () => {
              // Re-fetch recent tickets to keep list in sync
              const updatedTickets = await dbFetchRecentTickets();
              setPlacedTickets(updatedTickets);
          })
          .subscribe();

      // 3. Subscribe to RACES (Results, status)
      const raceSub = supabase.channel('public:races')
          .on('postgres_changes', { event: '*', schema: 'public', table: 'races' }, async () => {
              const updatedRaces = await dbFetchRaces();
              setRaces(updatedRaces);
          })
          .subscribe();

      return () => {
          supabase?.removeChannel(userSub);
          supabase?.removeChannel(ticketSub);
          supabase?.removeChannel(raceSub);
      };
  }, [currentUser?.id]); // Re-run if user changes slightly, but mostly stable

  // Timer
  useEffect(() => {
    if (isTestingMode) return;
    const interval = setInterval(() => setEffectiveTime(new Date()), 1000);
    return () => clearInterval(interval);
  }, [isTestingMode]);

  // --- ACTIONS ---

  const calculateCost = useCallback((betType: BetTypeOption, numbers: number[], xCount: number): number => {
    const pricing = BET_PRICING[betType];
    if (!pricing) return 0;
    if (pricing.perHorsePrice) return (numbers.length + xCount) * pricing.perHorsePrice;
    if (xCount > 0) return pricing.xPriceMap?.[xCount]?.[numbers.length] ?? 0;
    return pricing.priceMap[numbers.length] ?? 0;
  }, []);

  const updateBetSlip = (newSelection: Omit<BetSelection, 'cost' | 'multiplier'>) => {
    const costOfNewSelection = calculateCost(newSelection.betType, newSelection.numbers, newSelection.xCount);
    setBetSlip(prev => {
      const updated = { ...newSelection, cost: costOfNewSelection, multiplier: 1 };
      const newSelections = [...prev.selections, updated];
      const totalCost = newSelections.reduce((sum, s) => sum + (s.cost * s.multiplier), 0);
      return { selections: newSelections, totalCost };
    });
  };

  const placeBet = async () => {
    if (!currentUser || betSlip.selections.length === 0) return;

    // Security Cutoff
    const now = effectiveTime.getTime();
    const lateSelections = betSlip.selections.filter(selection => {
        const race = races.find(r => r.id === selection.raceId);
        if (!race) return true;
        return (race.endDate.getTime() - now) <= BETTING_CUTOFF_MS;
    });

    if (lateSelections.length > 0) {
        setConfirmationModal(null);
        alert(`FAILED: Betting closed for one or more races.`);
        return;
    }

    // Construct Ticket Object
    const newTicket: Ticket = {
      id: Math.floor(10000000 + Math.random() * 90000000).toString(),
      timestamp: effectiveTime,
      vendorId: currentUser.role === 'Vendor' ? currentUser.id : '',
      vendorName: currentUser.name,
      status: 'Active',
      customerId: currentUser.role === 'Customer' ? currentUser.id : undefined,
      ...betSlip
    };

    try {
        if (supabase) {
            // DATABASE TRANSACTION
            await dbPlaceBet(newTicket, currentUser);
        } else {
            // LOCAL FALLBACK (Mock Mode)
            if (currentUser.role === 'Customer') {
                const bal = (currentUser.walletBalance || 0) + (currentUser.bonusBalance || 0);
                if (bal < newTicket.totalCost) { setWalletFlash(true); return; }

                // Simple local deduction logic for mock
                const updatedUser = { ...currentUser, walletBalance: (currentUser.walletBalance || 0) - newTicket.totalCost };
                setUsers(prev => prev.map(u => u.id === currentUser.id ? updatedUser : u));
                setCurrentUser(updatedUser);
            }
            setPlacedTickets(prev => [...prev, newTicket]);
        }

        setLastTicket(newTicket);
        clearBetSlip();

    } catch (e: any) {
        alert(`Transaction Failed: ${e.message}`);
    }
  };

  const initiatePlaceBet = () => {
      const now = effectiveTime.getTime();
      const hasRaceEnded = betSlip.selections.some(selection => {
          const race = races.find(r => r.id === selection.raceId);
          return !race || (race.endDate.getTime() - now) <= BETTING_CUTOFF_MS;
      });

      if (hasRaceEnded) {
          alert('Betting has closed for one or more selected races.');
          return;
      }

      setConfirmationModal({
        isOpen: true,
        title: "Confirm Bet",
        content: (
          <div>
            <p>Are you sure you want to place this bet?</p>
            <p className="font-bold text-lg mt-2">Total Cost: {betSlip.totalCost.toFixed(2)} GMD</p>
          </div>
        ),
        onConfirm: placeBet
      });
  };

  // --- Other Handlers (Simplified for brevity, assuming they follow similar sync patterns or will be migrated later) ---

  const clearBetSlip = () => setBetSlip({ selections: [], totalCost: 0 });
  const removeSelection = (index: number) => {
      setBetSlip(prev => {
          const newSelections = prev.selections.filter((_, i) => i !== index);
          return { selections: newSelections, totalCost: newSelections.reduce((sum, s) => sum + (s.cost * s.multiplier), 0) };
      });
  };
  const updateSelectionMultiplier = (index: number, mult: number) => {
      setBetSlip(prev => {
          const newSelections = [...prev.selections];
          if(newSelections[index]) newSelections[index] = { ...newSelections[index], multiplier: Math.max(1, mult) };
          return { selections: newSelections, totalCost: newSelections.reduce((sum, s) => sum + (s.cost * s.multiplier), 0) };
      });
  };

  const initiateBookBet = () => {
      // Booking logic is less critical financially, can stay local/mock for now or follow same pattern
      const newBooking: Ticket = {
        id: `BOOK-${Math.random().toString(36).substring(2, 8).toUpperCase()}`,
        bookingCode: Math.random().toString(36).substring(2, 7).toUpperCase(),
        timestamp: effectiveTime,
        vendorId: '',
        vendorName: currentUser?.name || '',
        customerId: currentUser?.id,
        status: 'Booked',
        ...betSlip
      };
      // In production, save booking to DB too
      setPlacedTickets(prev => [...prev, newBooking]);
      setLastBooking(newBooking);
      clearBetSlip();
  };

  const handleLogin = (user: User) => setCurrentUser(user);
  const handleLogout = () => setCurrentUser(null);

  // --- Mock Implementations for Non-Critical Features (Chat, Images) ---
  // These would also be connected to Supabase tables in a full production refactor
  const handleSendMessage = (threadId: string, content: string, recipients: string[]) => { /* ... */ };
  const markThreadAsRead = (threadId: string) => { /* ... */ };

  // --- Admin/Supervisor Functions (Syncing mostly handled by subscriptions now) ---
  const handleAddUser = async (name: string, role: Role, phone?: string, password?: string) => {
      if(supabase) {
          await supabase.from('users').insert({
              id: `${role.toUpperCase().slice(0, 4)}-${Math.random().toString(36).substring(2,6)}`,
              name, role, phone, password, is_locked: false
          });
      } else {
          // Fallback
      }
  };

  const handleDeposit = (customerId: string, amount: number) => {
      // Should call a 'process_deposit' RPC in Supabase
      // For now, updating local users state is handled by the subscription callback
      return { success: true, bonusApplied: 0 };
  };

  if (!currentUser) return <LoginScreen onLogin={handleLogin} users={users} onSignUp={(n,r,p,pw) => { return {id:'new', name:n, role:r} as User; }} />;

  return (
    <>
      <Header
        user={currentUser}
        onLogout={handleLogout}
        walletFlash={walletFlash}
        onWalletFlashComplete={() => setWalletFlash(false)}
        onOpenChat={() => setIsChatOpen(true)}
        messages={messages}
        threads={threads}
        isTestingMode={isTestingMode}
        onToggleTestingMode={(currentUser.role === 'Admin' || currentUser.role === 'Supervisor') ? () => setIsTestingMode(!isTestingMode) : undefined}
        pendingDepositCount={depositRequests.filter(r => r.status === 'Pending').length}
      />
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        {currentUser.role === 'Vendor' && (
          <BettingTerminal
            races={races}
            betSlip={betSlip}
            onUpdateBetSlip={updateBetSlip}
            onClearBetSlip={clearBetSlip}
            onInitiatePlaceBet={initiatePlaceBet}
            lastTicket={lastTicket}
            onCloseTicket={() => setLastTicket(null)}
            onRemoveSelection={removeSelection}
            onUpdateSelectionMultiplier={updateSelectionMultiplier}
            placedTickets={placedTickets}
            allTickets={placedTickets}
            onCancelTicket={(id) => { /* Implement Cancel RPC */ }}
