import { createClient } from '@supabase/supabase-js';
import { Ticket, User, Race, DepositLog } from './types';

// Safely retrieve environment variables
const getEnvVar = (key: string): string | undefined => {
  try {
    // @ts-ignore
    if (typeof import.meta !== 'undefined' && import.meta.env) {
      // @ts-ignore
      return import.meta.env[key];
    }
  } catch (e) { }
  return undefined;
};

const supabaseUrl = getEnvVar('VITE_SUPABASE_URL');
const supabaseAnonKey = getEnvVar('VITE_SUPABASE_ANON_KEY');

// Initialize Client with optimized settings for mobile connections
export const supabase = (supabaseUrl && supabaseAnonKey) 
  ? createClient(supabaseUrl, supabaseAnonKey, {
      realtime: {
        params: {
          eventsPerSecond: 10, // Limit event throughput to prevent freezing
        },
      },
      auth: {
        persistSession: true, // Keep users logged in
      }
    }) 
  : null;

/**
 * Checks connection health.
 */
export const checkBackendConnection = async () => {
    if (!supabase) return false;
    try {
        const { error } = await supabase.from('users').select('count', { count: 'exact', head: true }).limit(1);
        return !error;
    } catch (e) {
        return false;
    }
};

/**
 * Executes a secure bet placement transaction on the database.
 */
export const dbPlaceBet = async (ticket: Ticket, user: User) => {
    if (!supabase) throw new Error("Supabase not connected");

    const isOnlineCustomer = user.role === 'Customer';

    // Call the Postgres RPC function defined in the SQL setup
    const { data, error } = await supabase.rpc('place_bet_transaction', {
        p_ticket_id: ticket.id,
        p_vendor_id: isOnlineCustomer ? null : user.id,
        p_vendor_name: user.name,
        p_customer_id: isOnlineCustomer ? user.id : null,
        p_total_cost: ticket.totalCost,
        p_selections: ticket.selections,
        p_status: ticket.status,
        p_booking_code: ticket.bookingCode || null
    });

    if (error) {
        console.error("Bet Transaction Error:", error);
        throw new Error(error.message);
    }
    return data;
};

/**
 * Executes a secure payout transaction.
 * Prevents double-paying a ticket by using a database lock.
 */
export const dbPayoutTicket = async (ticketId: string, amount: number, staffId: string, staffName: string) => {
    if (!supabase) throw new Error("Supabase not connected");

    const { data, error } = await supabase.rpc('payout_ticket_transaction', {
        p_ticket_id: ticketId,
        p_payout_amount: amount,
        p_paid_by_id: staffId,
        p_paid_by_name: staffName
    });

    if (error) throw new Error(error.message);
    return data; // Returns true if successful, false if already paid
}

/**
 * Syncs Users from DB
 */
export const dbFetchUsers = async (): Promise<User[]> => {
    if(!supabase) return [];
    const { data, error } = await supabase.from('users').select('*');
    if(error) { console.error(error); return []; }

    // Map DB snake_case to TS camelCase
    return data.map((u: any) => ({
        id: u.id,
        name: u.name,
        role: u.role,
        isLocked: u.is_locked,
        phone: u.phone,
        password: u.password,
        walletBalance: u.wallet_balance,
        bonusBalance: u.bonus_balance,
        createdById: u.created_by_id,
        createdByName: u.created_by_name
    }));
};

/**
 * Syncs Races from DB
 */
export const dbFetchRaces = async (): Promise<Race[]> => {
    if(!supabase) return [];
    const { data, error } = await supabase.from('races').select('*');
    if(error) { console.error(error); return []; }

    return data.map((r: any) => ({
        id: r.id,
        name: r.name,
        startDate: new Date(r.start_date),
        endDate: new Date(r.end_date),
        horseCount: r.horse_count,
        nonRunners: r.non_runners || [],
        result: r.result, // JSONB maps directly
        disabledBetTypes: r.disabled_bet_types || [],
        jackpot: r.jackpot
    }));
};

/**
 * Syncs ACTIVE tickets or tickets from last 24h.
 * CRITICAL PERFORMANCE FIX: Do NOT fetch 100,000 tickets.
 * Only fetch what is needed for the dashboard.
 */
export const dbFetchLiveTickets = async (user: User): Promise<Ticket[]> => {
    if(!supabase) return [];

    const twentyFourHoursAgo = new Date();
    twentyFourHoursAgo.setHours(twentyFourHoursAgo.getHours() - 24);

    let query = supabase
        .from('tickets')
        .select('*')
        .gte('timestamp', twentyFourHoursAgo.toISOString()) // Only recent
        .order('timestamp', { ascending: false });

    // RLS usually handles this, but explicit filtering helps performance too
    if (user.role === 'Vendor') {
        query = query.eq('vendor_id', user.id);
    } else if (user.role === 'Customer') {
        query = query.eq('customer_id', user.id);
    }

    const { data, error } = await query;

    if(error) { console.error(error); return []; }

    return data.map((t: any) => ({
        id: t.id,
        timestamp: new Date(t.timestamp),
        vendorId: t.vendor_id,
        vendorName: t.vendor_name,
        status: t.status,
        customerId: t.customer_id,
        bookingCode: t.booking_code,
        selections: t.selections,
        totalCost: t.total_cost,
        winnings: t.winnings,
        winningsBreakdown: t.winnings_breakdown,
        paidAt: t.paid_at ? new Date(t.paid_at) : undefined,
        paidById: t.paid_by_id,
        paidByName: t.paid_by_name,
        canceledAt: t.canceled_at ? new Date(t.canceled_at) : undefined,
        canceledById: t.canceled_by_id,
        canceledByName: t.canceled_by_name
    }));
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, ChatMessage, ChatThread } from '../types';
import { Logo } from './Logo';
import { useLanguage } from '../LanguageContext';
import { checkBackendConnection } from '../supabaseClient';

interface HeaderProps {
  user: User | null;
  onLogout: () => void;
  walletFlash: boolean;
  onWalletFlashComplete: () => void;
  onOpenChat: () => void;
  messages: ChatMessage[];
  threads: ChatThread[];
  isTestingMode?: boolean;
  onToggleTestingMode?: () => void;
  pendingDepositCount?: number;
}

export const Header: React.FC<HeaderProps> = ({ 
    user, 
    onLogout, 
    walletFlash, 
    onWalletFlashComplete, 
    onOpenChat, 
    messages, 
    threads, 
    isTestingMode, 
    onToggleTestingMode,
    pendingDepositCount = 0
}) => {
  const [isFlashing, setIsFlashing] = useState(false);
  const [isOnline, setIsOnline] = useState(true);
  const { language, setLanguage } = useLanguage();

  useEffect(() => {
    if (walletFlash) {
      setIsFlashing(true);
      const timer = setTimeout(() => {
        setIsFlashing(false);
        onWalletFlashComplete();
      }, 700); 
      return () => clearTimeout(timer);
    }
  }, [walletFlash, onWalletFlashComplete]);

  // Network Heartbeat
  useEffect(() => {
      const checkStatus = async () => {
          const status = await checkBackendConnection();
          setIsOnline(status);
      };

      // Check immediately and then every 30 seconds
      checkStatus();
      const interval = setInterval(checkStatus, 30000);

      // Also listen to window events
      window.addEventListener('online', () => setIsOnline(true));
      window.addEventListener('offline', () => setIsOnline(false));

      return () => {
          clearInterval(interval);
          window.removeEventListener('online', () => setIsOnline(true));
          window.removeEventListener('offline', () => setIsOnline(false));
      };
  }, []);

  const unreadCount = useMemo(() => {
    if (!user) return 0;
    const userThreads = threads.filter(thread => {
        if (thread.participantIds.includes(user.id)) return true;
        if (user.role === 'Vendor' && thread.participantIds.includes('ALL_VENDORS')) return true;
        if (['Admin', 'Supervisor'].includes(user.role) && thread.participantIds.includes('BACK_OFFICE')) return true;
        return false;
    });

    let count = 0;
    for (const thread of userThreads) {
        const hasUnread = messages.some(msg => msg.threadId === thread.id && !msg.readByIds.includes(user.id) && msg.senderId !== user.id);
        if (hasUnread) {
            count++;
        }
    }
    return count;
  }, [messages, threads, user]);

  return (
    <header className="bg-white shadow-md sticky top-0 z-40">
      <div className="max-w-7xl mx-auto px-2 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">

          {/* LEFT: Logo & Branding */}
          <div className="flex items-center flex-shrink-0">
            <Logo className="h-8 sm:h-10 w-auto" />
            <span className="ml-2 font-bold text-lg sm:text-xl text-betese-dark hidden md:block">Betese PMU</span>

            {/* Connection Status Badge */}
            {!isOnline && (
                <span className="ml-2 px-2 py-0.5 bg-red-600 text-white text-[10px] uppercase font-bold rounded animate-pulse">
                    OFFLINE
                </span>
            )}
            {isOnline && (
                <span className="ml-2 w-2 h-2 bg-green-500 rounded-full" title="System Online"></span>
            )}
          </div>

          {/* RIGHT: Controls */}
          <div className="flex items-center justify-end flex-grow gap-1 sm:gap-2 ml-2 min-w-0">

            {/* Language Switcher */}
            <div className="flex items-center bg-gray-100 p-0.5 rounded-lg flex-shrink-0 mr-1">
                <button 
                    onClick={() => setLanguage('en')}
                    className={`px-2 py-1 rounded text-[10px] sm:text-sm font-bold transition-all ${
                        language === 'en' 
                        ? 'bg-white text-blue-800 shadow-sm ring-1 ring-gray-200' 
                        : 'text-gray-500 hover:bg-gray-200'
                    }`}
                >
                    EN
                </button>
                <button 
                    onClick={() => setLanguage('fr')}
                    className={`px-2 py-1 rounded text-[10px] sm:text-sm font-bold transition-all ${
                        language === 'fr' 
                        ? 'bg-white text-blue-800 shadow-sm ring-1 ring-gray-200' 
                        : 'text-gray-500 hover:bg-gray-200'
                    }`}
                >
                    FR
                </button>
            </div>

            {user && (
                <>
                {/* Staff Deposit Alert */}
                {['Admin', 'Supervisor', 'Vendor'].includes(user.role) && pendingDepositCount > 0 && (
                    <div className="flex items-center animate-pulse bg-red-100 border border-red-400 px-2 py-1 rounded-full flex-shrink-0">
                        <span className="relative flex h-2 w-2 mr-1">
                            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                            <span className="relative inline-flex rounded-full h-2 w-2 bg-red-500"></span>
                        </span>
                        <span className="text-[10px] font-bold text-red-800">
                            {pendingDepositCount}
                        </span>
                    </div>
                )}

                {user.role === 'Customer' && (
                    <div className={`p-1 rounded-lg transition-all flex-shrink-0 ${isFlashing ? 'bg-red-100 animate-pulse' : 'bg-green-100'}`}>
                        <div className="text-right leading-none">
                            <span className="font-bold text-betese-green text-xs sm:text-sm">
                                {user.walletBalance?.toFixed(2)}
                            </span>
                        </div>
                    </div>
                )}

                {/* User Name */}
                <div className="text-right hidden sm:block mx-2">
                    <p className="font-semibold text-sm truncate max-w-[100px]">{user.name}</p>
                </div>

                {/* Chat Button */}
                <button onClick={onOpenChat} className="relative p-2 rounded-full hover:bg-gray-100 flex-shrink-0">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-gray-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" /></svg>
                    {unreadCount > 0 && <span className="absolute top-0 right-0 inline-flex items-center justify-center px-1.5 py-0.5 text-[10px] font-bold leading-none text-red-100 transform translate-x-1/4 -translate-y-1/4 bg-red-600 rounded-full">{unreadCount}</span>}
                </button>

                {/* Logout Button */}
                <button
                    onClick={onLogout}
                    className="p-2 ml-1 rounded-lg bg-red-50 border border-red-200 hover:bg-red-100 focus:ring-2 focus:ring-red-500 flex-shrink-0"
                    title="Logout"
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-red-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
                    </svg>
                </button>
                </>
            )}
          </div>
        </div>
      </div>
    </header>
  );
};

