      }

      try {
          const isConnected = await checkBackendConnection();
          setIsOnline(isConnected);
          if(!isConnected) return;

          const [fetchedUsers, fetchedRaces] = await Promise.all([
              dbFetchUsers(),
              dbFetchRaces()
          ]);

          if(fetchedUsers.length > 0) setUsers(fetchedUsers);
          if(fetchedRaces.length > 0) setRaces(fetchedRaces);

          // If a user is already logged in, fetch their specific ticket history
          if(currentUser) {
              const liveTickets = await dbFetchLiveTickets(currentUser);
              setPlacedTickets(liveTickets);
          }

      } catch (err) {
          console.error("Data Sync Error:", err);
      }
  };

  // Initial Load
  useEffect(() => {
      loadLiveSystemData();
  }, []);

  // Realtime Subscriptions (Specific to user to avoid 100k message flood)
  useEffect(() => {
      if (!supabase || !currentUser) return;

      // 1. Subscribe to USERS (Balance updates)
      const userSub = supabase.channel('public:users')
          .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'users', filter: `id=eq.${currentUser.id}` }, async (payload) => {
              // Update local current user state immediately for responsiveness
              setCurrentUser(prev => prev ? { ...prev, ...payload.new } : null);

              // Also refresh full user list in background
              const updatedUsers = await dbFetchUsers();
              setUsers(updatedUsers);
          })
          .subscribe();

      // 2. Subscribe to TICKETS (New sales, payouts)
      // Optimized: Only listen to tickets relevant to THIS user/vendor
      let ticketFilter = '';
      if(currentUser.role === 'Vendor') ticketFilter = `vendor_id=eq.${currentUser.id}`;
      if(currentUser.role === 'Customer') ticketFilter = `customer_id=eq.${currentUser.id}`;
      // Admin sees all, but we might want to restrict this in production to avoid freezing.

      const ticketSub = supabase.channel('public:tickets')
          .on('postgres_changes', { event: '*', schema: 'public', table: 'tickets', filter: ticketFilter }, async () => {
              // Re-fetch only the "Live" window of tickets
              const updatedTickets = await dbFetchLiveTickets(currentUser);
              setPlacedTickets(updatedTickets);
          })
          .subscribe();

      // 3. Subscribe to RACES (Results, status) - Everyone listens to this
      const raceSub = supabase.channel('public:races')
          .on('postgres_changes', { event: '*', schema: 'public', table: 'races' }, async () => {
              const updatedRaces = await dbFetchRaces();
              setRaces(updatedRaces);
          })
          .subscribe();

      return () => {
          supabase?.removeChannel(userSub);
          supabase?.removeChannel(ticketSub);
          supabase?.removeChannel(raceSub);
      };
  }, [currentUser?.id]); // Re-subscribe if user changes

  // Timer
  useEffect(() => {
    if (isTestingMode) return;
    const interval = setInterval(() => setEffectiveTime(new Date()), 1000);
    return () => clearInterval(interval);
  }, [isTestingMode]);

  // --- ACTIONS ---

  const calculateCost = useCallback((betType: BetTypeOption, numbers: number[], xCount: number): number => {
    const pricing = BET_PRICING[betType];
    if (!pricing) return 0;
    if (pricing.perHorsePrice) return (numbers.length + xCount) * pricing.perHorsePrice;
    if (xCount > 0) return pricing.xPriceMap?.[xCount]?.[numbers.length] ?? 0;
    return pricing.priceMap[numbers.length] ?? 0;
  }, []);

  const updateBetSlip = (newSelection: Omit<BetSelection, 'cost' | 'multiplier'>) => {
    const costOfNewSelection = calculateCost(newSelection.betType, newSelection.numbers, newSelection.xCount);
    setBetSlip(prev => {
      const updated = { ...newSelection, cost: costOfNewSelection, multiplier: 1 };
      const newSelections = [...prev.selections, updated];
      const totalCost = newSelections.reduce((sum, s) => sum + (s.cost * s.multiplier), 0);
      return { selections: newSelections, totalCost };
    });
  };

  const placeBet = async () => {
    if (!currentUser || betSlip.selections.length === 0) return;

    if (!isOnline && supabase) {
        alert("System is offline. Please check connection.");
        return;
    }

    // Security Cutoff
    const now = effectiveTime.getTime();
    const lateSelections = betSlip.selections.filter(selection => {
        const race = races.find(r => r.id === selection.raceId);
        if (!race) return true;
        return (race.endDate.getTime() - now) <= BETTING_CUTOFF_MS;
    });

    if (lateSelections.length > 0) {
        setConfirmationModal(null);
        alert(`FAILED: Betting closed for one or more races.`);
        return;
    }

    // Construct Ticket Object
    const newTicket: Ticket = {
      id: Math.floor(10000000 + Math.random() * 90000000).toString(),
      timestamp: effectiveTime,
      vendorId: currentUser.role === 'Vendor' ? currentUser.id : '',
      vendorName: currentUser.name,
      status: 'Active',
      customerId: currentUser.role === 'Customer' ? currentUser.id : undefined,
      ...betSlip
    };

    try {
        if (supabase) {
            // DATABASE TRANSACTION (Atomic & Secure)
            await dbPlaceBet(newTicket, currentUser);
        } else {
            // LOCAL FALLBACK (Mock Mode)
            if (currentUser.role === 'Customer') {
                const bal = (currentUser.walletBalance || 0) + (currentUser.bonusBalance || 0);
                if (bal < newTicket.totalCost) { setWalletFlash(true); return; }

                const updatedUser = { ...currentUser, walletBalance: (currentUser.walletBalance || 0) - newTicket.totalCost };
                setUsers(prev => prev.map(u => u.id === currentUser.id ? updatedUser : u));
                setCurrentUser(updatedUser);
            }
            setPlacedTickets(prev => [...prev, newTicket]);
        }

        setLastTicket(newTicket);
        clearBetSlip();

    } catch (e: any) {
        alert(`Transaction Failed: ${e.message}`);
    }
  };

  const initiatePlaceBet = () => {
      const now = effectiveTime.getTime();
      const hasRaceEnded = betSlip.selections.some(selection => {
          const race = races.find(r => r.id === selection.raceId);
          return !race || (race.endDate.getTime() - now) <= BETTING_CUTOFF_MS;
      });

      if (hasRaceEnded) {
          alert('Betting has closed for one or more selected races.');
          return;
      }

      setConfirmationModal({
        isOpen: true,
        title: "Confirm Bet",
        content: (
          <div>
            <p>Are you sure you want to place this bet?</p>
            <p className="font-bold text-lg mt-2">Total Cost: {betSlip.totalCost.toFixed(2)} GMD</p>
          </div>
        ),
        onConfirm: placeBet
      });
  };

  const payoutTicket = async (ticketId: string) => {
      if(!currentUser) return;
      const ticket = placedTickets.find(t => t.id === ticketId);
      if(!ticket || !ticket.winnings) return;

      if(supabase) {
          try {
              // Perform atomic DB payout
              const success = await dbPayoutTicket(ticketId, ticket.winnings, currentUser.id, currentUser.name);
              if(success) {
                  // UI update will happen via subscription, but we can optimistically update
                  const paidTicket = { ...ticket, status: 'Paid' as const, paidAt: new Date(), paidById: currentUser.id, paidByName: currentUser.name };
                  setPaidTicketModal(paidTicket);
              } else {
                  alert("Ticket already paid or invalid.");
              }
          } catch(e: any) {
              alert("Payout failed: " + e.message);
          }
      } else {
          // Local Mock Payout
          setPlacedTickets(prev => prev.map(t => {
            if (t.id === ticketId && t.status === 'Winning') {
                const paidTicket = { 
                    ...t, 
                    status: 'Paid' as const,
                    paidAt: effectiveTime,
                    paidById: currentUser.id,
                    paidByName: currentUser.name
                };
                setPaidTicketModal(paidTicket);
                return paidTicket;
            }
            return t;
          }));
      }
  }

  // --- Other Handlers ---

  const clearBetSlip = () => setBetSlip({ selections: [], totalCost: 0 });
  const removeSelection = (index: number) => {
      setBetSlip(prev => {
          const newSelections = prev.selections.filter((_, i) => i !== index);
          return { selections: newSelections, totalCost: newSelections.reduce((sum, s) => sum + (s.cost * s.multiplier), 0) };
      });
  };
  const updateSelectionMultiplier = (index: number, mult: number) => {
      setBetSlip(prev => {
          const newSelections = [...prev.selections];
          if(newSelections[index]) newSelections[index] = { ...newSelections[index], multiplier: Math.max(1, mult) };
          return { selections: newSelections, totalCost: newSelections.reduce((sum, s) => sum + (s.cost * s.multiplier), 0) };
      });
  };

  const initiateBookBet = () => {
      const newBooking: Ticket = {
        id: `BOOK-${Math.random().toString(36).substring(2, 8).toUpperCase()}`,
        bookingCode: Math.random().toString(36).substring(2, 7).toUpperCase(),
        timestamp: effectiveTime,
        vendorId: '',
        vendorName: currentUser?.name || '',
        customerId: currentUser?.id,
        status: 'Booked',
        ...betSlip
      };
      // In production, save booking to DB too (omitted for brevity, follows dbPlaceBet pattern)
      setPlacedTickets(prev => [...prev, newBooking]);
      setLastBooking(newBooking);
      clearBetSlip();
  };

  const handleLogin = (user: User) => {
      setCurrentUser(user);
      // Immediately try to fetch this user's data
      if (supabase) {
          dbFetchLiveTickets(user).then(setPlacedTickets);
      }
  };
  const handleLogout = () => {
      setCurrentUser(null);
      setPlacedTickets([]);
  };

  // --- MOCK Handlers for non-transactional items (Syncing these is identical pattern to Tickets) ---
  const handleSendMessage = (threadId: string, content: string, recipients: string[]) => { /* ... */ };
  const markThreadAsRead = (threadId: string) => { /* ... */ };

  const handleAddUser = async (name: string, role: Role, phone?: string, password?: string) => {
      if(supabase) {
          await supabase.from('users').insert({
              id: `${role.toUpperCase().slice(0, 4)}-${Math.random().toString(36).substring(2,6)}`,
              name, role, phone, password, is_locked: false
          });
          // State updates via subscription
      } else {
          // Fallback
      }
  };

  const handleDeposit = (customerId: string, amount: number) => {
      return { success: true, bonusApplied: 0 };
  };

  if (!currentUser) return <LoginScreen onLogin={handleLogin} users={users} onSignUp={(n,r,p,pw) => { return {id:'new', name:n, role:r} as User; }} />;

  return (
    <>
