// FIX: Added missing calculateWinSummary function
export function calculateWinSummary(race: Race, winningNumbers: number[], tickets: Ticket[]): WinSummary {
    const summary: WinSummary = {};

    const addToSummary = (type: string, stake: number) => {
        if (!summary[type]) summary[type] = { count: 0, stake: 0 };
        summary[type].count += 1;
        summary[type].stake += stake;
    };

    tickets.forEach(ticket => {
        if (ticket.status === 'Canceled') return;
        ticket.selections.forEach((sel) => {
            if (sel.raceId !== race.id) return;

            const results = checkSelectionWin(sel, winningNumbers);
            results.forEach(res => addToSummary(res.winType, sel.cost * sel.multiplier));
        });
    });

    return summary;
}

// FIX: Implemented calculateTicketWinnings with actual PMU logic
export function calculateTicketWinnings(ticket: Ticket, allRaces: Race[]): { totalWinnings: number; breakdown: WinningsBreakdown[] } {
    let grandTotalWinnings = 0;
    const finalBreakdown: WinningsBreakdown[] = [];

    if (ticket.status === 'Canceled') return { totalWinnings: 0, breakdown: [] };

    ticket.selections.forEach((sel, index) => {
        const race = allRaces.find(r => r.id === sel.raceId);
        if (!race || !race.result) return;

        const results: WinningsBreakdown[] = [];

        // 1. Primary
        const primaryWins = checkSelectionWin(sel, race.result.winningNumbers);
        primaryWins.forEach(win => {
            const payout = (race.result!.payouts as any)[win.payoutKey] || 0;
            const pricing = BET_PRICING[sel.betType];
            const basePrice = pricing?.basePrice || pricing?.perHorsePrice || 1;
            const totalPayout = (sel.cost / basePrice) * payout * sel.multiplier;

            results.push({
                selectionIndex: index,
                status: 'Win',
                winType: win.winType,
                payoutPerCombination: payout,
                totalPayout: totalPayout,
                source: 'Primary'
            });
        });

        // 2. Bracket 1
        if (race.result.bracketWinningNumbers && race.result.bracketPayouts) {
            const b1Wins = checkSelectionWin(sel, race.result.bracketWinningNumbers);
            b1Wins.forEach(win => {
                const payout = (race.result!.bracketPayouts as any)[win.payoutKey] || 0;
                const pricing = BET_PRICING[sel.betType];
                const basePrice = pricing?.basePrice || pricing?.perHorsePrice || 1;
                const totalPayout = (sel.cost / basePrice) * payout * sel.multiplier;

                results.push({
                    selectionIndex: index,
                    status: 'Win',
                    winType: win.winType,
                    payoutPerCombination: payout,
                    totalPayout: totalPayout,
                    source: 'Bracket 1'
                });
            });
        }

        // 3. Bracket 2
        if (race.result.bracket2WinningNumbers && race.result.bracket2Payouts) {
            const b2Wins = checkSelectionWin(sel, race.result.bracket2WinningNumbers);
            b2Wins.forEach(win => {
                const payout = (race.result!.bracket2Payouts as any)[win.payoutKey] || 0;
                const pricing = BET_PRICING[sel.betType];
                const basePrice = pricing?.basePrice || pricing?.perHorsePrice || 1;
                const totalPayout = (sel.cost / basePrice) * payout * sel.multiplier;

                results.push({
                    selectionIndex: index,
                    status: 'Win',
                    winType: win.winType,
                    payoutPerCombination: payout,
                    totalPayout: totalPayout,
                    source: 'Bracket 2'
                });
            });
        }

        if (results.length > 0) {
            results.forEach(res => {
                grandTotalWinnings += res.totalPayout || 0;
                finalBreakdown.push(res);
            });
        } else {
            finalBreakdown.push({ selectionIndex: index, status: 'Loss' });
        }
    });

    return { totalWinnings: grandTotalWinnings, breakdown: finalBreakdown };
}

// FIX: Helper function to determine wins for a specific selection
function checkSelectionWin(sel: any, winNums: number[]): { winType: string, payoutKey: string }[] {
    const wins: { winType: string, payoutKey: string }[] = [];
    if (!winNums || winNums.length < 1) return wins;

    const horses = sel.numbers;
    const betType = sel.betType;

    if (betType === BetTypeOption.SimpleGagnant) {
        if (horses.includes(winNums[0])) wins.push({ winType: 'Simple Gagnant', payoutKey: 'simpleGagnant' });
    }

    if (betType === BetTypeOption.SimplePlace) {
        if (horses.includes(winNums[0])) wins.push({ winType: 'Simple Placé', payoutKey: 'simplePlaceA' });
        else if (horses.includes(winNums[1])) wins.push({ winType: 'Simple Placé', payoutKey: 'simplePlaceB' });
        else if (horses.includes(winNums[2])) wins.push({ winType: 'Simple Placé', payoutKey: 'simplePlaceC' });
    }

    if (betType === BetTypeOption.CoupleGagnant) {
        if (horses.includes(winNums[0]) && horses.includes(winNums[1])) {
            wins.push({ winType: 'Couplé Gagnant', payoutKey: 'ordreGagnant' });
        }
    }

    if (betType === BetTypeOption.CouplePlace) {
        const top3 = winNums.slice(0, 3);
        const matches = horses.filter((h: number) => top3.includes(h));
        if (matches.length >= 2) {
             const h1 = horses.find((h: number) => h === winNums[0]);
             const h2 = horses.find((h: number) => h === winNums[1]);
             const h3 = horses.find((h: number) => h === winNums[2]);

             if (h1 && h2) wins.push({ winType: 'Couplé Placé', payoutKey: 'coupleA' });
             else if (h1 && h3) wins.push({ winType: 'Couplé Placé', payoutKey: 'coupleB' });
             else if (h2 && h3) wins.push({ winType: 'Couplé Placé', payoutKey: 'coupleC' });
        }
    }

    if (betType === BetTypeOption.Tierce) {
        const top3 = winNums.slice(0, 3);
        const matches = horses.filter((h: number) => top3.includes(h));
        if (matches.length === 3) {
            if (horses[0] === winNums[0] && horses[1] === winNums[1] && horses[2] === winNums[2]) {
                wins.push({ winType: 'Tiercé Ordre', payoutKey: 'tierceOrdre' });
            } else {
                wins.push({ winType: 'Tiercé Désordre', payoutKey: 'tierceDesordre' });
            }
        }
    }

    if (betType === BetTypeOption.Quarte) {
        const top4 = winNums.slice(0, 4);
        const top3 = winNums.slice(0, 3);
        const matches4 = horses.filter((h: number) => top4.includes(h));
        const matches3 = horses.filter((h: number) => top3.includes(h));

        if (matches4.length === 4) {
            if (horses[0] === winNums[0] && horses[1] === winNums[1] && horses[2] === winNums[2] && horses[3] === winNums[3]) {
                wins.push({ winType: 'Quarté+ Ordre', payoutKey: 'quarteOrdre' });
            } else {
                wins.push({ winType: 'Quarté+ Désordre', payoutKey: 'quarteDesordre' });
            }
        } else if (matches3.length === 3) {
            wins.push({ winType: 'Quarté+ Bonus 3', payoutKey: 'quarteBonus3' });
        }
    }

    if (betType === BetTypeOption.Quinte) {
        const top5 = winNums.slice(0, 5);
        const top4 = winNums.slice(0, 4);
        const top3 = winNums.slice(0, 3);
        const matches5 = horses.filter((h: number) => top5.includes(h));
        const matches4 = horses.filter((h: number) => top4.includes(h));
        const matches3 = horses.filter((h: number) => top3.includes(h));

        if (matches5.length === 5) {
            if (horses[0] === winNums[0] && horses[1] === winNums[1] && horses[2] === winNums[2] && horses[3] === winNums[3] && horses[4] === winNums[4]) {
                wins.push({ winType: 'Quinté+ Ordre', payoutKey: 'quinteOrdre' });
            } else {
                wins.push({ winType: 'Quinté+ Désordre', payoutKey: 'quinteDesordre' });
            }
        } else if (matches4.length === 4) {
            wins.push({ winType: 'Quinté+ Bonus 4', payoutKey: 'quinteBonus4' });
        } else if (matches3.length === 3) {
            wins.push({ winType: 'Quinté+ Bonus 3', payoutKey: 'quinteBonus3' });
        }
    }

    if ([BetTypeOption.Multi4, BetTypeOption.Multi5, BetTypeOption.Multi6, BetTypeOption.Multi7].includes(betType)) {
        const top4 = winNums.slice(0, 4);
        const matches = horses.filter((h: number) => top4.includes(h));
        if (matches.length === 4) {
            const key = betType === BetTypeOption.Multi4 ? 'multi4' : betType === BetTypeOption.Multi5 ? 'multi5' : betType === BetTypeOption.Multi6 ? 'multi6' : 'multi7';
            wins.push({ winType: betType, payoutKey: key });
        }
    }

    return wins;
}

