    className="mb-4 w-full sm:w-auto inline-flex items-center justify-center gap-2 px-6 py-4 bg-gray-800 text-white font-black rounded-xl shadow-md active:scale-95 transition-all uppercase tracking-tighter"
  >
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M12.707 5.293a1 1 0 010 1.414L9.414 10l3.293 3.293a1 1 0 01-1.414 1.414l-4-4a1 1 0 010-1.414l4-4a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
    Return Back to Menu
  </button>
);

export const BettingTerminal: React.FC<BettingTerminalProps> = (props) => {
    const { 
        races, betSlip, onUpdateBetSlip, onClearBetSlip, onInitiatePlaceBet, onRemoveSelection, onUpdateSelectionMultiplier,
        allTickets, onPayForBooking, customers, onDeposit, depositLogs, placedTickets, effectiveTime, currentUser,
        lastTicket, onCloseTicket, onPayoutTicket, onProcessWithdrawal, withdrawalRequests, onReprintTicket
    } = props;

    const [view, setView] = useState<View>('DASHBOARD');
    const [selectedRace, setSelectedRace] = useState<Race | null>(null);
    const [selectedBetType, setSelectedBetType] = useState<BetTypeOption | null>(null);
    const [selectedNumbers, setSelectedNumbers] = useState<number[]>([]);
    const [xCount, setXCount] = useState<number>(0);

    const sortedRaces = useMemo(() => [...races].sort((a,b) => a.endDate.getTime() - b.endDate.getTime()), [races]);

    // Cleanup state when moving back to dashboard
    const handleReturn = () => {
        onClearBetSlip();
        setSelectedNumbers([]);
        setXCount(0);
        setSelectedBetType(null);
        setView('DASHBOARD');
    };

    // Auto-select next available race
    useEffect(() => {
        if (!selectedRace && sortedRaces.length > 0) {
            const next = sortedRaces.find(r => r.endDate > effectiveTime);
            if (next) setSelectedRace(next);
        }
    }, [sortedRaces, effectiveTime, selectedRace]);

    const handleAddBet = useCallback(() => {
        if (!selectedRace || !selectedBetType) return;
        onUpdateBetSlip({
            raceId: selectedRace.id,
            raceName: selectedRace.name,
            betType: selectedBetType,
            numbers: selectedNumbers,
            xCount: xCount,
            pattern: [],
        });
        setSelectedNumbers([]);
        setXCount(0);
        setSelectedBetType(null);
    }, [selectedRace, selectedBetType, selectedNumbers, xCount, onUpdateBetSlip]);

    const renderView = () => {
        switch (view) {
            case 'PLACE_BET':
                return (
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-fade-in">
                        <div className="lg:col-span-2 space-y-4">
                            <div className="bg-white p-4 rounded-xl shadow-md border-t-4 border-green-600">
                                <h3 className="font-black text-gray-800 uppercase mb-3 flex items-center gap-2">
                                    <span className="bg-green-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs">1</span>
                                    Select Race
                                </h3>
                                <div className="flex flex-wrap gap-2">
                                    {sortedRaces.map(r => (
                                        <RaceTimerButton 
                                            key={r.id} race={r} 
                                            isSelected={selectedRace?.id === r.id} 
                                            onClick={() => setSelectedRace(r)} 
                                            initialEffectiveTime={effectiveTime} 
                                        />
                                    ))}
                                    {sortedRaces.length === 0 && <p className="text-gray-400 italic py-4">No races currently active.</p>}
                                </div>
                            </div>
                            {selectedRace && (
                                <div className="bg-white p-4 rounded-xl shadow-md border-t-4 border-blue-600">
                                    <h3 className="font-black text-gray-800 uppercase mb-3 flex items-center gap-2">
                                        <span className="bg-blue-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs">2</span>
                                        Bet Type & Horses
                                    </h3>
                                    <div className="grid grid-cols-3 sm:grid-cols-4 gap-2 mb-4">
                                        {Object.values(BetTypeOption).map(bt => (
                                            <button 
                                                key={bt} 
                                                onClick={() => setSelectedBetType(bt)}
                                                className={`p-3 rounded-lg text-xs font-black border-2 transition-all ${selectedBetType === bt ? 'bg-blue-600 text-white border-blue-800 shadow-inner' : 'bg-gray-50 text-gray-700 border-gray-200 hover:bg-gray-100'}`}
                                            >
                                                {bt}
                                            </button>
                                        ))}
                                    </div>
                                    {selectedBetType && (
                                        <HorseSelector 
                                            race={selectedRace} betType={selectedBetType} 
                                            selectedNumbers={selectedNumbers} xCount={xCount}
                                            onNumberSelect={setSelectedNumbers} onXSelect={setXCount}
                                        />
                                    )}
                                    <button 
                                        onClick={handleAddBet}
                                        disabled={!selectedBetType || (selectedNumbers.length + xCount === 0)}
                                        className="w-full mt-4 py-4 bg-betese-dark text-white font-black rounded-xl disabled:opacity-50 shadow-lg active:scale-95 transition-transform"
                                    >
                                        ADD TO SLIP
                                    </button>
                                </div>
                            )}
                        </div>
                        <BetSlipPanel 
                            betSlip={betSlip} onClear={onClearBetSlip} onInitiatePlaceBet={onInitiatePlaceBet} 
                            onRemove={onRemoveSelection} onUpdateSelectionMultiplier={onUpdateSelectionMultiplier} 
                        />
                    </div>
                );

            case 'TICKET_TOOLS':
                return (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-fade-in">
                        <TicketCheckPanel allTickets={allTickets} onPayoutTicket={onPayoutTicket} />
                        <BookingRetrievalPanel 
                            allTickets={allTickets} 
                            onPayForBooking={onPayForBooking} 
                            onPrintBookingSlip={onReprintTicket} 
                            races={races} 
                            effectiveTime={effectiveTime} 
                        />
                    </div>
                );

            case 'ONLINE':
                return (
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-fade-in">
                        <CustomerDepositPanel 
                            customers={customers} 
                            onDeposit={onDeposit} 
                            depositLogs={depositLogs} 
                            currentUserRole={currentUser.role} 
                        />
                        <ProcessWithdrawalPanel 
                            onProcessWithdrawal={onProcessWithdrawal} 
                            withdrawalRequests={withdrawalRequests} 
                            customers={customers} 
                        />
                    </div>
                );

            case 'SALES_REPORT':
                return (
                    <div className="space-y-6 animate-fade-in">
                        <div className="bg-white p-6 rounded-xl shadow-lg border-t-4 border-yellow-500">
                             <h3 className="text-xl font-black uppercase text-gray-800 mb-4">My Sales Activity</h3>
                             <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-6">
                                 <div className="p-4 bg-gray-50 rounded-lg border text-center">
                                     <span className="text-[10px] font-black text-gray-500 uppercase">Today's Sales</span>
                                     <span className="block text-2xl font-black text-betese-green">
                                         {placedTickets.reduce((sum, t) => sum + t.totalCost, 0).toFixed(2)}
                                     </span>
                                 </div>
                                 <div className="p-4 bg-gray-50 rounded-lg border text-center">
                                     <span className="text-[10px] font-black text-gray-500 uppercase">Winning Payouts</span>
                                     <span className="block text-2xl font-black text-blue-600">
                                         {placedTickets.filter(t => t.status === 'Paid').reduce((sum, t) => sum + (t.winnings || 0), 0).toFixed(2)}
                                     </span>
                                 </div>
                                 <div className="p-4 bg-gray-50 rounded-lg border text-center">
                                     <span className="text-[10px] font-black text-gray-500 uppercase">Tickets Count</span>
                                     <span className="block text-2xl font-black text-gray-800">{placedTickets.length}</span>
                                 </div>
                                 <div className="p-4 bg-gray-50 rounded-lg border text-center">
                                     <span className="text-[10px] font-black text-gray-500 uppercase">Balance</span>
                                     <span className="block text-2xl font-black text-orange-600">
                                         {(placedTickets.reduce((sum, t) => sum + t.totalCost, 0) - placedTickets.filter(t => t.status === 'Paid').reduce((sum, t) => sum + (t.winnings || 0), 0)).toFixed(2)}
                                     </span>
                                 </div>
                             </div>
                             <TicketDetailsTable title="My Recent Tickets" tickets={placedTickets} races={races} />
                        </div>
                    </div>
                );

            case 'DASHBOARD':
            default:
                const latestTicket = placedTickets[placedTickets.length - 1];
                return (
                    <div className="space-y-4">
                        {latestTicket && (
                            <div className="bg-yellow-50 border-2 border-yellow-200 p-4 rounded-2xl flex items-center justify-between animate-fade-in shadow-sm">
                                <div>
                                    <p className="text-[10px] font-black text-yellow-700 uppercase">Last Ticket Sold:</p>
                                    <p className="font-mono font-black text-lg text-gray-800">#{latestTicket.id}</p>
                                </div>
                                <button 
                                    onClick={() => onReprintTicket(latestTicket)}
                                    className="px-6 py-3 bg-yellow-500 text-betese-dark font-black rounded-xl shadow hover:bg-yellow-600 active:scale-95 transition-all text-sm uppercase flex items-center gap-2"
                                >
                                    <span>🖨️</span> Reprint Last
                                </button>
                            </div>
                        )}
                        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 sm:gap-6 animate-fade-in">
                            <MenuButton onClick={() => setView('PLACE_BET')} label="New Bet" subtext="Sell Ticket" icon="🏇" color="bg-green-600" />
                            <MenuButton onClick={() => setView('TICKET_TOOLS')} label="Payouts" subtext="Win & Bookings" icon="💰" color="bg-orange-600" />
                            <MenuButton onClick={() => setView('ONLINE')} label="Finance" subtext="Deposit/Withdraw" icon="📱" color="bg-blue-600" />
                            <MenuButton onClick={() => setView('SALES_REPORT')} label="Report" subtext="Sales History" icon="📊" color="bg-gray-700" />
                        </div>
                    </div>
                );
        }
    };

    return (
        <div className="max-w-7xl mx-auto px-2">
            {view !== 'DASHBOARD' && <BackButton onClick={handleReturn} />}
            {renderView()}
            {lastTicket && <TicketModal ticket={lastTicket} onClose={onCloseTicket} showPrintButton={true} races={races} />}
        </div>
    );
};

import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { BetSlip, BetTypeOption, Ticket, BetSelection, User, Role, WithdrawalRequest, Race, RaceResult, DepositLog, ChatMessage, ChatThread, Promotion, PromotionRule, DepositRequest, PaymentIntegrationConfig, ProgramImage } from './types';
import { BET_PRICING, MOCK_USERS, MOCK_PROMOTIONS, MOCK_CHAT_THREADS, MOCK_CHAT_MESSAGES } from './constants';
import { LoginScreen } from './components/LoginScreen';
import { BettingTerminal } from './components/BettingTerminal';
import { Header } from './components/Header';
import { AdminDashboard } from './components/AdminDashboard';
import { SupervisorDashboard } from './components/SupervisorDashboard';
import { CustomerDashboard } from './components/CustomerDashboard';
import { ConfirmationModal } from './components/ConfirmationModal';
import { BookingCodeModal } from './components/BookingCodeModal';
import { WithdrawalCodeModal } from './components/WithdrawalCodeModal';
import { TicketModal } from './components/TicketModal';
import { ChatPanel, BroadcastNotificationModal } from './components/ChatSystem';
import { EmergencyRecover } from './components/EmergencyRecover';
import { SEVEN_DAYS_IN_MS, calculateTicketWinnings, BETTING_CUTOFF_MS } from './utils';
import { LanguageProvider } from './LanguageContext';
import { 
    supabase, dbPlaceBet, dbPayoutTicket, dbFetchUsers, dbFetchRaces, 
    dbFetchLiveTickets, checkBackendConnection, dbSaveRace, 
    dbUpdateRace, dbDeleteRace, dbUpdateNonRunners, dbSaveRaceResult 
} from './supabaseClient';

const AppContent: React.FC = () => {
  // --- STATE MANAGEMENT ---
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]); 
  const [races, setRaces] = useState<Race[]>([]); 
  const [placedTickets, setPlacedTickets] = useState<Ticket[]>([]); 

  const [withdrawalRequests, setWithdrawalRequests] = useState<WithdrawalRequest[]>([]);
  const [depositLogs, setDepositLogs] = useState<DepositLog[]>([]);
  const [depositRequests, setDepositRequests] = useState<DepositRequest[]>([]);
  const [programImages, setProgramImages] = useState<ProgramImage[]>([]);
  const [promotions, setPromotions] = useState<Promotion[]>(MOCK_PROMOTIONS);
  const [threads, setThreads] = useState<ChatThread[]>(MOCK_CHAT_THREADS);
  const [messages, setMessages] = useState<ChatMessage[]>(MOCK_CHAT_MESSAGES);
  const [seenWinningTickets, setSeenWinningTickets] = useState<Set<string>>(new Set());
  const [paymentConfigs, setPaymentConfigs] = useState<PaymentIntegrationConfig[]>([]);

  const [betSlip, setBetSlip] = useState<BetSlip>({ selections: [], totalCost: 0 });
  const [lastTicket, setLastTicket] = useState<Ticket | null>(null);
  const [paidTicketModal, setPaidTicketModal] = useState<Ticket | null>(null);
  const [ticketToReprint, setTicketToReprint] = useState<Ticket | null>(null);
  const [lastBooking, setLastBooking] = useState<Ticket | null>(null);
  const [walletFlash, setWalletFlash] = useState(false);
  const [confirmationModal, setConfirmationModal] = useState<{ isOpen: boolean; title: string; content: React.ReactNode; onConfirm: () => void; } | null>(null);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [effectiveTime, setEffectiveTime] = useState(new Date());
  const [isOnline, setIsOnline] = useState(true);

  // --- RECOVERY & FETCHING ---
  const loadLiveSystemData = async (user?: User) => {
      if (!supabase) { setUsers(MOCK_USERS); return; }
      try {
          const isConnected = await checkBackendConnection();
          setIsOnline(isConnected);
          if(!isConnected) return;
          const [fetchedUsers, fetchedRaces] = await Promise.all([dbFetchUsers(), dbFetchRaces()]);
          if(fetchedUsers.length > 0) setUsers(fetchedUsers);
          setRaces(fetchedRaces);
          const targetUser = user || currentUser;
          if(targetUser) {
              const liveTickets = await dbFetchLiveTickets(targetUser);
              setPlacedTickets(liveTickets);
          }
      } catch (err) { console.error("Data Sync Error:", err); }
  };

  const handleRefreshSystem = () => {
      // Emergency Cleanup - Reset visible UI elements only
      setBetSlip({ selections: [], totalCost: 0 });
      setConfirmationModal(null);
      // We explicitly leave 'lastTicket' or 'paidTicketModal' for a moment so they are printed, 
      // but if we are here via Emergency button, we close them to un-freeze screen.
      setLastTicket(null);
      setPaidTicketModal(null);
      setTicketToReprint(null);
      setIsChatOpen(false);
      // Re-hydrate data from DB (this is where we get the ticket back if it was saved)
      loadLiveSystemData();
  };

  useEffect(() => { loadLiveSystemData(); }, []);

  useEffect(() => {
      if (!supabase || !currentUser) return;
      const userSub = supabase.channel('public:users').on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'users', filter: `id=eq.${currentUser.id}` }, async (payload) => {
          setCurrentUser(prev => prev ? { ...prev, ...payload.new } : null);
          const updatedUsers = await dbFetchUsers(); setUsers(updatedUsers);
      }).subscribe();

      let ticketFilter = '';
      if(currentUser.role === 'Vendor') ticketFilter = `vendor_id=eq.${currentUser.id}`;
      if(currentUser.role === 'Customer') ticketFilter = `customer_id=eq.${currentUser.id}`;

      const ticketSub = supabase.channel('public:tickets').on('postgres_changes', { event: '*', schema: 'public', table: 'tickets', filter: ticketFilter }, async () => {
          const updatedTickets = await dbFetchLiveTickets(currentUser); setPlacedTickets(updatedTickets);
      }).subscribe();
      const raceSub = supabase.channel('public:races').on('postgres_changes', { event: '*', schema: 'public', table: 'races' }, async () => {
          const updatedRaces = await dbFetchRaces(); setRaces(updatedRaces);
      }).subscribe();
      return () => { supabase?.removeChannel(userSub); supabase?.removeChannel(ticketSub); supabase?.removeChannel(raceSub); };
  }, [currentUser?.id]);

  useEffect(() => { const interval = setInterval(() => setEffectiveTime(new Date()), 1000); return () => clearInterval(interval); }, []);

  const ticketProcessor = useMemo(() => {
    const actionable = placedTickets.filter(t => !['Paid', 'Canceled', 'Lost'].includes(t.status));
    if (actionable.length === 0) return;
    const timer = setTimeout(() => { loadLiveSystemData(); }, 5000); 
    return () => clearTimeout(timer);
  }, [races]);

  // --- HANDLERS ---
  const handleAddRace = async (race: Race) => {
      try {
          if (supabase) { await dbSaveRace(race); } 
          else { setRaces(prev => [...prev, race]); }
      } catch (e: any) { alert("Failed to save race: " + e.message); }
  };

  const handleUpdateRace = async (race: Race) => {
      try {
          if (supabase) { await dbUpdateRace(race); } 
          else { setRaces(prev => prev.map(r => r.id === race.id ? race : r)); }
      } catch (e: any) { alert("Failed to update race: " + e.message); }
  };

  const handleDeleteRace = async (race: Race) => {
      if (!confirm("Are you sure you want to delete this race?")) return;
      try {
          if (supabase) { await dbDeleteRace(race.id); } 
          else { setRaces(prev => prev.filter(r => r.id !== race.id)); }
      } catch (e: any) { alert("Failed to delete race: " + e.message); }
  };

  const payoutTicket = async (ticketId: string) => {
      if(!currentUser) return;
      const ticket = placedTickets.find(t => t.id === ticketId);
      if(!ticket || !ticket.winnings) return;
      if(supabase) {
          try {
              const success = await dbPayoutTicket(ticketId, ticket.winnings, currentUser.id, currentUser.name);
              if(success) {
                  const paidTicket = { ...ticket, status: 'Paid' as const, paidAt: new Date(), paidById: currentUser.id, paidByName: currentUser.name };
                  setPaidTicketModal(paidTicket);
              } else { alert("Ticket already paid or invalid."); }
          } catch(e: any) { alert("Payout failed: " + e.message); }
      }
  };

  const updateBetSlip = (newSelection: Omit<BetSelection, 'cost' | 'multiplier'>) => {
    const pricing = BET_PRICING[newSelection.betType];
    let cost = 0;
    if (pricing) {
        if (pricing.perHorsePrice) cost = (newSelection.numbers.length + newSelection.xCount) * pricing.perHorsePrice;
        else if (newSelection.xCount > 0) cost = pricing.xPriceMap?.[newSelection.xCount]?.[newSelection.numbers.length] ?? 0;
        else cost = pricing.priceMap[newSelection.numbers.length] ?? 0;
    }
    setBetSlip(prev => {
      const updated = { ...newSelection, cost, multiplier: 1 };
      const newSelections = [...prev.selections, updated];
      const totalCost = newSelections.reduce((sum, s) => sum + (s.cost * s.multiplier), 0);
      return { selections: newSelections, totalCost };
    });
  };

  const placeBet = async () => {
    if (!currentUser || betSlip.selections.length === 0) return;
    const now = effectiveTime.getTime();
    const isClosed = betSlip.selections.some(s => {
        const r = races.find(race => race.id === s.raceId);
        return !r || (r.endDate.getTime() - now) <= BETTING_CUTOFF_MS;
    });
    if (isClosed) { alert("FAILED: Betting closed."); return; }

    const newTicket: Ticket = {
      id: Math.floor(10000000 + Math.random() * 90000000).toString(),
      timestamp: effectiveTime,
      vendorId: currentUser.role === 'Vendor' ? currentUser.id : '',
      vendorName: currentUser.name,
      status: 'Active',
      customerId: currentUser.role === 'Customer' ? currentUser.id : undefined,
      ...betSlip
    };
    try {
        if (supabase) { await dbPlaceBet(newTicket, currentUser); } 
        else { setPlacedTickets(prev => [...prev, newTicket]); }
        // THE TICKET IS NOW SAVED. IF FREEZE HAPPENS AFTER THIS, IT IS SECURE.
        setLastTicket(newTicket);
        setBetSlip({ selections: [], totalCost: 0 });
    } catch (e: any) { alert(`Transaction Failed: ${e.message}`); }
  };

  const handleLogin = (user: User) => { setCurrentUser(user); if (supabase) { loadLiveSystemData(user); } };
  const handleLogout = () => { setCurrentUser(null); setPlacedTickets([]); };

  if (!currentUser) return <LoginScreen onLogin={handleLogin} users={users} onSignUp={() => ({} as User)} />;

  return (
    <>
      <EmergencyRecover onRecover={handleRefreshSystem} />
      <Header
        user={currentUser}
        onLogout={handleLogout}
        walletFlash={walletFlash}
        onWalletFlashComplete={() => setWalletFlash(false)}
        onOpenChat={() => setIsChatOpen(true)}
        onRefreshSystem={handleRefreshSystem}
        messages={messages}
        threads={threads}
        pendingDepositCount={depositRequests.filter(r => r.status === 'Pending').length}
      />
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        {currentUser.role === 'Vendor' && (
          <BettingTerminal
            races={races}
            betSlip={betSlip}
            onUpdateBetSlip={updateBetSlip}
            onClearBetSlip={() => setBetSlip({ selections: [], totalCost: 0 })}
            onInitiatePlaceBet={placeBet}
            lastTicket={lastTicket}
            onCloseTicket={() => setLastTicket(null)}
            onRemoveSelection={(index) => setBetSlip(prev => { const s = prev.selections.filter((_, i) => i !== index); return { selections: s, totalCost: s.reduce((sum, x) => sum + (x.cost * x.multiplier), 0) }; })}
            onUpdateSelectionMultiplier={(index, m) => setBetSlip(prev => { const s = [...prev.selections]; if(s[index]) s[index].multiplier = Math.max(1, m); return { selections: s, totalCost: s.reduce((sum, x) => sum + (x.cost * x.multiplier), 0) }; })}
            placedTickets={placedTickets}
            allTickets={placedTickets}
            onCancelTicket={() => {}}
            customers={users.filter(u => u.role === 'Customer')}
            onDeposit={() => ({ success: true, bonusApplied: 0 })}
            onPayForBooking={() => ({ success: true, message: 'ok' })}
            onProcessWithdrawal={() => true}
            depositLogs={depositLogs}
            onPayoutTicket={payoutTicket}
            messages={messages}
            threads={threads}
            onOpenChat={() => setIsChatOpen(true)}
            effectiveTime={effectiveTime}
            currentUser={currentUser}
            withdrawalRequests={withdrawalRequests}
            onReprintTicket={setTicketToReprint}
            depositRequests={depositRequests}
            onApproveDepositRequest={() => {}}
            onRejectDepositRequest={() => {}}
          />
        )}
        {currentUser.role === 'Admin' && (
            <AdminDashboard
                tickets={placedTickets}
                races={races}
                onAddRace={handleAddRace}
                onUpdateRace={handleUpdateRace}
                onDeleteRace={handleDeleteRace}
                onUpdateNonRunners={() => {}}
                onSaveRaceResult={() => {}}
                users={users}
                onToggleLock={() => {}}
                onLockAllVendors={() => {}}
                onAddUser={() => {}}
                onDeposit={() => ({ success: true, bonusApplied: 0 })}
                depositLogs={depositLogs}
                allTickets={placedTickets}
                onCancelTicket={() => {}}
                programImages={programImages}
                onAddProgramImage={() => {}}
                onDeleteProgramImage={() => {}}
                promotions={promotions}
                onTogglePromotionStatus={() => {}}
                onUpdatePromotion={() => {}}
                onMovePromotion={() => {}}
                onCreatePromotion={() => {}}
                onDeletePromotion={() => {}}
                onAdminResetPassword={() => ({ success: true, message: '' })}
                effectiveTime={effectiveTime}
                currentUser={currentUser}
                onPayoutTicket={payoutTicket}
                onReprintTicket={setTicketToReprint}
                depositRequests={depositRequests}
                onApproveDepositRequest={() => {}}
                onRejectDepositRequest={() => {}}
                paymentConfigs={paymentConfigs}
                onSavePaymentConfig={() => {}}
            />
        )}
        {currentUser.role === 'Customer' && (
             <CustomerDashboard 
                user={currentUser}
                races={races}
                betSlip={betSlip}
                onUpdateBetSlip={updateBetSlip}
                onClearBetSlip={() => setBetSlip({ selections: [], totalCost: 0 })}
                onInitiatePlaceBet={placeBet}
                onInitiateBookBet={() => {}}
                lastTicket={lastTicket}
                onCloseTicket={() => setLastTicket(null)}
                onRemoveSelection={() => {}}
                onUpdateSelectionMultiplier={() => {}}
                placedTickets={placedTickets}
                onCancelTicket={() => {}}
                seenWinningTickets={seenWinningTickets}
                onMarkWinningTicketAsSeen={(id) => setSeenWinningTickets(prev => new Set(prev).add(id))}
                onWithdrawalRequest={() => {}}
                withdrawalRequests={withdrawalRequests}
                onWalletFlash={() => setWalletFlash(true)}
                programImages={programImages}
                promotions={promotions}
                onChangePassword={() => ({ success: true, message: 'Mock' })}
                effectiveTime={effectiveTime}
                onDepositRequest={() => {}}
                depositRequests={depositRequests}
             />
        )}
      </main>
      {paidTicketModal && <TicketModal ticket={paidTicketModal} onClose={() => setPaidTicketModal(null)} showPrintButton={true} races={races} />}
      {ticketToReprint && <TicketModal ticket={ticketToReprint} onClose={() => setTicketToReprint(null)} showPrintButton={true} races={races} />}
      <ChatPanel isOpen={isChatOpen} onClose={() => setIsChatOpen(false)} currentUser={currentUser} users={users} threads={threads} messages={messages} onSendMessage={() => {}} onMarkAsRead={() => {}} />
    </>
  );
};

