                                 <div className="p-4 bg-gray-50 rounded-lg border text-center">
                                     <span className="text-[10px] font-black text-gray-500 uppercase">Tickets</span>
                                     <span className="block text-2xl font-black text-gray-800">{placedTickets.length}</span>
                                 </div>
                                 <div className="p-4 bg-gray-50 rounded-lg border text-center">
                                     <span className="text-[10px] font-black text-gray-500 uppercase">Net</span>
                                     <span className="block text-2xl font-black text-orange-600">
                                         {(placedTickets.reduce((sum, t) => sum + t.totalCost, 0) - placedTickets.filter(t => t.status === 'Paid').reduce((sum, t) => sum + (t.winnings || 0), 0)).toFixed(0)}
                                     </span>
