                // Recovery feature: The very last ticket in the list (most recent)
                const lastSavedTicket = placedTickets.length > 0 ? placedTickets[placedTickets.length - 1] : null;
                return (
                    <div className="space-y-6">
                        {/* RECOVERY BAR: Always shows the last saved ticket for easy re-print */}
