                                        <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
                                        Ticket Successfully Saved:
                                    </p>
                                    <p className="font-mono font-black text-2xl text-gray-900 tracking-tight">#{lastSavedTicket.id}</p>
                                    <p className="text-[10px] font-bold text-gray-500">Time: {lastSavedTicket.timestamp.toLocaleTimeString()}</p>
                                </div>
                                <button 
                                    onClick={() => onReprintTicket(lastSavedTicket)}
                                    className="px-8 py-4 bg-yellow-500 text-betese-dark font-black rounded-xl shadow-xl hover:bg-yellow-600 active:scale-95 transition-all text-sm uppercase flex items-center gap-3 border-2 border-yellow-600"
                                >
                                    <span className="text-2xl">🖨️</span> REPRINT NOW
