// --- Data Persistence Hooks ---

function useRehydratedState<T>(key: string, defaultValue: T, rehydrator: (data: any) => T): [T, React.Dispatch<React.SetStateAction<T>>] {
  const [state, setState] = useState<T>(() => {
    try {
      const storedValue = localStorage.getItem(key);
      if (storedValue) {
        const parsedData = JSON.parse(storedValue);
        const rehydratedData = rehydrator(parsedData);
        if (key === 'betese-races' && Array.isArray(rehydratedData)) {
            const allRacesPast = rehydratedData.length > 0 && rehydratedData.every((race: Race) => new Date(race.endDate) < new Date());
            if (allRacesPast) {
                localStorage.setItem(key, JSON.stringify(defaultValue));
                return rehydrator(defaultValue);
            }
        }
        return rehydratedData;
      }
      localStorage.setItem(key, JSON.stringify(defaultValue));
      return defaultValue;
    } catch (e) {
      console.error(`Failed to parse or rehydrate ${key}`, e);
      return defaultValue;
    }
  });

  useEffect(() => {
    try {
      localStorage.setItem(key, JSON.stringify(state));
    } catch (e) {
      console.error(`Failed to save state for ${key}`, e);
    }
  }, [key, state]);

  return [state, setState];
}

function useRehydratedSetState(key: string, defaultValue: Set<string>): [Set<string>, React.Dispatch<React.SetStateAction<Set<string>>>] {
    const [state, setState] = useState<Set<string>>(() => {
        try {
            const storedValue = localStorage.getItem(key);
            if (storedValue) {
                return new Set(JSON.parse(storedValue));
            }
            localStorage.setItem(key, JSON.stringify(Array.from(defaultValue)));
            return defaultValue;
        } catch (e) { 
            return defaultValue; 
        }
    });

    useEffect(() => {
        localStorage.setItem(key, JSON.stringify(Array.from(state)));
    }, [key, state]);

    return [state, setState];
}

const rehydrateRaces = (data: any[]): Race[] => data.map(r => ({ ...r, startDate: new Date(r.startDate), endDate: new Date(r.endDate), result: r.result ? { ...r.result, payouts: r.result.payouts || {} } : undefined }));
const rehydrateTickets = (data: any[]): Ticket[] => data.map(t => ({ ...t, timestamp: new Date(t.timestamp), paidAt: t.paidAt ? new Date(t.paidAt) : undefined, canceledAt: t.canceledAt ? new Date(t.canceledAt) : undefined }));
const rehydrateWithdrawals = (data: any[]): WithdrawalRequest[] => data.map(w => ({ ...w, requestedAt: new Date(w.requestedAt), completedAt: w.completedAt ? new Date(w.completedAt) : undefined }));
const rehydrateDeposits = (data: any[]): DepositLog[] => data.map(d => ({ ...d, timestamp: new Date(d.timestamp) }));
const rehydrateDepositRequests = (data: any[]): DepositRequest[] => data.map(d => ({ ...d, timestamp: new Date(d.timestamp), processedAt: d.processedAt ? new Date(d.processedAt) : undefined }));
const rehydrateMessages = (data: any[]): ChatMessage[] => data.map(m => ({ ...m, timestamp: new Date(m.timestamp) }));
const rehydrateThreads = (data: any[]): ChatThread[] => data.map(t => ({ ...t, lastMessageTimestamp: t.lastMessageTimestamp ? new Date(t.lastMessageTimestamp) : undefined }));
const rehydrateManualOrders = (data: any[]): ManualBetOrder[] => data.map(o => ({ ...o, createdAt: new Date(o.createdAt) }));
const identity = (data: any) => data;


const AppContent: React.FC = () => {
  // --- Persistent State ---
  const [currentUser, setCurrentUser] = useRehydratedState<User | null>('betese-currentUser', null, identity);
  const [users, setUsers] = useRehydratedState<User[]>('betese-users', MOCK_USERS, identity);
  const [races, setRaces] = useRehydratedState<Race[]>('betese-races', MOCK_RACES, rehydrateRaces);
  const [placedTickets, setPlacedTickets] = useRehydratedState<Ticket[]>('betese-tickets', [], rehydrateTickets);
  const [withdrawalRequests, setWithdrawalRequests] = useRehydratedState<WithdrawalRequest[]>('betese-withdrawals', [], rehydrateWithdrawals);
  const [depositLogs, setDepositLogs] = useRehydratedState<DepositLog[]>('betese-deposits', [], rehydrateDeposits);
  const [depositRequests, setDepositRequests] = useRehydratedState<DepositRequest[]>('betese-deposit-requests', [], rehydrateDepositRequests);
  const [programImages, setProgramImages] = useRehydratedState<ProgramImage[]>('betese-programImages', [], identity);
  const [promotions, setPromotions] = useRehydratedState<Promotion[]>('betese-promotions', MOCK_PROMOTIONS, identity);
  const [threads, setThreads] = useRehydratedState<ChatThread[]>('betese-threads', MOCK_CHAT_THREADS, rehydrateThreads);
  const [messages, setMessages] = useRehydratedState<ChatMessage[]>('betese-messages', MOCK_CHAT_MESSAGES, rehydrateMessages);
  const [manualBetOrders, setManualBetOrders] = useRehydratedState<ManualBetOrder[]>('betese-manualOrders', [], rehydrateManualOrders);
  const [seenWinningTickets, setSeenWinningTickets] = useRehydratedSetState('betese-seenTickets', new Set());
  const [isTestingMode, setIsTestingMode] = useRehydratedState<boolean>('betese-testingMode', false, identity);
  const [paymentConfigs, setPaymentConfigs] = useRehydratedState<PaymentIntegrationConfig[]>('betese-payment-configs', [], identity);
  const [systemKey, setSystemKey] = useState(0);

  // --- Transient State ---
  const [betSlip, setBetSlip] = useState<BetSlip>({ selections: [], totalCost: 0 });
  const [lastTicket, setLastTicket] = useState<Ticket | null>(null);
  const [paidTicketModal, setPaidTicketModal] = useState<Ticket | null>(null);
  const [ticketToReprint, setTicketToReprint] = useState<Ticket | null>(null);
  const [lastBooking, setLastBooking] = useState<Ticket | null>(null);
  const [lastWithdrawal, setLastWithdrawal] = useState<WithdrawalRequest | null>(null);
  const [walletFlash, setWalletFlash] = useState(false);
  const [confirmationModal, setConfirmationModal] = useState<{ isOpen: boolean; title: string; content: React.ReactNode; onConfirm: () => void; } | null>(null);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [broadcastNotification, setBroadcastNotification] = useState<ChatMessage | null>(null);
  const [effectiveTime, setEffectiveTime] = useState(new Date());

  useEffect(() => {
    if (isTestingMode) return;
    const interval = setInterval(() => setEffectiveTime(new Date()), 1000);
    return () => clearInterval(interval);
  }, [isTestingMode]);

  const handleTimeJump = (minutes: number) => {
    if (!isTestingMode) return;
    setEffectiveTime(prevTime => new Date(prevTime.getTime() + minutes * 60 * 1000));
  };

  const handleResetData = () => {
    const keysToRemove = [
      'betese-currentUser', 'betese-users', 'betese-races', 'betese-tickets',
      'betese-withdrawals', 'betese-deposits', 'betese-programImages', 'betese-promotions',
      'betese-threads', 'betese-messages', 'betese-seenTickets', 'betese-testingMode', 
      'betese-deposit-requests', 'betese-payment-configs', 'betese-manualOrders'
    ];
    keysToRemove.forEach(key => localStorage.removeItem(key));
    window.location.reload();
  };

  const handleRefreshSystem = () => {
    setBetSlip({ selections: [], totalCost: 0 });
    setConfirmationModal(null);
    setLastTicket(null);
    setPaidTicketModal(null);
    setTicketToReprint(null);
    setIsChatOpen(false);
    setSystemKey(prev => prev + 1);
  };

  useEffect(() => {
    const updatedTickets = placedTickets.map(ticket => {
        if (['Paid', 'Canceled', 'Booked'].includes(ticket.status)) return ticket;
        const allRacesResulted = ticket.selections.every(selection => races.find(r => r.id === selection.raceId)?.result);
        if (!allRacesResulted) {
            if (['Winning', 'Lost'].includes(ticket.status)) return { ...ticket, status: 'Active' as const, winnings: 0, winningsBreakdown: undefined };
            return ticket;
        }
        const { totalWinnings, breakdown } = calculateTicketWinnings(ticket, races);
        if (totalWinnings > 0) return { ...ticket, status: 'Winning' as const, winnings: totalWinnings, winningsBreakdown: breakdown };
        else return { ...ticket, status: 'Lost' as const, winnings: 0, winningsBreakdown: breakdown };
    });

    if (JSON.stringify(placedTickets) !== JSON.stringify(updatedTickets)) {
        const userBalanceUpdates: { [userId: string]: number } = {};
        updatedTickets.forEach((newTicket, index) => {
            const oldTicket = placedTickets[index];
            if (newTicket.customerId) {
                if (newTicket.status === 'Winning' && newTicket.winnings && oldTicket.status !== 'Winning') userBalanceUpdates[newTicket.customerId] = (userBalanceUpdates[newTicket.customerId] || 0) + newTicket.winnings;
                else if (newTicket.status === 'Winning' && oldTicket.status === 'Winning' && newTicket.winnings !== oldTicket.winnings) userBalanceUpdates[newTicket.customerId] = (userBalanceUpdates[newTicket.customerId] || 0) + (newTicket.winnings - oldTicket.winnings);
                else if (oldTicket.status === 'Winning' && newTicket.status === 'Lost' && oldTicket.winnings) userBalanceUpdates[newTicket.customerId] = (userBalanceUpdates[newTicket.customerId] || 0) - oldTicket.winnings;
            }
        });
        if (Object.keys(userBalanceUpdates).length > 0) {
            setUsers(prevUsers => {
                const newUsers = prevUsers.map(user => userBalanceUpdates[user.id] ? { ...user, walletBalance: (user.walletBalance ?? 0) + userBalanceUpdates[user.id] } : user);
                if (currentUser && userBalanceUpdates[currentUser.id]) setCurrentUser(newUsers.find(u => u.id === currentUser.id)!);
                return newUsers;
            });
        }
        setPlacedTickets(updatedTickets);
    }
  }, [races, placedTickets, currentUser, setCurrentUser, setUsers]);

  const updateBetSlip = (newSelection: Omit<BetSelection, 'cost' | 'multiplier'>) => {
    const pricing = BET_PRICING[newSelection.betType];
    let cost = 0;
    if (pricing) {
        if (pricing.perHorsePrice) cost = (newSelection.numbers.length + newSelection.xCount) * pricing.perHorsePrice;
        else if (newSelection.xCount > 0) cost = pricing.xPriceMap?.[newSelection.xCount]?.[newSelection.numbers.length] ?? 0;
        else cost = pricing.priceMap[newSelection.numbers.length] ?? 0;
    }
    setBetSlip(prev => {
      const updated = { ...newSelection, cost, multiplier: 1 };
      const newSelections = [...prev.selections, updated];
      return { selections: newSelections, totalCost: newSelections.reduce((sum, s) => sum + (s.cost * s.multiplier), 0) };
    });
  };

  const placeBet = () => {
    if (!currentUser || betSlip.selections.length === 0) return;
    const now = effectiveTime.getTime();
    if (betSlip.selections.some(s => {
        const r = races.find(race => race.id === s.raceId);
        return !r || (r.endDate.getTime() - now) <= BETTING_CUTOFF_MS;
    })) {
        setConfirmationModal(null);
        alert(`FAILED: Betting closed (Cutoff reached).`);
        return;
    }

    if(currentUser.role === 'Customer') {
      const totalBalance = (currentUser.walletBalance ?? 0) + (currentUser.bonusBalance ?? 0);
      if (totalBalance < betSlip.totalCost) { setWalletFlash(true); return; }
      let remainingCost = betSlip.totalCost;
      const walletToUse = Math.min(remainingCost, currentUser.walletBalance ?? 0);
      const newWallet = (currentUser.walletBalance ?? 0) - walletToUse;
      remainingCost -= walletToUse;
      const newBonus = (currentUser.bonusBalance ?? 0) - remainingCost;
      const updated = { ...currentUser, walletBalance: newWallet, bonusBalance: newBonus };
      setCurrentUser(updated);
      setUsers(users.map(u => u.id === currentUser.id ? updated : u));
    }

    const newTicket: Ticket = {
      id: Math.floor(10000000 + Math.random() * 90000000).toString(),
      timestamp: effectiveTime,
      vendorId: currentUser.role === 'Vendor' ? currentUser.id : '',
      vendorName: currentUser.name,
      status: 'Active',
      customerId: currentUser.role === 'Customer' ? currentUser.id : undefined,
      ...betSlip
    };
    setPlacedTickets(prev => [...prev, newTicket]);
    setLastTicket(newTicket);
    setBetSlip({ selections: [], totalCost: 0 });
  };

  const initiatePlaceBet = () => {
    const now = effectiveTime.getTime();
    if (betSlip.selections.some(s => {
        const r = races.find(race => race.id === s.raceId);
        return !r || (r.endDate.getTime() - now) <= BETTING_CUTOFF_MS;
    })) { alert('Betting has closed for one or more selected races.'); return; }
    setConfirmationModal({ isOpen: true, title: "Confirm Bet", content: <p className="font-bold">Total Cost: {betSlip.totalCost.toFixed(2)} GMD</p>, onConfirm: placeBet });
  }

  const bookBet = () => {
    if (!currentUser || betSlip.selections.length === 0) return;
    const now = effectiveTime.getTime();
    if (betSlip.selections.some(s => (races.find(r => r.id === s.raceId)?.endDate.getTime() || 0) - now <= BETTING_CUTOFF_MS)) { setConfirmationModal(null); alert(`FAILED: Booking closed.`); return; }
    const newBooking: Ticket = { id: `BOOK-${Math.random().toString(36).substring(2, 8).toUpperCase()}`, bookingCode: Math.random().toString(36).substring(2, 7).toUpperCase(), timestamp: effectiveTime, vendorId: '', vendorName: currentUser.name, customerId: currentUser.id, status: 'Booked', ...betSlip };
    setPlacedTickets(prev => [...prev, newBooking]);
    setLastBooking(newBooking);
    setBetSlip({ selections: [], totalCost: 0 });
  };

  const initiateBookBet = () => {
     if (betSlip.selections.some(s => (races.find(r => r.id === s.raceId)?.endDate.getTime() || 0) - effectiveTime.getTime() <= BETTING_CUTOFF_MS)) { alert('Betting has closed.'); return; }
     setConfirmationModal({ isOpen: true, title: "Confirm Booking", content: <p className="font-bold">Total Cost: {betSlip.totalCost.toFixed(2)} GMD</p>, onConfirm: bookBet });
  }

  const handleCreateManualBet = (selectionData: Omit<BetSelection, 'cost' | 'raceName'>, multiplier: number, totalCost: number, assignedVendorId: string) => {
    if(!currentUser) return;
    const race = races.find(r => r.id === selectionData.raceId);
    const newOrder: ManualBetOrder = {
        id: `MAN-${Date.now()}`,
        createdAt: effectiveTime,
        createdById: currentUser.id,
        createdByName: currentUser.name,
        assignedVendorId,
        selections: [{ ...selectionData, raceName: race?.name || 'Unknown', cost: totalCost / multiplier, multiplier }],
        totalCost,
        status: 'Pending'
    };
    setManualBetOrders(prev => [...prev, newOrder]);
    alert("Manual bet assigned to vendor.");
  };

  const processManualBet = (orderId: string) => {
    const order = manualBetOrders.find(o => o.id === orderId);
    if(!order || !currentUser) return;
    const newTicket: Ticket = { id: Math.floor(10000000 + Math.random() * 90000000).toString(), timestamp: effectiveTime, vendorId: currentUser.id, vendorName: currentUser.name, status: 'Active', selections: order.selections, totalCost: order.totalCost };
    setPlacedTickets(prev => [...prev, newTicket]);
    setManualBetOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: 'Completed' } : o));
    setLastTicket(newTicket);
  };

  const cancelManualBet = (orderId: string) => {
    setManualBetOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: 'Canceled' } : o));
  };

  const handleDeposit = (customerId: string, amount: number, method: 'Cash' | 'Wave' | 'AfriMoney' | 'Correction' = 'Cash', transactionId?: string): { success: boolean, bonusApplied: number | null } => {
    const userToUpdate = users.find(u => u.id === customerId);
    if (!userToUpdate || !currentUser) return { success: false, bonusApplied: null };
    if (amount < 0 && (userToUpdate.walletBalance ?? 0) + amount < 0) return { success: false, bonusApplied: null };

    let bonusApplied = 0;
    if (amount > 0 && method !== 'Correction') {
        const isFirst = depositLogs.filter(d => d.customerId === customerId).length === 0;
        const promo = promotions.find(p => p.isActive && (isFirst ? p.type === 'first-deposit' : p.type !== 'first-deposit'));
        if (promo) {
            const rule = promo.rules.filter(r => amount >= r.depositAmount).sort((a,b) => b.depositAmount - a.depositAmount)[0];
            if(rule) bonusApplied = rule.bonusAmount;
        }
    }
    const updated = { ...userToUpdate, walletBalance: (userToUpdate.walletBalance ?? 0) + amount, bonusBalance: (userToUpdate.bonusBalance ?? 0) + bonusApplied };
    setUsers(prev => prev.map(u => u.id === customerId ? updated : u));
    if (currentUser.id === customerId) setCurrentUser(updated);
    setDepositLogs(prev => [...prev, { id: `dep-${Date.now()}`, customerId, customerName: updated.name, customerPhone: updated.phone, amount, bonusAwarded: bonusApplied || undefined, processedById: currentUser.id, processedByName: currentUser.name, timestamp: effectiveTime, method, transactionId }]);
    return { success: true, bonusApplied };
  };

  const handleApproveDepositRequest = (requestId: string) => {
      const request = depositRequests.find(r => r.id === requestId);
      if (!request || request.status !== 'Pending' || !currentUser) return;
      handleDeposit(request.customerId, request.amount, request.method, request.transactionId);
      setDepositRequests(prev => prev.map(r => r.id === requestId ? { ...r, status: 'Approved', processedBy: currentUser.id, processedByName: currentUser.name, processedAt: effectiveTime } : r));
  };

  const handleRejectDepositRequest = (requestId: string) => {
      if(!currentUser) return;
      setDepositRequests(prev => prev.map(r => r.id === requestId ? { ...r, status: 'Rejected', processedBy: currentUser.id, processedByName: currentUser.name, processedAt: effectiveTime } : r));
  };

  const payForBooking = (bookingCode: string): { success: boolean; message: string } => {
    const tBook = placedTickets.find(t => t.bookingCode?.toUpperCase() === bookingCode.toUpperCase() && t.status === 'Booked');
    if (!tBook || !currentUser) return { success: false, message: 'Booking not found.' };
    if (tBook.selections.some(s => (races.find(r => r.id === s.raceId)?.endDate.getTime() || 0) - effectiveTime.getTime() <= BETTING_CUTOFF_MS)) return { success: false, message: 'Betting closed for these races.' };
    const active = { ...tBook, status: 'Active' as const, vendorId: currentUser.id, vendorName: currentUser.name, timestamp: effectiveTime };
    setPlacedTickets(prev => prev.map(t => t.id === tBook.id ? active : t));
    setPaidTicketModal(active);
    return { success: true, message: 'Booking paid and activated.' };
  };

  if (!currentUser) return <LoginScreen onLogin={setCurrentUser} users={users} onSignUp={handleSignUp} />;

  return (
    <>
      <EmergencyRecover onRecover={handleRefreshSystem} />
      <Header user={currentUser} onLogout={() => setCurrentUser(null)} walletFlash={walletFlash} onWalletFlashComplete={() => setWalletFlash(false)} onOpenChat={() => setIsChatOpen(true)} onRefreshSystem={handleRefreshSystem} messages={messages} threads={threads} isTestingMode={isTestingMode} onToggleTestingMode={(currentUser.role === 'Admin' || currentUser.role === 'Supervisor') ? () => setIsTestingMode(!isTestingMode) : undefined} pendingDepositCount={depositRequests.filter(r => r.status === 'Pending').length} />
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6" key={systemKey}>
        {currentUser.role === 'Vendor' && (
          <BettingTerminal races={races} betSlip={betSlip} onUpdateBetSlip={updateBetSlip} onClearBetSlip={() => setBetSlip({selections:[], totalCost:0})} onInitiatePlaceBet={initiatePlaceBet} lastTicket={lastTicket} onCloseTicket={() => setLastTicket(null)} onRemoveSelection={(i) => setBetSlip(prev => {const s=prev.selections.filter((_,idx)=>idx!==i); return {selections:s, totalCost: s.reduce((sum,x)=>sum+(x.cost*x.multiplier),0)}})} onUpdateSelectionMultiplier={updateSelectionMultiplier} placedTickets={placedTickets.filter(t => t.vendorId === currentUser.id)} allTickets={placedTickets} onCancelTicket={cancelTicket} customers={users.filter(u => u.role === 'Customer')} onDeposit={handleDeposit} onPayForBooking={payForBooking} onProcessWithdrawal={processWithdrawal} depositLogs={depositLogs} onPayoutTicket={payoutTicket} messages={messages} threads={threads} onOpenChat={() => setIsChatOpen(true)} effectiveTime={effectiveTime} currentUser={currentUser} withdrawalRequests={withdrawalRequests} onReprintTicket={setTicketToReprint} depositRequests={depositRequests} onApproveDepositRequest={handleApproveDepositRequest} onRejectDepositRequest={handleRejectDepositRequest} manualBetOrders={manualBetOrders} onProcessManualBet={processManualBet} />
        )}
        {currentUser.role === 'Admin' && (
            <AdminDashboard tickets={placedTickets.filter(t => t.vendorId === currentUser.id)} users={users} onToggleLock={toggleLock} onLockAllVendors={lockAllVendors} onAddUser={addUser} onDeposit={handleDeposit} races={races} onSaveRaceResult={handleSaveRaceResult} onAddRace={addRace} onUpdateNonRunners={updateNonRunners} depositLogs={depositLogs} onUpdateRace={updateRace} onDeleteRace={deleteRace} allTickets={placedTickets} onCancelTicket={cancelTicket} programImages={programImages} onAddProgramImage={addProgramImage} onDeleteProgramImage={deleteProgramImage} promotions={promotions} onTogglePromotionStatus={togglePromotionStatus} onUpdatePromotion={updatePromotion} onMovePromotion={movePromotion} onCreatePromotion={createPromotion} onDeletePromotion={deletePromotion} onAdminResetPassword={adminResetPassword} effectiveTime={effectiveTime} currentUser={currentUser} onPayoutTicket={payoutTicket} onReprintTicket={setTicketToReprint} depositRequests={depositRequests} onApproveDepositRequest={handleApproveDepositRequest} onRejectDepositRequest={handleRejectDepositRequest} paymentConfigs={paymentConfigs} onSavePaymentConfig={handleUpdatePaymentConfig} manualBetOrders={manualBetOrders} onCreateManualBet={handleCreateManualBet} onCancelManualBet={cancelManualBet} />
        )}
        {currentUser.role === 'Supervisor' && (
            <SupervisorDashboard tickets={placedTickets.filter(t => t.vendorId === currentUser.id)} users={users} onToggleLock={toggleLock} onAddUser={addUser} onDeposit={handleDeposit} races={races} onSaveRaceResult={handleSaveRaceResult} onUpdateNonRunners={updateNonRunners} depositLogs={depositLogs} onUpdateRace={updateRace} onDeleteRace={deleteRace} allTickets={placedTickets} onCancelTicket={cancelTicket} programImages={programImages} onAddProgramImage={addProgramImage} onDeleteProgramImage={deleteProgramImage} promotions={promotions} onTogglePromotionStatus={togglePromotionStatus} onUpdatePromotion={updatePromotion} onMovePromotion={movePromotion} onCreatePromotion={createPromotion} onDeletePromotion={deletePromotion} onAdminResetPassword={adminResetPassword} effectiveTime={effectiveTime} currentUser={currentUser} onPayoutTicket={payoutTicket} onReprintTicket={setTicketToReprint} depositRequests={depositRequests} onApproveDepositRequest={handleApproveDepositRequest} onRejectDepositRequest={handleRejectDepositRequest} manualBetOrders={manualBetOrders} onCreateManualBet={handleCreateManualBet} onCancelManualBet={cancelManualBet} />
        )}
        {currentUser.role === 'Customer' && (
          <CustomerDashboard user={currentUser} races={races} betSlip={betSlip} onUpdateBetSlip={updateBetSlip} onClearBetSlip={() => setBetSlip({selections:[], totalCost:0})} onInitiatePlaceBet={initiatePlaceBet} onInitiateBookBet={initiateBookBet} lastTicket={lastTicket} onCloseTicket={() => setLastTicket(null)} onRemoveSelection={(i) => setBetSlip(prev => {const s=prev.selections.filter((_,idx)=>idx!==i); return {selections:s, totalCost: s.reduce((sum,x)=>sum+(x.cost*x.multiplier),0)}})} onUpdateSelectionMultiplier={updateSelectionMultiplier} placedTickets={placedTickets.filter(t => t.customerId === currentUser.id)} onCancelTicket={cancelTicket} seenWinningTickets={seenWinningTickets} onMarkWinningTicketAsSeen={(id) => setSeenWinningTickets(prev => new Set(prev).add(id))} onWithdrawalRequest={handleWithdrawalRequest} withdrawalRequests={withdrawalRequests.filter(wr => wr.customerId === currentUser.id)} onWalletFlash={() => setWalletFlash(true)} programImages={programImages} promotions={promotions} onChangePassword={changePassword} effectiveTime={effectiveTime} onDepositRequest={(amt, meth, tid) => setDepositRequests(prev => [{id: `dr-${Date.now()}`, customerId: currentUser.id, customerName: currentUser.name, amount: amt, method: meth, transactionId: tid, status: 'Pending', timestamp: effectiveTime}, ...prev])} depositRequests={depositRequests.filter(dr => dr.customerId === currentUser.id)} onCancelWithdrawal={(rid) => setWithdrawalRequests(prev => prev.map(r => (r.id === rid && r.status === 'Pending') ? { ...r, status: 'Canceled' } : r))} />
        )}
      </main>
      {confirmationModal?.isOpen && <ConfirmationModal {...confirmationModal} onClose={() => setConfirmationModal(null)} />}
      {lastBooking && <BookingCodeModal ticket={lastBooking} onClose={() => setLastBooking(null)} />}
      {lastWithdrawal && <WithdrawalCodeModal request={lastWithdrawal} onClose={() => setLastWithdrawal(null)} />}
      {paidTicketModal && <TicketModal ticket={paidTicketModal} onClose={() => setPaidTicketModal(null)} showPrintButton={true} races={races} />}
      {ticketToReprint && <TicketModal ticket={ticketToReprint} onClose={() => setTicketToReprint(null)} showPrintButton={true} races={races} />}
      <ChatPanel isOpen={isChatOpen} onClose={() => setIsChatOpen(false)} currentUser={currentUser} users={users} threads={threads} messages={messages} onSendMessage={() => {}} onMarkAsRead={() => {}} />
      {isTestingMode && (currentUser.role === 'Admin' || currentUser.role === 'Supervisor') && <TestingPanel currentTime={effectiveTime} onTimeJump={handleTimeJump} onResetData={handleResetData} />}
    </>
  );
};

