        </div>
        {count !== undefined && count > 0 && (
            <span className="absolute -top-2 -right-2 bg-red-600 text-white w-8 h-8 rounded-full border-2 border-white flex items-center justify-center font-black text-xs animate-bounce shadow-lg">
                {count}
            </span>
        )}
