        {count !== undefined && count > 0 && (
            <span className="absolute -top-1 -right-1 bg-red-600 text-white w-7 h-7 rounded-full border-2 border-white flex items-center justify-center font-black text-xs animate-bounce shadow-lg">
                {count}
