        races = [], 
        betSlip, 
        onUpdateBetSlip, 
        onClearBetSlip, 
        onInitiatePlaceBet, 
        onRemoveSelection, 
        onUpdateSelectionMultiplier,
        allTickets = [], 
        onPayForBooking, 
        customers = [], 
        onDeposit, 
        depositLogs = [], 
        placedTickets = [], 
        effectiveTime, 
        currentUser,
        lastTicket, 
        onCloseTicket, 
        onPayoutTicket, 
        onProcessWithdrawal, 
        withdrawalRequests = [], 
        onReprintTicket,
        depositRequests = [], 
        onApproveDepositRequest, 
        onRejectDepositRequest, 
