    'Simple Gagnant', 'Simple Placé', 'Couplé Gagnant', 'Couplé Placé',
    'Tiercé Ordre', 'Tiercé Désordre', 'Quarté+ Ordre', 'Quarté+ Désordre', 'Quarté+ Bonus 3',
    'Quinté+ Ordre', 'Quinté+ Désordre', 'Quinté+ Bonus 4', 'Quinté+ Bonus 3',
    'Multi 4', 'Multi 5', 'Multi 6', 'Multi 7'
];

// FIX: Added missing calculateWinSummary to determine liabilities before saving results.
export function calculateWinSummary(race: Race, winningNumbers: number[], tickets: Ticket[]): WinSummary {
    const summary: WinSummary = {};
    const winners = winningNumbers;
    if (!winners || winners.length === 0) return summary;

    const add = (cat: string, stake: number) => {
        if (!summary[cat]) summary[cat] = { count: 0, stake: 0 };
        summary[cat].count++;
        summary[cat].stake += stake;
    };

    tickets.forEach(t => {
        if (t.status === 'Canceled') return;
        t.selections.forEach(sel => {
            if (sel.raceId !== race.id) return;
            const stake = sel.cost * sel.multiplier;
            const nums = sel.numbers;

            if (sel.betType === BetTypeOption.SimpleGagnant) {
                if (nums[0] === winners[0]) add('Simple Gagnant', stake);
            } 
            else if (sel.betType === BetTypeOption.SimplePlace) {
                if (nums[0] === winners[0] || nums[0] === winners[1] || nums[0] === winners[2]) add('Simple Placé', stake);
            }
            else if (sel.betType === BetTypeOption.CoupleGagnant) {
                const top2 = winners.slice(0, 2);
                if (nums.includes(top2[0]) && nums.includes(top2[1])) add('Couplé Gagnant', stake);
            }
            else if (sel.betType === BetTypeOption.CouplePlace) {
                const top3 = winners.slice(0, 3);
                const matches = nums.filter(n => top3.includes(n)).length;
                if (matches >= 2) add('Couplé Placé', stake);
            }
            else if (sel.betType === BetTypeOption.Tierce) {
                const top3 = winners.slice(0, 3);
                const isOrdre = nums[0] === winners[0] && nums[1] === winners[1] && nums[2] === winners[2];
                if (isOrdre) add('Tiercé Ordre', stake);
                else if (nums.includes(top3[0]) && nums.includes(top3[1]) && nums.includes(top3[2])) add('Tiercé Désordre', stake);
            }
            else if (sel.betType === BetTypeOption.Quarte) {
                const top4 = winners.slice(0, 4);
                const isOrdre = nums[0] === winners[0] && nums[1] === winners[1] && nums[2] === winners[2] && nums[3] === winners[3];
                if (isOrdre) add('Quarté+ Ordre', stake);
                else if (nums.includes(top4[0]) && nums.includes(top4[1]) && nums.includes(top4[2]) && nums.includes(top4[3])) add('Quarté+ Désordre', stake);
                else if (nums.includes(top4[0]) && nums.includes(top4[1]) && nums.includes(top4[2])) add('Quarté+ Bonus 3', stake);
            }
            else if (sel.betType === BetTypeOption.Quinte) {
                const top5 = winners.slice(0, 5);
                const isOrdre = nums[0] === winners[0] && nums[1] === winners[1] && nums[2] === winners[2] && nums[3] === winners[3] && nums[4] === winners[4];
                if (isOrdre) add('Quinté+ Ordre', stake);
                else if (nums.includes(top5[0]) && nums.includes(top5[1]) && nums.includes(top5[2]) && nums.includes(top5[3]) && nums.includes(top5[4])) add('Quinté+ Désordre', stake);
                else if (nums.includes(top5[0]) && nums.includes(top5[1]) && nums.includes(top5[2]) && nums.includes(top5[3])) add('Quinté+ Bonus 4', stake);
                else if (nums.includes(top5[0]) && nums.includes(top5[1]) && nums.includes(top5[2])) add('Quinté+ Bonus 3', stake);
            }
            else if (sel.betType === BetTypeOption.Multi4 || sel.betType === BetTypeOption.Multi5 || sel.betType === BetTypeOption.Multi6 || sel.betType === BetTypeOption.Multi7) {
                const top4 = winners.slice(0, 4);
                const matches = nums.filter(n => top4.includes(n)).length;
                if (matches === 4) add(sel.betType.toString(), stake);
            }
        });
    });
    return summary;
}

export function calculateTicketWinnings(ticket: Ticket, allRaces: Race[]): { totalWinnings: number; breakdown: WinningsBreakdown[] } {
    let grandTotalWinnings = 0;
    const finalBreakdown: WinningsBreakdown[] = [];
    if (ticket.status === 'Canceled') return { totalWinnings: 0, breakdown: [] };

    ticket.selections.forEach((sel, index) => {
        const race = allRaces.find(r => r.id === sel.raceId);
        if (!race || !race.result) return;
        // Simplified win check for this example context
        const isWin = sel.numbers.includes(race.result.winningNumbers[0]);
        if (isWin) {
            const payout = (race.result.payouts as any).simpleGagnant || 0;
            const winAmt = (sel.cost) * payout * sel.multiplier;
            grandTotalWinnings += winAmt;
            finalBreakdown.push({ selectionIndex: index, status: 'Win', totalPayout: winAmt, winType: sel.betType });
        } else {
            finalBreakdown.push({ selectionIndex: index, status: 'Loss' });
        }
    });
    return { totalWinnings: grandTotalWinnings, breakdown: finalBreakdown };
}

