          <div key={i} className="mb-2 last:mb-0 border-b border-dotted last:border-0 pb-1">
            <div className="flex bold text-xs">
              <span className="uppercase">{sel.raceName}</span>
              <span className="right">{sel.betType}</span>
            </div>

            {/* MASSIVE HORSES - THIS FIXES THE VISIBILITY ISSUE */}
            <div className="center my-1 bg-black text-white p-1">
                <p className="text-[9px] bold uppercase mb-0.5">SELECTED HORSES:</p>
                <div className="huge bold leading-none">
                {sel.pattern && sel.pattern.length > 0 
                    ? sel.pattern.join('-') 
                    : (sel.xCount > 0 ? 'X-'.repeat(sel.xCount) : '') + sel.numbers.join('-')
                }
                </div>
            </div>

            <div className="flex text-[11px]">
              <span>STAKE (x{sel.multiplier}):</span>
              <span className="bold">GMD {(sel.cost * sel.multiplier).toFixed(2)}</span>
            </div>
          </div>
        ))}
      </div>

      {/* Totals */}
      <div className="right bold my-2">
        <span className="text-[10px] uppercase">Total to Pay:</span>
        <div className="large">GMD {ticket.totalCost.toFixed(2)}</div>
      </div>

      {/* Important Notice */}
      <div className="center bold uppercase text-[8px] border-y py-1 mb-2">
        Keep ticket safe. Valid for 7 days.
      </div>

      {/* QR CODE AT THE ABSOLUTE BOTTOM */}
      <div className="center pt-1">
        <img src={qrUrl} alt="QR" className="w-[70px] h-[70px] mx-auto" />
        <p className="bold text-[9px] mt-1">VERIFY TICKET</p>
      </div>
    </div>
  );

  const renderPaidReceipt = () => (
    <div className="text-black bg-white center font-mono">
      <div className="large bold border-y py-2">PAID RECEIPT</div>
      <p className="my-1 bold text-xs">REF #{ticket.id}</p>

      <div className="my-4 border-2 border-black p-2">
        <p className="bold text-[10px]">TOTAL PAID OUT:</p>
        <p className="large bold">GMD {(ticket.winnings || 0).toFixed(2)}</p>
      </div>

      <div className="flex bold text-[10px] my-2">
        <span>CASHIER: {ticket.paidByName}</span>
        <span>{ticket.paidAt?.toLocaleTimeString()}</span>
      </div>

      <div className="border-b my-2"></div>
      <img src={qrUrl} alt="QR" className="w-[60px] h-[60px] mx-auto" />
    </div>
  );

  return (
    <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-2 overflow-y-auto">
        <div className="bg-white rounded-xl shadow-2xl w-full max-w-[320px] flex flex-col animate-fade-in my-auto">
          <div className="p-3 border-b flex justify-between items-center bg-gray-100 rounded-t-xl">
              <span className="font-black text-xs text-betese-dark uppercase">Ticket Preview</span>
              <button onClick={onClose} className="text-gray-400 text-3xl leading-none">&times;</button>
          </div>

          <div className="p-4 bg-gray-200">
            <div id={`print-box-${ticket.id}`} className="bg-white p-3 shadow-md mx-auto border border-gray-300">
                {isPaid ? renderPaidReceipt() : renderStandardTicket()}
            </div>
          </div>

          <div className="p-5 bg-white border-t rounded-b-xl space-y-3">
            {showPrintButton && (
                <button
                    onClick={handlePrint}
                    className="w-full py-5 bg-betese-green text-white font-black text-xl rounded-xl shadow-xl active:scale-95 transition-all flex justify-center items-center gap-2 border-b-4 border-black/20"
                >
                    🖨️ PRINT TICKET
                </button>
            )}
            <button onClick={onClose} className="w-full py-3 text-gray-500 font-bold text-sm uppercase tracking-widest bg-gray-50 rounded-lg">Close</button>
          </div>
        </div>
      </div>
  );
};

import React, { useMemo } from 'react';
import { Race } from '../types';
import { BETTING_CUTOFF_MS } from '../utils';

interface RaceTimerButtonProps {
  race: Race;
  isSelected: boolean;
  onClick: (raceId: string) => void;
  initialEffectiveTime: Date; 
  variant?: 'vendor' | 'customer';
}

const RaceTimerButton: React.FC<RaceTimerButtonProps> = ({ race, isSelected, onClick, initialEffectiveTime, variant = 'vendor' }) => {
  const timeLeft = race.endDate.getTime() - initialEffectiveTime.getTime();
  const isEnded = timeLeft <= 0;

  // Betting closes 2 mins before race start
  const isBettingClosed = timeLeft <= BETTING_CUTOFF_MS;
  const isClosingSoon = !isBettingClosed && timeLeft < (BETTING_CUTOFF_MS + 60000);

  const totalSecondsRemaining = Math.max(0, Math.floor(timeLeft / 1000));
  const minutes = Math.floor(totalSecondsRemaining / 60);
  const seconds = totalSecondsRemaining % 60;

  const buttonClasses = useMemo(() => {
    if (isEnded) return 'bg-gray-300 text-gray-500 cursor-not-allowed';
    if (isBettingClosed) return 'bg-red-50 text-red-700 ring-1 ring-red-200';
    if (isSelected) return 'bg-betese-green text-white shadow-lg ring-2 ring-betese-yellow';
    if (isClosingSoon) return 'bg-yellow-400 text-yellow-900 shadow-lg ring-2 ring-yellow-600 animate-pulse';
    return 'bg-green-100 text-betese-dark hover:bg-green-200 shadow';
  }, [isEnded, isBettingClosed, isSelected, isClosingSoon]);

  const handleClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!isEnded) {
      onClick(race.id);
    }
  };

  return (
    <button
      onClick={handleClick}
      disabled={isEnded}
      className={`p-3 rounded-xl font-black transition-all flex flex-col items-center justify-center gap-1 w-32 h-28 text-center ${buttonClasses}`}
    >
      <span className="text-xl">🏇</span>
      <span className="text-sm uppercase tracking-tighter">{race.name}</span>

      {isEnded ? (
        <span className="text-xs font-bold text-gray-600">FINISHED</span>
      ) : (
        <div className="flex flex-col items-center">
            <span className="text-lg font-mono leading-none">
              {String(minutes).padStart(2, '0')}:{String(seconds).padStart(2, '0')}
            </span>
            {isBettingClosed ? (
                <span className="text-[10px] text-red-600 uppercase font-black bg-red-100 px-1 rounded mt-1">CLOSED</span>
            ) : (
                <span className="text-[10px] opacity-70 uppercase">Starts in</span>
            )}
        </div>
      )}
    </button>
  );
};

export default RaceTimerButton;

