                      </button>
                  </div>
              </div>
            )}
            {activeTab === 'history' && <TicketHistoryPanel tickets={placedTickets} onCancelTicket={onCancelTicket} races={races} effectiveTime={effectiveTime} />}
            {activeTab === 'wallet' && (
                <div className="space-y-6">
                    <WalletPanel user={user} onWithdrawalRequest={onWithdrawalRequest} withdrawalRequests={withdrawalRequests} onWalletFlash={onWalletFlash} onDepositRequest={onDepositRequest} depositRequests={depositRequests} onCancelWithdrawal={onCancelWithdrawal} />
                    <PasswordChangePanel user={user} onChangePassword={onChangePassword} />
                </div>
            )}
             {activeTab === 'info' && (
                <div className="space-y-6">
                    <div className="bg-white p-6 rounded-lg shadow-lg">
                         <h3 className="text-xl font-bold text-betese-dark mb-4">{t('legal_compliance')}</h3>
