          <div className="p-2 border-b flex justify-between items-center bg-gray-100 rounded-t-xl">
              <span className="font-black text-[10px] text-gray-500 uppercase">Thermal Preview</span>
              <button onClick={onClose} className="text-gray-400 text-2xl leading-none">&times;</button>
          </div>

          <div className="p-2 bg-gray-200">
            <div id={`p-box-${ticket.id}`} className="bg-white p-1.5 shadow-inner mx-auto border border-gray-300 w-[190px]">
                {isPaid ? renderPaidReceipt() : renderStandardTicket()}
            </div>
          </div>

          <div className="p-4 bg-white border-t rounded-b-xl space-y-2">
            {/* 100% Logic: Only show Print if specifically allowed (Staff only) */}
            {showPrintButton && (
                <button
                    onClick={handlePrint}
                    className="w-full py-3 bg-betese-green text-white font-black text-xl rounded-lg shadow-xl active:scale-95 transition-all flex justify-center items-center gap-2 border-b-4 border-black/20"
                >
                    🖨️ PRINT
                </button>
            )}
            <button onClick={onClose} className="w-full py-2 text-gray-500 font-bold text-xs uppercase tracking-widest bg-gray-50 rounded-lg">Close</button>
          </div>
        </div>
      </div>
  );
};

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { Race, Ticket, User, DepositLog, ChatMessage, ChatThread, BetSlip, BetTypeOption, BetSelection, WithdrawalRequest, DepositRequest, ManualBetOrder, RaceResult } from '../types';
