);

const BackButton: React.FC<{ onClick: () => void }> = ({ onClick }) => (
  <button 
    onClick={onClick} 
    className="mb-4 w-full sm:w-auto inline-flex items-center justify-center gap-2 px-6 py-4 bg-gray-800 text-white font-black rounded-xl shadow-md active:scale-95 transition-all uppercase tracking-tighter"
  >
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M12.707 5.293a1 1 0 010 1.414L9.414 10l3.293 3.293a1 1 0 01-1.414 1.414l-4-4a1 1 0 010-1.414l4-4a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
    Return to Menu
  </button>
);

export const BettingTerminal: React.FC<BettingTerminalProps> = (props) => {
    const { 
        races = [], 
        betSlip, 
        onUpdateBetSlip, 
        onClearBetSlip, 
        onInitiatePlaceBet, 
        onRemoveSelection, 
        onUpdateSelectionMultiplier,
        allTickets = [], 
        onPayForBooking, 
        customers = [], 
        onDeposit, 
        depositLogs = [], 
        placedTickets = [], 
        effectiveTime, 
        currentUser,
        lastTicket, 
        onCloseTicket, 
        onPayoutTicket, 
        onProcessWithdrawal, 
        withdrawalRequests = [], 
        onReprintTicket,
        depositRequests = [], 
        onApproveDepositRequest, 
        onRejectDepositRequest, 
        manualBetOrders = [], 
        onProcessManualBet,
        onSaveRaceResult,
        onOpenChat
    } = props;

    const [view, setView] = useState<View>('DASHBOARD');
    const [selectedRace, setSelectedRace] = useState<Race | null>(null);
    const [selectedBetType, setSelectedBetType] = useState<BetTypeOption | null>(null);
    const [selectedNumbers, setSelectedNumbers] = useState<number[]>([]);
    const [xCount, setXCount] = useState<number>(0);
    const [rapportModalRace, setRapportModalRace] = useState<Race | null>(null);

    const sortedRaces = useMemo(() => [...races].sort((a,b) => a.endDate.getTime() - b.endDate.getTime()), [races]);

    const handleReturn = () => {
        onClearBetSlip();
        setSelectedNumbers([]);
        setXCount(0);
        setSelectedBetType(null);
        setView('DASHBOARD');
    };

    useEffect(() => {
        if (!selectedRace && sortedRaces.length > 0) {
            const next = sortedRaces.find(r => r.endDate > effectiveTime);
            if (next) setSelectedRace(next);
        }
    }, [sortedRaces, effectiveTime, selectedRace]);

    // PERMANENT COUNTDOWN LOGIC
    const timeRemaining = selectedRace ? selectedRace.endDate.getTime() - effectiveTime.getTime() : 0;
    const isBettingClosed = timeRemaining <= BETTING_CUTOFF_MS;

    const handleAddBet = useCallback(() => {
        if (!selectedRace || !selectedBetType) return;

        // STRICT MINIMUM HORSE VALIDATION
        const pricing = BET_PRICING[selectedBetType];
        const totalSelected = selectedNumbers.length + xCount;

        if (totalSelected < pricing.minHorses) {
            alert(`INVALID SELECTION: ${selectedBetType} requires at least ${pricing.minHorses} horses. You only selected ${totalSelected}.`);
            return;
        }

        if (isBettingClosed) {
            alert("FAILED: Betting is CLOSED for this race (2-minute cutoff).");
            return;
        }

        onUpdateBetSlip({ raceId: selectedRace.id, raceName: selectedRace.name, betType: selectedBetType, numbers: selectedNumbers, xCount: xCount, pattern: [] });
        setSelectedNumbers([]);
        setXCount(0);
        setSelectedBetType(null);
    }, [selectedRace, selectedBetType, selectedNumbers, xCount, onUpdateBetSlip, isBettingClosed]);

    const pendingManualCount = (manualBetOrders || []).filter(o => o.assignedVendorId === currentUser.id && o.status === 'Pending').length;
    const pendingFinanceCount = ((depositRequests || []).filter(r => r.status === 'Pending').length) + ((withdrawalRequests || []).filter(r => r.status === 'Pending').length);

    const renderView = () => {
        switch (view) {
            case 'PLACE_BET':
                return (
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-fade-in relative">
                        <div className="lg:col-span-2 space-y-4">
                            {/* PERMANENT VENDOR COUNTDOWN HEADER */}
                            {selectedRace && (
                                <div className={`sticky top-0 z-20 p-4 rounded-xl border-b-4 flex justify-between items-center shadow-lg transition-colors ${isBettingClosed ? 'bg-red-600 border-red-800 text-white' : 'bg-betese-green border-green-800 text-white'}`}>
                                    <div>
                                        <p className="text-[10px] font-black uppercase opacity-80 leading-none">Console - Active Race</p>
                                        <h4 className="text-2xl font-black uppercase">{selectedRace.name}</h4>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-[10px] font-black uppercase opacity-80">{isBettingClosed ? 'Status' : 'Time Remaining'}</p>
                                        <p className="text-4xl font-mono font-black leading-none">
                                            {isBettingClosed ? 'CLOSED' : `${Math.floor(timeRemaining / 60000).toString().padStart(2, '0')}:${Math.floor((timeRemaining % 60000) / 1000).toString().padStart(2, '0')}`}
                                        </p>
                                    </div>
                                </div>
                            )}

                            <div className="bg-white p-4 rounded-xl shadow-md border-t-4 border-green-600">
                                <h3 className="font-black text-gray-800 uppercase mb-3 flex items-center gap-2">
                                    <span className="bg-green-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs">1</span>
                                    Select Race
                                </h3>
                                <div className="flex flex-wrap gap-2">
                                    {sortedRaces.map(r => (
                                        <RaceTimerButton key={r.id} race={r} isSelected={selectedRace?.id === r.id} onClick={() => setSelectedRace(r)} initialEffectiveTime={effectiveTime} />
                                    ))}
                                </div>
                            </div>
                            {selectedRace && (
                                <div className="bg-white p-4 rounded-xl shadow-md border-t-4 border-blue-600">
                                    <h3 className="font-black text-gray-800 uppercase mb-3 flex items-center gap-2">
                                        <span className="bg-blue-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs">2</span>
                                        Bet Type & Horses
                                    </h3>
                                    <div className="grid grid-cols-3 sm:grid-cols-4 gap-2 mb-4">
                                        {Object.values(BetTypeOption).map(bt => (
                                            <button key={bt} onClick={() => setSelectedBetType(bt)} className={`p-3 rounded-lg text-xs font-black border-2 transition-all ${selectedBetType === bt ? 'bg-blue-600 text-white border-blue-800 shadow-inner' : 'bg-gray-50 text-gray-700 border-gray-200 hover:bg-gray-100'}`}>
                                                {bt}
                                            </button>
                                        ))}
                                    </div>
                                    {selectedBetType && <HorseSelector race={selectedRace} betType={selectedBetType} selectedNumbers={selectedNumbers} xCount={xCount} onNumberSelect={setSelectedNumbers} onXSelect={setXCount} />}

                                    <button 
                                        onClick={handleAddBet} 
                                        disabled={!selectedBetType || (selectedNumbers.length + xCount === 0) || isBettingClosed} 
                                        className={`w-full mt-4 py-4 font-black rounded-xl shadow-lg active:scale-95 transition-all text-white ${isBettingClosed ? 'bg-gray-400 cursor-not-allowed' : 'bg-betese-dark hover:brightness-110'}`}
                                    >
                                        {isBettingClosed ? 'RACE CLOSED' : 'ADD TO SLIP'}
                                    </button>
                                </div>
                            )}
                        </div>
                        <BetSlipPanel betSlip={betSlip} onClear={onClearBetSlip} onInitiatePlaceBet={onInitiatePlaceBet} onRemove={onRemoveSelection} onUpdateSelectionMultiplier={onUpdateSelectionMultiplier} />
                    </div>
                );

            case 'SCAN_PAY':
                return (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-fade-in">
                        <TicketCheckPanel allTickets={allTickets} onPayoutTicket={onPayoutTicket} />
                        <BookingRetrievalPanel allTickets={allTickets} onPayForBooking={onPayForBooking} onPrintBookingSlip={onReprintTicket} races={races} effectiveTime={effectiveTime} />
                    </div>
                );

            case 'FINANCE':
                return (
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-fade-in">
                        <CustomerDepositPanel 
                            customers={customers} 
                            onDeposit={onDeposit} 
                            depositLogs={depositLogs} 
                            currentUserRole={currentUser.role} 
                            depositRequests={depositRequests}
                            onApproveDepositRequest={onApproveDepositRequest}
                            onRejectDepositRequest={onRejectDepositRequest}
                        />
                        <ProcessWithdrawalPanel onProcessWithdrawal={onProcessWithdrawal} withdrawalRequests={withdrawalRequests} customers={customers} />
                    </div>
                );

            case 'RAPPORTS':
                return <PayoutReportView races={races} onPrintRequest={setRapportModalRace} effectiveTime={effectiveTime} />;

            case 'UPDATE_RESULTS':
                return <RaceResultsManagement races={races} tickets={allTickets} onSave={onSaveRaceResult} effectiveTime={effectiveTime} />;

            case 'SALES_REPORT':
                return (
                    <div className="space-y-6 animate-fade-in">
                        <div className="bg-white p-6 rounded-xl shadow-lg border-t-4 border-yellow-500">
                             <h3 className="text-xl font-black uppercase text-gray-800 mb-4">Daily Performance</h3>
                             <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-6">
                                 <div className="p-4 bg-gray-50 rounded-lg border text-center"><span className="text-[10px] font-black text-gray-500 uppercase">Sales</span><span className="block text-2xl font-black text-betese-green">GMD {placedTickets.reduce((sum, t) => sum + t.totalCost, 0).toFixed(0)}</span></div>
                                 <div className="p-4 bg-gray-50 rounded-lg border text-center"><span className="text-[10px] font-black text-gray-500 uppercase">Payouts</span><span className="block text-2xl font-black text-blue-600">GMD {placedTickets.filter(t => t.status === 'Paid').reduce((sum, t) => sum + (t.winnings || 0), 0).toFixed(0)}</span></div>
                                 <div className="p-4 bg-gray-50 rounded-lg border text-center"><span className="text-[10px] font-black text-gray-500 uppercase">Tickets</span><span className="block text-2xl font-black text-gray-800">{placedTickets.length}</span></div>
                                 <div className="p-4 bg-gray-50 rounded-lg border text-center"><span className="text-[10px] font-black text-gray-500 uppercase">Net</span><span className="block text-2xl font-black text-orange-600">GMD {(placedTickets.reduce((sum, t) => sum + t.totalCost, 0) - placedTickets.filter(t => t.status === 'Paid').reduce((sum, t) => sum + (t.winnings || 0), 0)).toFixed(0)}</span></div>
                             </div>
                             <TicketDetailsTable title="Transaction Log" tickets={placedTickets} races={races} />
                        </div>
                    </div>
                );

            case 'MANUAL_BETS':
                return <PendingManualBetsPanel manualBetOrders={manualBetOrders} currentUser={currentUser} races={races} onProcessManualBet={onProcessManualBet} />;

            case 'DASHBOARD':
            default:
                const lastSavedTicket = placedTickets.length > 0 ? placedTickets[placedTickets.length - 1] : null;
                return (
                    <div className="space-y-6">
                        {lastSavedTicket && (
                            <div className="bg-yellow-100 border-l-8 border-yellow-500 p-4 rounded-r-2xl flex items-center justify-between animate-fade-in shadow-lg">
                                <div><p className="text-[11px] font-black text-yellow-800 uppercase">Ticket Printed:</p><p className="font-mono font-black text-2xl text-gray-900 tracking-tight">#{lastSavedTicket.id}</p></div>
                                <button onClick={() => onReprintTicket(lastSavedTicket)} className="px-8 py-4 bg-yellow-500 text-betese-dark font-black rounded-xl shadow hover:bg-yellow-600 active:scale-95 text-sm uppercase flex items-center gap-3 border-2 border-yellow-600"><span className="text-2xl">🖨️</span> REPRINT</button>
                            </div>
                        )}

                        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 sm:gap-6 animate-fade-in">
                            <MenuButton onClick={() => setView('PLACE_BET')} label="Place Bet" subtext="New Ticket" icon="🏇" color="bg-green-600" />
                            <MenuButton onClick={() => setView('SCAN_PAY')} label="Scan/Pay" subtext="Payout/Check" icon="💰" color="bg-orange-600" />
                            <MenuButton onClick={() => setView('FINANCE')} label="Finance" subtext="Wallets" icon="📱" color="bg-blue-600" count={pendingFinanceCount} />
                            <MenuButton onClick={() => setView('SALES_REPORT')} label="Sales" subtext="Daily Activity" icon="📊" color="bg-gray-700" />
                            <MenuButton onClick={() => setView('RAPPORTS')} label="Rapport" subtext="Print Results" icon="🖨️" color="bg-cyan-600" />
                            <MenuButton onClick={() => setView('UPDATE_RESULTS')} label="Results" subtext="Enter Winners" icon="🏆" color="bg-red-600" />
                            <MenuButton onClick={() => setView('MANUAL_BETS')} label="Manual" subtext="Office Orders" icon="📝" color="bg-indigo-600" count={pendingManualCount} />
                            <MenuButton onClick={() => onOpenChat()} label="Chat" subtext="Support" icon="💬" color="bg-purple-600" />
                        </div>
                    </div>
                );
        }
    };

    return (
        <div className="max-w-7xl mx-auto px-2">
            {rapportModalRace && <RapportModal race={rapportModalRace} onClose={() => setRapportModalRace(null)} showPrintButton={true} />}
            {view !== 'DASHBOARD' && <BackButton onClick={handleReturn} />}
            {renderView()}
            {/* VENDORS ALWAYS GET PRINT BUTTON */}
            {lastTicket && <TicketModal ticket={lastTicket} onClose={onCloseTicket} showPrintButton={true} races={races} />}
        </div>
    );
};

