                                      disabled={isDisabled}
                                      className={`relative p-3 rounded-xl text-xs font-black transition-all flex flex-col items-center justify-center h-20 gap-1 border-2 ${
                                          isDisabled 
                                              ? 'bg-gray-100 text-gray-400 border-gray-200 cursor-not-allowed'
