                    </div>
                );
            case 'FINANCE':
                return (
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-fade-in">
                        <CustomerDepositPanel customers={customers} onDeposit={onDeposit} depositLogs={depositLogs} currentUserRole={currentUser.role} depositRequests={depositRequests} onApproveDepositRequest={onApproveDepositRequest} onRejectDepositRequest={onRejectDepositRequest} />
                        <ProcessWithdrawalPanel onProcessWithdrawal={onProcessWithdrawal} withdrawalRequests={withdrawalRequests} customers={customers} />
                    </div>
                );
            case 'SALES_REPORT':
                return (
                    <div className="space-y-6 animate-fade-in">
                         <div className="bg-white p-6 rounded-xl shadow-lg border-t-4 border-yellow-500">
                             <div className="flex justify-between items-center mb-6">
                                <h3 className="text-2xl font-black uppercase text-gray-800">Daily Activity</h3>
                                <button onClick={handlePrintDailyReport} className="px-6 py-3 bg-betese-green text-white font-black rounded-xl shadow-lg hover:bg-green-700 active:scale-95 transition-all flex items-center gap-2">
                                    <span className="text-xl">🖨️</span> PRINT DAILY REPORT
                                </button>
                             </div>
                             <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-8">
                                 <div className="p-4 bg-gray-50 rounded-lg border text-center"><span className="text-[10px] font-black text-gray-500 uppercase">Sales</span><span className="block text-2xl font-black text-betese-green">GMD {reportSales.toFixed(0)}</span></div>
                                 <div className="p-4 bg-gray-50 rounded-lg border text-center"><span className="text-[10px] font-black text-gray-500 uppercase">Payouts</span><span className="block text-2xl font-black text-blue-600">GMD {reportPayouts.toFixed(0)}</span></div>
                                 <div className="p-4 bg-gray-50 rounded-lg border text-center"><span className="text-[10px] font-black text-gray-500 uppercase">Tickets</span><span className="block text-2xl font-black text-gray-800">{placedTickets.length}</span></div>
                                 <div className="p-4 bg-gray-50 rounded-lg border text-center"><span className="text-[10px] font-black text-gray-500 uppercase">Net</span><span className="block text-2xl font-black text-orange-600">GMD {reportNet.toFixed(0)}</span></div>
