                                <button onClick={handlePrintDailyReport} className="px-6 py-4 bg-betese-green text-white font-black rounded-xl shadow hover:bg-green-700 active:scale-95 text-sm uppercase flex items-center gap-3 border-b-4 border-black/20"><span className="text-2xl">📊</span> PRINT SALES</button>
                            </div>
