                            <div className="report-row b"><span>PAYOUTS:</span><span>GMD {reportPayouts.toFixed(0)}</span></div>
                            <div className="solid"></div>
                            <div className="flex huge b my-2 justify-between">
                                <span style={{fontSize:'12px'}}>NET:</span>
                                <span>GMD {reportNet.toFixed(0)}</span>
                            </div>
