                            <MenuButton onClick={() => setView('SALES_REPORT')} label="History" subtext="Sales Log" icon="📑" color="bg-gray-700" />
                            <MenuButton onClick={() => setView('RAPPORTS')} label="Rapport" subtext="Print Results" icon="🖨️" color="bg-cyan-600" />
                            <MenuButton onClick={() => setView('UPDATE_RESULTS')} label="Results" subtext="Enter Winners" icon="🏆" color="bg-red-600" />
                            <MenuButton onClick={() => setView('MANUAL_BETS')} label="Manual" subtext="Office" icon="📝" color="bg-emerald-600" count={pendingManualCount} />
                            <MenuButton onClick={() => onOpenChat()} label="Chat" subtext="Support" icon="💬" color="bg-purple-600" />
                        </div>

                        {/* HIDDEN PRINTABLE DAILY REPORT */}
                        <div id="printable-daily-sales-summary" className="hidden">
                            <div className="c b text-lg border-b border-black text-center pb-1 uppercase">BETESE DAILY SALES</div>
                            <div className="flex b text-[10px] my-2 justify-between">
                                <span>VEND: {currentUser.name}</span>
                                <span>{effectiveTime.toLocaleDateString()}</span>
                            </div>
                            <div className="solid"></div>
                            <div className="report-row b"><span>TOTAL TICKETS:</span><span>{placedTickets.length}</span></div>
                            <div className="report-row b"><span>GROSS SALES:</span><span>GMD {reportSales.toFixed(0)}</span></div>
                            <div className="report-row b"><span>TOTAL PAID:</span><span>GMD {reportPayouts.toFixed(0)}</span></div>
                            <div className="solid"></div>
                            <div className="flex huge b my-2 justify-between">
                                <span style={{fontSize:'12px'}}>CASH ON HAND:</span>
                                <span>GMD {reportNet.toFixed(0)}</span>
                            </div>
                            <div className="solid"></div>
                            <p className="c b text-[9px] mt-4">OFFICIAL VENDOR RECEIPT</p>
                            <p className="c text-[8px] opacity-70 italic">{effectiveTime.toLocaleString()}</p>
                        </div>
                    </div>
                );
        }
    };

    return (
        <div className="max-w-7xl mx-auto px-2">
            {rapportModalRace && <RapportModal race={rapportModalRace} onClose={() => setRapportModalRace(null)} showPrintButton={true} />}
            {view !== 'DASHBOARD' && <BackButton onClick={handleReturn} />}
            {renderView()}
            {lastTicket && <TicketModal ticket={lastTicket} onClose={onCloseTicket} showPrintButton={true} races={races} />}
        </div>
    );
};

import React from 'react';
