        <span>REF:#{ticket.id}</span>
        <span>{ticket.timestamp.toLocaleDateString([], {day:'2-digit', month:'2-digit'})} {ticket.timestamp.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
